// ── React component tabs ─────────────────────────────────────────
function planningRenderReact(container, tab) {
  container.innerHTML = `
    <div id="planning-react-mount" style="min-height:600px;border-radius:10px;overflow:hidden">
      <div style="display:flex;align-items:center;justify-content:center;height:200px;color:var(--txt3)">
        <div style="text-align:center">
          <div style="font-size:2rem;margin-bottom:.5rem">&#9881;</div>
          <div style="font-size:.9rem">Loading ${tab === 'setup' ? 'Project Setup' : 'Measurement Book'}...</div>
        </div>
      </div>
    </div>
  `;

  if (_planningReactLoaded) {
    planningMountComponent(tab);
    return;
  }

  // Dynamically load React + ReactDOM + Babel in order
  const loadScript = (src) => new Promise((res, rej) => {
    const s = document.createElement('script');
    s.src = src; s.onload = res; s.onerror = rej;
    document.head.appendChild(s);
  });

  Promise.all([
    loadScript('https://cdnjs.cloudflare.com/ajax/libs/react/18.2.0/umd/react.production.min.js'),
    loadScript('https://cdnjs.cloudflare.com/ajax/libs/react-dom/18.2.0/umd/react-dom.production.min.js'),
  ]).then(() => loadScript('https://cdnjs.cloudflare.com/ajax/libs/babel-standalone/7.23.5/babel.min.js'))
    .then(() => {
      _planningReactLoaded = true;
      planningMountComponent(tab);
    })
    .catch(err => {
      const mount = document.getElementById('planning-react-mount');
      if (mount) mount.innerHTML = `<div style="padding:2rem;text-align:center;color:var(--danger)">&#9888; Could not load React: ${err.message}<br><small>Check your internet connection.</small></div>`;
    });
}

function planningMountComponent(tab) {
  const mount = document.getElementById('planning-react-mount');
  if (!mount) return;
  mount.innerHTML = '';

  // Both 'setup' and 'measurement' now render inline via Babel/React.
  // (Previously 'setup' loaded an iframe pointing at /Planning which 404'd
  //  because that path doesn't exist on GitHub Pages.)
  const src = (tab === 'setup') ? PLANNING_SETUP_JSX : PLANNING_MB_JSX;
  const expectedComponent = (tab === 'setup') ? 'ProjectSetup' : 'MeasurementBook';

  try {
    const reactPreamble = 'const { useState, useCallback, useMemo, useEffect, useRef, useContext } = React;\n';
    const cleanSrc = reactPreamble + src
      .replace(/^import\s[\s\S]*?;\s*\n/gm, '')
      .replace(/^export\s+default\s+function\s+/gm, 'function ')
      .replace(/^export\s+default\s+class\s+/gm, 'class ')
      .replace(/^export\s+default\s+/gm, 'const __defaultExport__ = ')
      + `\nwindow.__PlanningComponent__ = typeof ${expectedComponent} !== "undefined" ? ${expectedComponent} : (typeof __defaultExport__ !== "undefined" ? __defaultExport__ : null);`;
    const compiled = Babel.transform(cleanSrc, { presets: ['react'], sourceType: 'script', plugins: [] }).code;
    eval(compiled); // eslint-disable-line no-eval
    const Component = window.__PlanningComponent__;
    if (Component && window.ReactDOM) {
      const root = ReactDOM.createRoot ? ReactDOM.createRoot(mount) : null;
      if (root) root.render(React.createElement(Component));
      else ReactDOM.render(React.createElement(Component), mount);
    } else {
      mount.innerHTML = '<div style="padding:2rem;text-align:center;color:var(--danger)">&#9888; Component not found in source.</div>';
    }
  } catch(err) {
    console.error('Planning component error:', err);
    mount.innerHTML = `<div style="padding:2rem;text-align:center;color:var(--danger)">&#9888; Component error: ${err.message}</div>`;
  }
}


function renderPurchaseDashboard() {
  const el = document.getElementById('mainContent');
  el.innerHTML = `
    <div class="page-header">
      <div class="page-header-row">
        <div><h1>&#128722; Purchase Dashboard</h1><p>PO tracker &middot; MRS &middot; Stores &middot; Vendor summary</p></div>
        <button class="btn btn-secondary btn-sm" onclick="renderPurchaseDashboard()">&#8635; Refresh</button>
      </div>
    </div>
    <div class="kpi-grid" style="margin-bottom:1.4rem">
      <div class="kpi-card gold"><div class="kpi-top"><div class="kpi-icon gold">&#9203;</div><div class="kpi-trend flat">Action needed</div></div><div class="kpi-value" id="pdKpiPending">&#8212;</div><div class="kpi-label">POs Pending Approval</div></div>
      <div class="kpi-card"><div class="kpi-top"><div class="kpi-icon green">&#10003;</div><div class="kpi-trend up">Approved</div></div><div class="kpi-value" id="pdKpiApproved">&#8212;</div><div class="kpi-label">POs Approved</div></div>
      <div class="kpi-card danger"><div class="kpi-top"><div class="kpi-icon red">&#10007;</div></div><div class="kpi-value" id="pdKpiRejected">&#8212;</div><div class="kpi-label">POs Rejected</div></div>
      <div class="kpi-card info"><div class="kpi-top"><div class="kpi-icon blue">&#8377;</div><div class="kpi-trend flat">Total</div></div><div class="kpi-value" id="pdKpiValue">&#8212;</div><div class="kpi-label">Total PO Value</div></div>
    </div>
    <div class="card">
      <div class="card-head">
        <h3>&#128203; Purchase Orders</h3>
        <div style="display:flex;gap:.5rem;flex-wrap:wrap">
          <select id="pdFilter" onchange="pdApplyFilter()" style="font-size:.75rem;border:1px solid var(--border);border-radius:6px;padding:4px 8px;background:var(--surface2)">
            <option value="all">All POs</option>
            <option value="pending">Pending Approval</option>
            <option value="approved">Approved</option>
            <option value="rejected">Rejected</option>
          </select>
          <select id="pdSiteFilter" onchange="pdApplyFilter()" style="font-size:.75rem;border:1px solid var(--border);border-radius:6px;padding:4px 8px;background:var(--surface2)">
            <option value="">All Sites</option>
          </select>
          <input id="pdSearch" oninput="pdApplyFilter()" placeholder="Search vendor / PO no..." style="font-size:.75rem;border:1px solid var(--border);border-radius:6px;padding:4px 10px;background:var(--surface2);width:160px">
        </div>
      </div>
      <div class="card-body table-wrap">
        <table class="data-table" id="pdTable">
          <thead><tr><th>PO No</th><th>Date</th><th>Vendor</th><th>Site</th><th style="text-align:right">Amount</th><th>Status</th></tr></thead>
          <tbody id="pdTbody"><tr><td colspan="6" style="text-align:center;padding:2rem;color:var(--txt3)">&#8987; Loading POs...</td></tr></tbody>
        </table>
      </div>
    </div>`;

  fetchSheet(PO_TAB, 'SELECT A,E,F,G,R,S,AF,AG,AP,AQ', PO_SHEET_ID).then(rawRows => {
    window._pdRows = rawRows
      .filter(r => r['PO No'] && r['PO No'] !== 'Dummy')
      .map(r => ({
        poNo:   r['PO No']   || '',
        date:   r['PO Date'] || '',
        vendor: r['Vendor Name'] || r['R'] || '',
        site:   r['Site Name']   || r['S'] || '',
        amount: parseFloat(String(r['Net Amount'] || r['AP'] || '0').replace(/[^0-9.]/g,'')) || 0,
        status: r['PO Approval Status'] || r['AG'] || '',
        lock:   r['Lock'] || r['AQ'] || '',
      }));

    const pending  = window._pdRows.filter(r => r.status.toUpperCase() !== 'REJECTED' && r.lock === 'Released for Approval').length;
    const approved = window._pdRows.filter(r => r.status.toUpperCase().includes('APPROVED')).length;
    const rejected = window._pdRows.filter(r => r.status.toUpperCase().includes('REJECTED')).length;
    const totalVal = window._pdRows.reduce((s, r) => s + r.amount, 0);

    document.getElementById('pdKpiPending').textContent  = pending;
    document.getElementById('pdKpiApproved').textContent = approved;
    document.getElementById('pdKpiRejected').textContent = rejected;
    document.getElementById('pdKpiValue').textContent    = '\u20b9' + Math.round(totalVal).toLocaleString('en-IN');

    const sites = [...new Set(window._pdRows.map(r => r.site).filter(Boolean))].sort();
    const sf = document.getElementById('pdSiteFilter');
    if (sf) sites.forEach(s => { const o = document.createElement('option'); o.value = s; o.textContent = s; sf.appendChild(o); });

    pdApplyFilter();
  }).catch(() => {
    const tb = document.getElementById('pdTbody');
    if (tb) tb.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:2rem;color:var(--danger)">Could not load PO data. Check sheet sharing.</td></tr>';
  });

  window.pdApplyFilter = function() {
    const f   = document.getElementById('pdFilter')?.value || 'all';
    const sf  = document.getElementById('pdSiteFilter')?.value || '';
    const srch = (document.getElementById('pdSearch')?.value || '').toLowerCase();
    let rows = window._pdRows || [];
    if (sf)   rows = rows.filter(r => r.site === sf);
    if (srch) rows = rows.filter(r => r.poNo.toLowerCase().includes(srch) || r.vendor.toLowerCase().includes(srch));
    if (f === 'pending')  rows = rows.filter(r => r.status.toUpperCase() !== 'REJECTED' && r.lock === 'Released for Approval');
    if (f === 'approved') rows = rows.filter(r => r.status.toUpperCase().includes('APPROVED'));
    if (f === 'rejected') rows = rows.filter(r => r.status.toUpperCase().includes('REJECTED'));
    const tbody = document.getElementById('pdTbody');
    if (!tbody) return;
    if (!rows.length) { tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:2rem;color:var(--txt3)">No POs found.</td></tr>'; return; }
    const bgColor = r => {
      if (r.lock === 'Released for Approval') return '#fff8e1';
      if (r.status.toUpperCase().includes('APPROVED')) return '#e8f5e9';
      if (r.status.toUpperCase().includes('REJECT'))   return '#ffebee';
      return '';
    };
    tbody.innerHTML = rows.map(r => `<tr style="background:${bgColor(r)}">
      <td style="font-weight:600;color:var(--g9)">${r.poNo}</td>
      <td style="color:var(--txt2)">${r.date}</td>
      <td>${r.vendor}</td>
      <td style="color:var(--txt2)">${r.site}</td>
      <td style="text-align:right;font-weight:600">\u20b9${r.amount.toLocaleString('en-IN')}</td>
      <td><span class="tag" style="font-size:.68rem">${r.lock === 'Released for Approval' ? 'Pending Approval' : (r.status || '&#8212;')}</span></td>
    </tr>`).join('');
  };
}


// ═══════════════════════════════════════════════════════════════════════
//  PURCHASE VIEW — card-based PO verification (route 'purchase-view')
//  Each card shows PO summary; expand to see items + rates, historical
//  rate comparison (Part × Site), additional charges, and vendor bill
//  status summary from the PaymentRequest ledger.
// ═══════════════════════════════════════════════════════════════════════

let _pvAllRows    = [];
let _pvFilter     = 'all';
let _pvSearch     = '';
let _pvSite       = '';
let _pvLastDocUUID = '', _pvLastPONo = '';
let _pvLedgerFY = '';
let _pvLedgerVendorKey = '';
window._pvSetLedgerFY = function(fy) {
  _pvLedgerFY = fy;
  const box = document.getElementById('pvVendorLedgerBox');
  if (!box || !_vplpData) return;
  const v = _vplpData.vendors.find(x => x.key === _pvLedgerVendorKey);
  if (!v) return;
  box.innerHTML = _vplpLedger(v, { fy: _pvLedgerFY, onChangeFY: '_pvSetLedgerFY' });
  applyTableFeatures(box);
};
async function _pvLoadVendorLedger(r) {
  const box = document.getElementById('pvVendorLedgerBox');
  if (!box) return;
  try {
    await _vplpEnsure();
    const d = _vplpData;
    if (!d) { box.innerHTML = '<div style="color:var(--txt3);font-size:.78rem">Ledger data unavailable.</div>'; return; }
    // Resolve vendor key: prefer Vendor ID from the PO header, then name match
    const HC = _opColMap(_openPOHeaders);
    const ph = _openPOHeaders.find(h => _opPO(_opGet(h, HC, ['PO No'])) === _opPO(r.poNo));
    let vendorKey = '';
    if (ph) { const vid = String(_opGet(ph, HC, ['Vendor ID']) || '').toUpperCase().trim(); if (vid) vendorKey = vid; }
    if (!vendorKey) {
      const vn = _opNorm(r.vendor || '');
      const hit = d.vendors.find(v => _opNorm(v.name) === vn);
      if (hit) vendorKey = hit.key;
    }
    _pvLedgerVendorKey = vendorKey;
    const v = vendorKey ? d.vendors.find(x => x.key === vendorKey) : null;
    if (!v) { box.innerHTML = `<div style="font-size:.78rem;color:var(--txt3);padding:.5rem 0">No PO ledger activity found for <b>${_mdpEsc(r.vendor || '—')}</b>.</div>`; return; }
    box.innerHTML = _vplpLedger(v, { fy: _pvLedgerFY, onChangeFY: '_pvSetLedgerFY' });
    applyTableFeatures(box);
  } catch (err) {
    const b = document.getElementById('pvVendorLedgerBox');
    if (b) b.innerHTML = '<div style="color:var(--danger);font-size:.78rem">Could not load vendor ledger.</div>';
  }
}
// ── Purchase View approvals (SCM Head / MD) ──────────────────────────────
// Buttons appear in the PO detail modal only when the PO's Lock field is
// "Released for review", and each button is independently gated by an Access
// action (approve-md / approve-scm / reject-md / reject-scm) on 'purchase-view'.
// Approving/rejecting writes the PO Approval Status (PO_Actual col AG, matched
// by UUID in col A) via the backend 'updateCell' action. Rejection first asks
// for a reason from the (org-configurable) reason list.
const PV_LOCK_GATE = 'Released for review';
const PV_STATUS = {
  'approve-md':  'Approved by MD',
  'approve-scm': 'Approved by SCM Head',
  'reject-md':   'Rejected by MD',
  'reject-scm':  'Rejected by SCM Head',
};
const PV_DEFAULT_REJECT_REASONS = [
  'Rate higher than market / last purchase',
  'Incorrect vendor',
  'Incorrect quantity',
  'Incorrect specification / item',
  'Budget not available',
  'Duplicate PO',
  'Incomplete / incorrect details',
  'Other',
];
// Reason list — org override via PortalConfig 'po_reject_reasons' (JSON array).
function _pvRejectReasons() {
  const v = pcReadJSON('po_reject_reasons', null);
  return (Array.isArray(v) && v.length) ? v.map(String) : PV_DEFAULT_REJECT_REASONS;
}
// Optional column to persist the rejection reason into (PO_Actual). Off unless
// PortalConfig 'po_reject_reason_col' is set to a column letter (e.g. "AH").
function _pvReasonCol() {
  try { const v = (window._SHEET_CONFIG || {})['po_reject_reason_col']; if (typeof v === 'string' && /^[A-Za-z]{1,3}$/.test(v.trim())) return v.trim().toUpperCase(); } catch (e) {}
  return '';
}
function _pvCan(action) { return (typeof userCan !== 'function') || userCan('purchase-view', action); }
// A PO is eligible for the approve/reject buttons when its Lock field is
// "Released for review" (per spec). Real POs may carry "Released for Approval"
// for the same stage, so accept either, plus anything the Pending tab counts.
const PV_LOCK_GATES = ['released for review', 'released for approval'];
function _pvIsGated(r) {
  const lk = (r.lock || '').trim().toLowerCase();
  return r.isPending || PV_LOCK_GATES.indexOf(lk) !== -1;
}
function _pvActionButtons(r, fontSize) {
  const po = _mdpEsc(r.poNo), fs = fontSize || '.74rem';
  const btn = (action, bg, label) => _pvCan(action)
    ? `<button onclick="event.stopPropagation();_pv${action.startsWith('approve') ? 'Approve' : 'Reject'}('${po}','${action.endsWith('md') ? 'md' : 'scm'}')" class="btn btn-sm" style="background:${bg};color:#fff;border:none;font-size:${fs}">${label}</button>`
    : '';
  return [
    btn('approve-md',  '#15803d', '&#10003; Approve (MD)'),
    btn('approve-scm', '#16a34a', '&#10003; Approve (SCM Head)'),
    btn('reject-md',   '#b91c1c', '&#10007; Reject (MD)'),
    btn('reject-scm',  '#dc2626', '&#10007; Reject (SCM Head)'),
  ].filter(Boolean);
}
function _pvActionBar(r) {
  if (!_pvIsGated(r)) return '';
  const btns = _pvActionButtons(r);
  if (!btns.length) return '';
  return `<div class="card card-pad" style="margin-bottom:1rem;display:flex;gap:.5rem;flex-wrap:wrap;align-items:center;background:var(--surface2)">
    <span style="font-size:.7rem;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.04em">Approval</span>
    ${btns.join('')}
    <span id="pv-action-msg" style="font-size:.74rem;color:var(--txt3);margin-left:auto"></span>
  </div>`;
}
async function _pvWriteCell(uuid, col, val) {
  const res = await fetch(APPS_SCRIPT_URL, {
    method: 'POST', headers: { 'Content-Type': 'text/plain;charset=utf-8' },
    body: JSON.stringify({ action: 'updateCell', sheetId: PO_SHEET_ID, tab: PO_TAB, matchCol: 'A', matchVal: uuid, updateCol: col, updateVal: val }),
  });
  const j = await res.json().catch(() => ({}));
  return !!(j && (j.success || j.ok));
}
async function _pvApplyStatus(r, status, reason) {
  const msg = document.getElementById('pv-action-msg');
  if (msg) { msg.textContent = 'Saving…'; msg.style.color = 'var(--txt3)'; }
  if (!r.uuid) { if (msg) { msg.textContent = 'No PO UUID — cannot write'; msg.style.color = 'var(--danger)'; } return; }
  try {
    const ok = await _pvWriteCell(r.uuid, 'AG', status);
    if (!ok) throw new Error('write failed');
    const rc = _pvReasonCol();
    if (reason && rc) { try { await _pvWriteCell(r.uuid, rc, reason); } catch (e) {} }
    r.status = status;
    if (msg) { msg.textContent = 'Saved ✓'; msg.style.color = '#16a34a'; }
    setTimeout(() => { try { _regCloseModal(); } catch (e) {} _pvLoad(true); }, 700);
  } catch (e) {
    if (msg) { msg.textContent = 'Save failed — check backend / sheet access'; msg.style.color = 'var(--danger)'; }
  }
}
window._pvApprove = function(poNo, role) {
  const r = _pvAllRows.find(x => x.poNo === poNo); if (!r) return;
  const action = role === 'md' ? 'approve-md' : 'approve-scm';
  if (!_pvCan(action)) { alert('You do not have permission for this action.'); return; }
  const status = PV_STATUS[action];
  if (!confirm(`Approve ${poNo}\n\nSet PO Approval Status to “${status}”?`)) return;
  _pvApplyStatus(r, status, '');
};
window._pvReject = function(poNo, role) {
  const r = _pvAllRows.find(x => x.poNo === poNo); if (!r) return;
  const action = role === 'md' ? 'reject-md' : 'reject-scm';
  if (!_pvCan(action)) { alert('You do not have permission for this action.'); return; }
  const esc = _mdpEsc, reasons = _pvRejectReasons();
  let ov = document.getElementById('pvRejectOverlay'); if (ov) ov.remove();
  ov = document.createElement('div');
  ov.id = 'pvRejectOverlay';
  ov.style.cssText = 'position:fixed;inset:0;z-index:1300;background:rgba(0,0,0,.45);display:flex;align-items:center;justify-content:center;padding:1rem';
  ov.innerHTML = `<div class="card" style="max-width:440px;width:100%">
    <div class="card-pad">
      <div style="font-weight:700;font-size:1rem;margin-bottom:.15rem">Reject ${esc(poNo)}</div>
      <div style="font-size:.76rem;color:var(--txt3);margin-bottom:.9rem">${role === 'md' ? 'Reject (MD)' : 'Reject (SCM Head)'}${r.vendor ? ' &middot; ' + esc(r.vendor) : ''}</div>
      <label style="font-size:.7rem;font-weight:700;color:var(--txt3)">REJECTION REASON</label>
      <select id="pvRejReason" style="width:100%;margin:.3rem 0 .8rem;padding:7px 9px;border:1px solid var(--border);border-radius:6px;background:var(--surface2);font-size:.84rem">
        ${reasons.map(x => `<option value="${esc(x)}">${esc(x)}</option>`).join('')}
      </select>
      <label style="font-size:.7rem;font-weight:700;color:var(--txt3)">NOTE (optional)</label>
      <textarea id="pvRejNote" rows="2" style="width:100%;margin-top:.3rem;padding:7px 9px;border:1px solid var(--border);border-radius:6px;background:var(--surface2);font-size:.84rem;resize:vertical" placeholder="Add detail…"></textarea>
      <div style="display:flex;gap:.5rem;justify-content:flex-end;margin-top:1rem">
        <button onclick="document.getElementById('pvRejectOverlay').remove()" class="btn btn-sm btn-secondary">Cancel</button>
        <button id="pvRejConfirm" onclick="_pvConfirmReject('${esc(poNo)}','${role}')" class="btn btn-sm" style="background:#dc2626;color:#fff;border:none">Confirm Reject</button>
      </div>
    </div>
  </div>`;
  ov.addEventListener('click', e => { if (e.target === ov) ov.remove(); });
  document.body.appendChild(ov);
};
window._pvConfirmReject = function(poNo, role) {
  const r = _pvAllRows.find(x => x.poNo === poNo); if (!r) return;
  const action = role === 'md' ? 'reject-md' : 'reject-scm';
  const reason = (document.getElementById('pvRejReason') || {}).value || '';
  const note = ((document.getElementById('pvRejNote') || {}).value || '').trim();
  const full = note ? `${reason} — ${note}` : reason;
  const ov = document.getElementById('pvRejectOverlay'); if (ov) ov.remove();
  _pvApplyStatus(r, PV_STATUS[action], full);
};

function renderPurchaseView() {
  const el = document.getElementById('mainContent');
  _pvFilter = 'all'; _pvSearch = ''; _pvSite = '';
  el.innerHTML = `
    <div class="page-header">
      <div class="page-header-row">
        <div><h1>Purchase View</h1><p>PO verification &middot; items &amp; rates &middot; vendor ledger &middot; additional charges</p></div>
        <button class="btn btn-secondary btn-sm" onclick="_pvLoad(true)">&#8635; Refresh</button>
      </div>
    </div>
    <div style="display:flex;gap:.5rem;margin-bottom:1rem;flex-wrap:wrap;align-items:center">
      <div style="display:flex;gap:.35rem">
        <button id="pv-tab-all"      onclick="_pvSetFilter('all')"      class="btn btn-sm btn-primary">All</button>
        <button id="pv-tab-pending"  onclick="_pvSetFilter('pending')"  class="btn btn-sm btn-secondary">&#9203; Pending</button>
        <button id="pv-tab-approved" onclick="_pvSetFilter('approved')" class="btn btn-sm btn-secondary">&#10003; Approved</button>
        <button id="pv-tab-rejected" onclick="_pvSetFilter('rejected')" class="btn btn-sm btn-secondary">&#10007; Rejected</button>
      </div>
      <input id="pv-search" type="text" placeholder="Search PO, vendor, site&#8230;" oninput="_pvOnSearch(this.value)"
        style="flex:1;min-width:180px;padding:.38rem .65rem;border:1.5px solid var(--border);border-radius:8px;font-size:.82rem;font-family:inherit;outline:none;background:var(--surface2)">
      <select id="pv-site" onchange="_pvSetSite(this.value)"
        style="padding:.38rem .65rem;border:1.5px solid var(--border);border-radius:8px;font-size:.82rem;font-family:inherit;background:var(--surface2)">
        <option value="">All Sites</option>
      </select>
    </div>
    <div class="kpi-grid" style="margin-bottom:1.2rem">
      <div class="kpi-card"      style="padding:.75rem 1rem"><div class="kpi-value" id="pv-kpi-total">—</div><div class="kpi-label">Total POs</div></div>
      <div class="kpi-card warn" style="padding:.75rem 1rem"><div class="kpi-value" id="pv-kpi-pending">—</div><div class="kpi-label">Pending</div></div>
      <div class="kpi-card info" style="padding:.75rem 1rem"><div class="kpi-value" id="pv-kpi-approved">—</div><div class="kpi-label">Approved</div></div>
      <div class="kpi-card"      style="padding:.75rem 1rem"><div class="kpi-value" id="pv-kpi-rejected">—</div><div class="kpi-label">Rejected</div></div>
    </div>
    <div id="pv-cards">
      <div style="display:flex;align-items:center;justify-content:center;gap:12px;padding:3rem;color:var(--txt3)">
        <div style="width:24px;height:24px;border:2px solid var(--border);border-top-color:var(--g5);border-radius:50%;animation:spin 1s linear infinite"></div>
        Loading POs&hellip;
      </div>
    </div>`;
  _pvLoad();
}

async function _pvLoad(force) {
  const cardsEl = document.getElementById('pv-cards');
  try {
    await Promise.all([_regEnsure(force), _mdpLoad(force)]);
  } catch (e) {
    if (cardsEl) cardsEl.innerHTML = '<div class="card card-pad" style="color:var(--danger)">Could not load PO data. Check sheet sharing.</div>';
    return;
  }
  _pvAllRows = _pvBuildRows();
  _pvFillSiteDropdown();
  _pvFillKPIs();
  _pvRenderCards();
}

function _pvBuildRows() {
  const HC = _opColMap(_openPOHeaders);
  return _openPOHeaders
    .filter(r => {
      const p = (_opGet(r, HC, ['PO No']) || '').trim();
      return p && p.toLowerCase() !== 'dummy';
    })
    .map(r => {
      const G = cands => _opGet(r, HC, cands);
      const statusRaw = G(['PO Approval Status']) || '';
      const lock = G(['Lock']) || '';
      const isPending  = statusRaw.toUpperCase() !== 'REJECTED' && lock === 'Released for Approval';
      const isApproved = statusRaw.toUpperCase().includes('APPROVED');
      const isRejected = statusRaw.toUpperCase().includes('REJECT');
      return {
        raw: r,
        poNo:     G(['PO No']),
        date:     G(['PO Date']),
        vendor:   G(['Vendor Name', 'Vendor', 'Supplier Name', 'Supplier', 'Party Name']),
        site:     G(['Site Name']),
        status:   statusRaw,
        lock,
        isPending, isApproved, isRejected,
        uuid:     G(['UUID']) || '',
        net:      _opNum(G(['Net Amount', 'Grand Total'])),
        approver: G(['Approver Name']),
      };
    })
    .sort((a, b) => _mdpDateVal(b.date) - _mdpDateVal(a.date));
}

function _pvFillSiteDropdown() {
  const sel = document.getElementById('pv-site'); if (!sel) return;
  const sites = [...new Set(_pvAllRows.map(r => r.site).filter(Boolean))].sort();
  const cur = sel.value;
  sel.innerHTML = '<option value="">All Sites</option>' +
    sites.map(s => `<option value="${_mdpEsc(s)}" ${s === cur ? 'selected' : ''}>${_mdpEsc(s)}</option>`).join('');
}

function _pvFillKPIs() {
  const tot  = _pvAllRows.length;
  const pend = _pvAllRows.filter(r => r.isPending).length;
  const appr = _pvAllRows.filter(r => r.isApproved).length;
  const rej  = _pvAllRows.filter(r => r.isRejected).length;
  const s = (id, v) => { const e = document.getElementById(id); if (e) e.textContent = v; };
  s('pv-kpi-total', tot); s('pv-kpi-pending', pend); s('pv-kpi-approved', appr); s('pv-kpi-rejected', rej);
}

function _pvFilteredRows() {
  let rows = _pvAllRows;
  if (_pvFilter === 'pending')  rows = rows.filter(r => r.isPending);
  if (_pvFilter === 'approved') rows = rows.filter(r => r.isApproved);
  if (_pvFilter === 'rejected') rows = rows.filter(r => r.isRejected);
  if (_pvSite)   rows = rows.filter(r => r.site === _pvSite);
  if (_pvSearch) { const q = _pvSearch.toLowerCase(); rows = rows.filter(r => (r.poNo + ' ' + r.vendor + ' ' + r.site).toLowerCase().includes(q)); }
  return rows;
}

function _pvRenderCards() {
  const el = document.getElementById('pv-cards'); if (!el) return;
  const rows = _pvFilteredRows();
  if (!rows.length) {
    el.innerHTML = '<div class="card card-pad" style="text-align:center;color:var(--txt3);padding:2rem">No POs found.</div>';
    return;
  }
  el.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:1rem">${rows.map(r => _pvSummaryCard(r)).join('')}</div>`;
}

function _pvStatusStyle(r) {
  if (r.isApproved) return { color:'#2e7d32', bg:'#e8f5e9', label:'Approved',         accent:'#2e7d32' };
  if (r.isRejected) return { color:'#c62828', bg:'#ffebee', label:'Rejected',         accent:'#c62828' };
  if (r.isPending)  return { color:'#b07000', bg:'#fff8e1', label:'Pending Approval', accent:'#f59e0b' };
  return               { color:'var(--txt2)', bg:'var(--surface2)', label:r.status || 'Draft', accent:'var(--g5)' };
}

function _pvSummaryCard(r) {
  const esc = _mdpEsc;
  const st = _pvStatusStyle(r);
  const appLink = r.uuid
    ? `${APPSHEET_SCM_URL}?tblName=PO&rowKey=${encodeURIComponent(r.uuid)}`
    : AS.purchase();
  return `<div class="card" style="border-left:4px solid ${st.accent}">
    <div style="padding:.85rem 1rem">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:.3rem">
        <span style="font-weight:700;font-size:.95rem;color:var(--g9);font-family:monospace">${esc(r.poNo)}</span>
        <span style="background:${st.bg};color:${st.color};padding:.15rem .5rem;border-radius:20px;font-size:.68rem;font-weight:700;white-space:nowrap;flex-shrink:0;margin-left:.5rem">${st.label}</span>
      </div>
      <div style="font-size:.83rem;color:var(--txt2);margin-bottom:.2rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(r.vendor) || '—'}</div>
      <div style="display:flex;justify-content:space-between;align-items:center">
        <span style="font-size:.72rem;color:var(--txt3)">${esc(r.site)} &middot; ${_mdpFmtDate(r.date)}</span>
        <span style="font-weight:700;color:var(--g8);font-size:.9rem">${r.net ? '&#8377;' + r.net.toLocaleString('en-IN') : '—'}</span>
      </div>
      <div style="display:flex;gap:.5rem;margin-top:.75rem;flex-wrap:wrap">
        <button onclick="_pvToggle('${esc(r.poNo)}')" class="btn btn-sm btn-secondary" style="font-size:.72rem">&#128269; Verify PO</button>
        <a href="${esc(appLink)}" target="_blank" class="btn btn-sm btn-secondary" style="font-size:.72rem;text-decoration:none">&#128279; AppSheet</a>
      </div>
      ${_pvIsGated(r) && _pvActionButtons(r, '.7rem').length ? `<div style="display:flex;gap:.4rem;margin-top:.5rem;flex-wrap:wrap;padding-top:.5rem;border-top:1px solid var(--border)">${_pvActionButtons(r, '.7rem').join('')}</div>` : ''}
    </div>
  </div>`;
}

window._pvToggle = function(poNo) {
  const r = _pvAllRows.find(x => x.poNo === poNo); if (!r) return;
  const st = _pvStatusStyle(r);
  const appLink = r.uuid
    ? `${APPSHEET_SCM_URL}?tblName=PO&rowKey=${encodeURIComponent(r.uuid)}`
    : AS.purchase();
  const headerExtra = `<a href="${_mdpEsc(appLink)}" target="_blank" class="btn btn-sm btn-secondary" style="font-size:.72rem;text-decoration:none">&#128279; AppSheet</a>`;
  const titleHtml = `${_mdpEsc(poNo)} <span style="background:${st.bg};color:${st.color};padding:.12rem .45rem;border-radius:20px;font-size:.68rem;font-weight:700;margin-left:.4rem">${st.label}</span>`;
  _pvLedgerFY = '';
  _regOpenModal(titleHtml, _pvActionBar(r) + _pvDetailBody(r), headerExtra);
  _poLoadAttachments(_pvLastDocUUID, _pvLastPONo);
  _pvLoadVendorLedger(r);
};

// Rate verdict: this PO's rate vs the average of past rates for the same
// material+site. A ±0.5% band counts as "same" (absorbs rounding/paise noise);
// anything beyond ALWAYS shows its direction. Big swings (>=10%) are loud
// (red/green); small drifts are muted (orange/olive) but still flagged — so a
// 4% rise reads as "▲ +4%", never a misleading "=".
function _pvRateDelta(rate, avg) {
  const diff = avg ? (rate - avg) / avg : 0;   // signed fraction
  const pct  = Math.round(diff * 100);          // integer % for display
  if (diff >  0.10)  return { symbol: '&#9650;', text: '+' + pct + '%', bg: '#ffebee', color: '#c62828' }; // >=10% over — alarm
  if (diff >  0.005) return { symbol: '&#9650;', text: '+' + pct + '%', bg: '#fff3e0', color: '#e65100' }; // mildly higher
  if (diff < -0.10)  return { symbol: '&#9660;', text: pct + '%',       bg: '#e8f5e9', color: '#2e7d32' }; // >=10% under — good
  if (diff < -0.005) return { symbol: '&#9660;', text: pct + '%',       bg: '#f1f8e9', color: '#558b2f' }; // mildly lower
  return { symbol: '&#61;', text: '', bg: '#e3f2fd', color: '#1565c0' };                                   // within ±0.5% — same
}
function _pvDetailBody(r) {
  const esc = _mdpEsc;
  const inr = v => '&#8377;' + Number(v || 0).toLocaleString('en-IN', {minimumFractionDigits:2, maximumFractionDigits:2});
  const HC = _opColMap(_openPOHeaders);
  const IC = _opColMap(_openPOItems);
  const AC = _opColMap(_openPOAddlCharges);
  const K  = _opPO(r.poNo);
  const KK = _opPOKey(r.poNo); // letter-sorted for EGVE/EVGE variants
  const G  = cands => _opGet(r.raw, HC, cands);

  // Items for this PO
  const items = _openPOItems.filter(x => _opPO(_opGet(x, IC, ['PO No', 'Order No'])) === K);

  // Additional Charges rows for this PO — try both simple and key-sorted PO number
  const _addlPOCols = ['PO No', 'PO No (Key)', 'Order No', 'PO Number', 'PO No.', 'PO'];
  const addlRows = _openPOAddlCharges.filter(x => {
    const xpo = _opGet(x, AC, _addlPOCols);
    return _opPO(xpo) === K || _opPOKey(xpo) === KK;
  });

  // Build historical rate map (Part × Site) from all other approved POs
  const hdrByPO = {};
  _openPOHeaders.forEach(h => { const k = _opPO(_opGet(h, HC, ['PO No'])); if (k) hdrByPO[k] = h; });
  const rateMap = {};
  const _matMap = _opMatMap();
  const currentPOItems = new Set(items); // exclude by object identity — immune to PO No format drift
  _openPOItems.forEach(x => {
    if (currentPOItems.has(x)) return;
    const xPoNo = _opPO(_opGet(x, IC, ['PO No', 'Order No']));
    if (xPoNo === K) return;
    const ph = hdrByPO[xPoNo]; if (!ph) return;
    const site = _opNorm(_opGet(ph, HC, ['Site Name']));
    const rawDesc = _opGet(x, IC, ['Material Description', 'Material Desc', 'Material Name']) ||
                    _opGet(x, IC, ['Description', 'Item Description', 'Particulars', 'Item']) ||
                    _opGet(x, IC, ['Part Details', 'Part Description']);
    const part = _opNorm(_opPartReadable(rawDesc, _matMap).text || rawDesc);
    const rate = _opNum(_opGet(x, IC, ['Unit Rate', 'Rate', 'Unit Price', 'Price', 'Basic Rate']));
    if (!part || !rate) return;
    const key = part + '||' + site;
    (rateMap[key] = rateMap[key] || []).push({ rate, poNo: _opGet(ph, HC, ['PO No']), date: _opGet(ph, HC, ['PO Date']), vendor: _opGet(ph, HC, ['Vendor Name', 'Vendor', 'Supplier Name', 'Supplier', 'Party Name']), site: _opGet(ph, HC, ['Site Name', 'Site', 'Project Site']) });
  });

  // ── Line items table (PDF columns: MR ID | Description | UOM | Qty | Unit Rate | Tax % | Tax Amt | Total)
  let calcSubA = 0, calcTaxA = 0;
  const rateHistoryItems = []; // collect per-item history for the Rate History section
  const itemRows = items.map(x => {
    const g = c => _opGet(x, IC, c);
    const mrId    = g(['MR ID', 'MR No', 'MRS', 'MR']);
    const partKey = g(['Part Details', 'Part Description']);
    const rawDesc = g(['Material Description', 'Material Desc', 'Material Name', 'Material']) ||
                    g(['Description', 'Item Description', 'Particulars', 'Item']) || partKey;
    const pr    = _opPartReadable(rawDesc, _matMap);
    const qty   = _opNum(g(['Qty', 'Quantity', 'PO Qty', 'Order Qty']));
    const rate  = _opNum(g(['Unit Rate', 'Rate', 'Unit Price', 'Price', 'Basic Rate']));
    const uom   = g(['UOM', 'Unit', 'Units']);
    const taxP  = g(['Tax (%)', 'Tax %', 'Tax Percentage', 'GST %', 'Tax Percent']);
    const taxA  = _opNum(g(['Tax. Amount', 'Tax Amount', 'Tax Amt', 'Total Tax']));
    const tot   = _opNum(g(['Total Amount', 'Amount', 'Line Total'])) || qty * rate;
    calcSubA += tot; calcTaxA += taxA;

    // Rate badge vs Part × Site history
    const partNorm = _opNorm(pr.text || rawDesc);
    const siteNorm = _opNorm(r.site);
    const hist = (rateMap[partNorm + '||' + siteNorm] || []);
    let rateBadge = '';
    if (rate && hist.length) {
      const sorted = hist.slice().sort((a, b) => _mdpDateVal(b.date) - _mdpDateVal(a.date));
      const avg  = hist.reduce((s, e) => s + e.rate, 0) / hist.length;
      const diff = (rate - avg) / avg;
      const tipLines = sorted.map(h => `${esc(h.poNo)} (${_mdpFmtDate(h.date)}) &#8377;${h.rate.toLocaleString('en-IN', {minimumFractionDigits:2, maximumFractionDigits:2})}`).join('&#10;');
      const tip  = `Avg &#8377;${avg.toLocaleString('en-IN', {minimumFractionDigits:2, maximumFractionDigits:2})} across ${hist.length} PO${hist.length>1?'s':''}:&#10;${tipLines}`;
      const d = _pvRateDelta(rate, avg);
      rateBadge = `<span title="${tip}" style="background:${d.bg};color:${d.color};font-size:.6rem;font-weight:700;padding:.1rem .35rem;border-radius:9px;margin-left:.3rem;cursor:help">${d.symbol}${d.text ? ' ' + d.text : ''}</span>`;
      rateHistoryItems.push({ desc: pr.partDesc || rawDesc || partKey || '—', thisRate: rate, avg, diff, sorted });
    } else if (rate) {
      // No prior purchase of this item at this site — say so explicitly.
      rateBadge = `<span title="No previous purchase of this item at this site — first-time rate, nothing to compare against" style="background:#eef2ff;color:#4338ca;font-size:.6rem;font-weight:700;padding:.1rem .35rem;border-radius:9px;margin-left:.3rem;cursor:help">&#9737; No history</span>`;
    }
    const descHtml = (pr.partNo ? `<span style="font-family:monospace;font-size:.68rem;color:var(--g7)">${esc(pr.partNo)}</span> &middot; ` : '') + esc(pr.partDesc || '—');
    const td = 'padding:5px 8px;font-size:.77rem';
    return `<tr>
      <td style="${td};color:var(--txt3);font-size:.7rem;white-space:nowrap">${esc(mrId) || '—'}</td>
      <td style="${td}">${descHtml}</td>
      <td style="${td};white-space:nowrap">${esc(uom) || '—'}</td>
      <td style="${td};text-align:right">${qty || '—'}</td>
      <td style="${td};text-align:right;white-space:nowrap">${rate ? inr(rate) : '—'}${rateBadge}</td>
      <td style="${td};color:var(--txt3)">${esc(taxP) || '—'}</td>
      <td style="${td};text-align:right;color:var(--txt2)">${taxA ? inr(taxA) : '—'}</td>
      <td style="${td};text-align:right;font-weight:600">${tot ? inr(tot) : '—'}</td>
    </tr>`;
  }).join('');

  // ── Additional Charges table (from separate sheet tab)
  // Read header totals early so the fallback note can show them when tab rows are missing.
  const _subBHdr = _opNum(G(['Sub Total (b)', 'Sub Total(b)', 'Sub Total B']));
  const _taxBHdr = _opNum(G(['Tax (b)', 'Tax(b)', 'Tax B']));
  let calcSubB = 0, calcTaxB = 0;
  const addlChargeRows = addlRows.map(x => {
    const g = c => _opGet(x, AC, c);
    const desc  = g(['Description', 'Charge Description', 'Charge Type', 'Particulars', 'Type', 'Charge', 'Service Description', 'Item']);
    const amt   = _opNum(g(['Amount', 'Base Amount', 'Charge Amount', 'Sub Total', 'Value', 'Net']));
    const taxP  = g(['Tax (%)', 'Tax %', 'GST %', 'Tax Percentage', 'Tax Rate', 'Tax']);
    const taxA  = _opNum(g(['Tax Amount', 'Tax Amt', 'Tax. Amount', 'GST Amount']));
    const tot   = _opNum(g(['Total', 'Total Amount', 'Net Amount', 'Grand Total'])) || (amt + taxA);
    calcSubB += (amt || tot); calcTaxB += taxA;
    const td = 'padding:5px 8px;font-size:.77rem';
    return `<tr>
      <td style="${td}">${esc(desc) || '—'}</td>
      <td style="${td};text-align:right">${amt ? inr(amt) : '—'}</td>
      <td style="${td};color:var(--txt3)">${esc(taxP) || '—'}</td>
      <td style="${td};text-align:right;color:var(--txt2)">${taxA ? inr(taxA) : '—'}</td>
      <td style="${td};text-align:right;font-weight:600">${tot ? inr(tot) : '—'}</td>
    </tr>`;
  }).join('');

  // ── Totals — prefer header values, fall back to calculated sums
  const subA = _opNum(G(['Sub Total (a)'])) || calcSubA;
  const taxA_h = _opNum(G(['Tax (a)'])) || calcTaxA;
  const subB = _opNum(G(['Sub Total (b)'])) || calcSubB;
  const taxB_h = _opNum(G(['Tax (b)'])) || calcTaxB;
  const rnd  = _opNum(G(['Round', 'Round off', 'Roundoff']));
  const net  = _opNum(G(['Net Amount', 'Grand Total'])) || (subA + taxA_h + subB + taxB_h + (rnd||0));

  const tRowFn = (l, v, bold, accent) => {
    if (!v && v !== 0) return '';
    const color = accent || (bold ? 'var(--txt)' : 'var(--txt3)');
    const border = bold ? 'border-top:2px solid var(--border);padding-top:7px;' : '';
    return `<tr>
      <td style="padding:3px 16px 3px 0;font-size:.8rem;${border}color:${color};${bold?'font-weight:700':''}">${l}</td>
      <td style="text-align:right;padding:3px 0;font-size:.8rem;${border}color:${color};${bold?'font-weight:700':''}">${inr(v)}</td>
    </tr>`;
  };

  const totalsHtml = `<div style="display:flex;justify-content:flex-end;margin:.5rem 0 .5rem">
    <table style="min-width:260px"><tbody>
      ${tRowFn('Sub Total (a)', subA)}
      ${tRowFn('Tax (a)', taxA_h)}
      ${subB ? tRowFn('Sub Total (b)', subB) : ''}
      ${taxB_h ? tRowFn('Tax (b)', taxB_h) : ''}
      ${rnd ? tRowFn('Round off (\xb1)', rnd) : ''}
      ${tRowFn('Grand Total', net, true, '#1a6634')}
    </tbody></table>
  </div>`;

  const H = t => `<div style="font-size:.72rem;font-weight:700;color:var(--g9);margin:1rem 0 .4rem;text-transform:uppercase;letter-spacing:.05em;padding:0 1rem;border-left:3px solid var(--g5)">${t}</div>`;

  const inWords = G(['Amount in Words']);

  // ── Documents: quote attachments (Drive files named by UUID) + the PO PDF
  // (Drive file named by PO Number) — both fetched by _poLoadAttachments. Sheet-
  // column URLs are intentionally NOT shown (AppSheet refs 404 outside the app).
  const quoteRef  = G(['Quote Ref', 'Quote Reference', 'Quote No']);
  const quoteDate = G(['Quote Date']);
  _pvLastDocUUID = G(['UUID']) || '';
  _pvLastPONo    = r.poNo || '';
  const docSection = `
    ${H('Documents')}
    <div style="padding:0 1rem .5rem">
      ${quoteRef || quoteDate ? `<div style="font-size:.76rem;color:var(--txt2);margin-bottom:.4rem">Quote: <b>${esc(quoteRef) || '—'}</b>${quoteDate ? ' &nbsp;&middot;&nbsp; ' + _mdpFmtDate(quoteDate) : ''}</div>` : ''}
      <div id="poAttBox" style="color:var(--txt3);font-size:.78rem;padding:.3rem 0">&#9203; Loading documents&hellip;</div>
    </div>`;


  return `<div>
    ${docSection}
    ${H('Items &amp; Rates')}
    <div style="padding:0 1rem .25rem">
      ${items.length
        ? `<div style="overflow-x:auto"><table class="data-table" style="font-size:.77rem;margin:0">
            <thead><tr><th>MR ID</th><th>Description</th><th>UOM</th><th style="text-align:right">Qty</th><th style="text-align:right">Unit Rate</th><th>Tax %</th><th style="text-align:right">Tax Amt</th><th style="text-align:right">Total</th></tr></thead>
            <tbody>${itemRows}</tbody>
           </table></div>`
        : '<div style="color:var(--txt3);font-size:.78rem;padding:.25rem 0">No line items found.</div>'}
    </div>

    ${H('Additional Charges')}
    <div style="padding:0 1rem .25rem">
      ${addlRows.length
        ? `<div style="overflow-x:auto"><table class="data-table" style="font-size:.77rem;margin:0">
            <thead><tr><th>Description</th><th style="text-align:right">Amount</th><th>Tax %</th><th style="text-align:right">Tax Amt</th><th style="text-align:right">Total</th></tr></thead>
            <tbody>${addlChargeRows}</tbody>
           </table></div>`
        : _subBHdr
          ? `<div style="overflow-x:auto"><table class="data-table" style="font-size:.77rem;margin:0">
               <thead><tr><th>Description</th><th style="text-align:right">Amount</th><th>Tax %</th><th style="text-align:right">Tax Amt</th><th style="text-align:right">Total</th></tr></thead>
               <tbody><tr>
                 <td style="padding:5px 8px">Additional Charges</td>
                 <td style="padding:5px 8px;text-align:right">${inr(_subBHdr)}</td>
                 <td style="padding:5px 8px;color:var(--txt3)">—</td>
                 <td style="padding:5px 8px;text-align:right;color:var(--txt2)">${_taxBHdr ? inr(_taxBHdr) : '—'}</td>
                 <td style="padding:5px 8px;text-align:right;font-weight:600">${inr(_subBHdr + (_taxBHdr || 0))}</td>
               </tr></tbody>
             </table></div>
             <div style="font-size:.7rem;color:var(--txt3);margin-top:.3rem">&#9432; Breakup not available — total from PO header</div>`
          : '<div style="color:var(--txt3);font-size:.78rem;padding:.25rem 0">No additional charges for this PO.</div>'}
    </div>

    <div style="padding:0 1rem">
      ${totalsHtml}
      ${inWords ? `<div style="font-size:.76rem;color:var(--txt2);margin-bottom:.75rem"><b>In words:</b> ${esc(inWords)}</div>` : ''}
    </div>

    ${rateHistoryItems.length ? `
    ${H('Rate Comparison History')}
    <div style="padding:0 1rem .25rem">
      <div style="overflow-x:auto"><table class="data-table" style="font-size:.75rem;margin:0">
        <thead><tr>
          <th>Material</th>
          <th style="text-align:right">This Rate</th>
          <th style="text-align:right">Past Avg</th>
          <th style="text-align:center">&#916;</th>
          <th>Past PO</th>
          <th>Vendor</th>
          <th>Site</th>
          <th>Date</th>
          <th style="text-align:right">Past Rate</th>
        </tr></thead>
        <tbody>${rateHistoryItems.map(h => {
          const d = _pvRateDelta(h.thisRate, h.avg);
          const diffLabel = `<span style="color:${d.color};font-weight:700">${d.symbol}${d.text ? ' ' + d.text : ''}</span>`;
          const td = 'padding:4px 8px';
          return h.sorted.map((p, i) => `<tr>
            ${i === 0 ? `<td rowspan="${h.sorted.length}" style="${td}">${esc(h.desc)}</td>
              <td rowspan="${h.sorted.length}" style="${td};text-align:right;font-weight:600">${inr(h.thisRate)}</td>
              <td rowspan="${h.sorted.length}" style="${td};text-align:right;color:var(--txt2)">${inr(h.avg)}</td>
              <td rowspan="${h.sorted.length}" style="${td};text-align:center">${diffLabel}</td>` : ''}
            <td style="${td};font-family:monospace;font-size:.7rem">${esc(p.poNo) || '—'}</td>
            <td style="${td};font-size:.72rem">${esc(p.vendor) || '—'}</td>
            <td style="${td};font-size:.72rem;color:var(--txt2)">${esc(p.site) || '—'}</td>
            <td style="${td};white-space:nowrap;color:var(--txt2)">${_mdpFmtDate(p.date)}</td>
            <td style="${td};text-align:right">${inr(p.rate)}</td>
          </tr>`).join('');
        }).join('')}</tbody>
      </table></div>
    </div>` : `
    ${H('Rate Comparison History')}
    <div style="padding:0 1rem .5rem"><div style="background:#eef2ff;border:1px solid #c7d2fe;border-radius:8px;padding:.7rem .9rem;font-size:.8rem;color:#3730a3">
      &#9737; <b>No previous purchase history</b> for these items at this site — these are first-time rates, so there is nothing to compare against.
    </div></div>`}

    ${H('Vendor Ledger — ' + _mdpEsc(r.vendor || '—'))}
    <div style="padding:0 1rem 1rem"><div id="pvVendorLedgerBox" style="color:var(--txt3);font-size:.78rem;padding:.3rem 0">&#9203; Loading vendor ledger&hellip;</div></div>
  </div>`;
}

window._pvSetFilter = function(f) {
  _pvFilter = f;
  ['all','pending','approved','rejected'].forEach(k => {
    const b = document.getElementById('pv-tab-' + k);
    if (b) b.className = 'btn btn-sm ' + (k === f ? 'btn-primary' : 'btn-secondary');
  });
  _pvRenderCards();
};
window._pvOnSearch = function(v) {
  clearTimeout(window._pvSearchT);
  window._pvSearchT = setTimeout(() => {
    _pvSearch = v.trim(); _pvRenderCards();
    const e = document.getElementById('pv-search');
    if (e) { e.focus(); const n = e.value.length; try { e.setSelectionRange(n,n); } catch (_) {} }
  }, 250);
};
window._pvSetSite = function(v) { _pvSite = v; _pvRenderCards(); };

// ── ITEM RATE MASTER ────────────────────────────────────────────────────────
// Route: item-rate-master | Section: Procurement
// Min / max / avg purchase rate per item, sourced from the
// 4-GRNMaster_Actual tab of the Master spreadsheet (SHEET_ID).
// Type 1 groups by Item + UOM + Site; Type 2 groups by Item + UOM.
// Period filter: financial year. Export gated by Access Settings 'export' action.

let _irmFY      = '';
let _irmType    = 1;
let _irmSearch  = '';
let _irmAllRows = [];
let _irmGrouped = null;
let _irmGRNRows = null;   // raw rows from 4-GRNMaster_Actual
let _irmExpanded = new Set();

async function _irmEnsure(force) {
  if (!force && _irmGRNRows) return;
  await _openPOEnsure(force);
  try {
    _irmGRNRows = await fetchSheetSafe('4-GRNMaster_Actual', SHEET_ID, { rawId: true }) || [];
  } catch (e) {
    _irmGRNRows = [];
  }
}

async function renderItemRateMaster() {
  const el = document.getElementById('mainContent'); if (!el) return;
  el.innerHTML = `<div class="page-header"><div class="page-header-row">
    <div><h1>&#128200; Item Rate Master</h1><p>Min / Max / Average purchase rates per item &middot; sourced from GRN Master</p></div>
    <button class="btn btn-secondary btn-sm" onclick="_irmReload(this)">&#8635; Refresh</button>
  </div></div>
  <div id="irm-body"><div class="card card-pad" style="text-align:center;color:var(--txt3);padding:2.5rem">&#9203; Loading data&hellip;</div></div>`;
  try {
    await _irmEnsure();
    _irmAllRows = _irmBuildRows();
    _irmGrouped = null;
    _irmFY      = _irmDefaultFY();
    _irmSearch  = '';
    _irmType    = 1;
    if (!_irmAllRows.length && _irmGRNRows && _irmGRNRows.length) {
      const gCols = _irmGRNRows[0] ? Object.keys(_irmGRNRows[0]) : [];
      const IC2 = _opColMap(_openPOItems || []);
      const pCols = (_openPOItems && _openPOItems[0]) ? Object.keys(_openPOItems[0]) : [];
      const b = document.getElementById('irm-body');
      if (b) b.innerHTML = `<div class="card card-pad" style="color:var(--danger);padding:1.5rem">
        <b>&#9888; 0 rows parsed. GRN rows: ${_irmGRNRows.length}, PO Items: ${(_openPOItems||[]).length}.</b>
        <div style="font-size:.78rem;margin-top:.5rem;color:var(--txt2)">GRN columns: <code style="font-size:.74rem">${_mdpEsc(gCols.join(' · '))}</code></div>
        <div style="font-size:.78rem;margin-top:.35rem;color:var(--txt2)">PO Items columns: <code style="font-size:.74rem">${_mdpEsc(pCols.join(' · '))}</code></div>
        <div style="font-size:.74rem;color:var(--txt3);margin-top:.35rem">Check browser console. GRN needs a UUID column; PO Items needs Part Details (Key) / Part Details / CheckSum.</div>
      </div>`;
      return;
    }
    _irmRender();
  } catch (err) {
    const b = document.getElementById('irm-body');
    if (b) b.innerHTML = `<div class="card card-pad" style="color:var(--danger);text-align:center;padding:2.5rem">&#9888; Could not load data: ${_mdpEsc(String(err && err.message || err))}</div>`;
  }
}

function _irmDefaultFY() {
  const fySet = Array.from(new Set(_irmAllRows.map(r => _vplpFYof(r.poDate)).filter(Boolean))).sort();
  const cur = _vplpFYof(new Date().toISOString());
  return fySet.includes(cur) ? cur : (fySet[fySet.length - 1] || '');
}

function _irmBuildRows() {
  const raw = _irmGRNRows || [];
  if (!raw.length) return [];

  // Step 1: collect UUID set from GRN Master (parts that have been actually received)
  const grnUUIDs = new Set();
  raw.forEach(r => {
    const uuid = String(r['UUID'] || r['Row UUID'] || r['GRN UUID'] || r['Id'] || r['ID'] || '').trim();
    if (uuid) grnUUIDs.add(uuid);
  });
  try { console.log('[IRM] GRN UUID count:', grnUUIDs.size, '| sample:', [...grnUUIDs].slice(0,3)); } catch (e) {}
  if (!grnUUIDs.size) return [];

  // Step 2: PO_Actual header lookup: PO No → { vendor, site, poDate }
  const HC = _opColMap(_openPOHeaders || []);
  const poHdrMap = {};
  (_openPOHeaders || []).forEach(h => {
    const poNo = String(_opGet(h, HC, ['PO No', 'Order No', 'PO No.']) || '').trim();
    if (!poNo) return;
    poHdrMap[poNo] = {
      vendor: String(_opGet(h, HC, ['Vendor Name', 'Vendor', 'Supplier Name', 'Supplier']) || '').trim(),
      site:   String(_opGet(h, HC, ['Site Name', 'Site', 'Project Site', 'Project', 'Location']) || '').trim(),
      poDate: String(_opGet(h, HC, ['PO Date', 'Date', 'Order Date']) || '').trim(),
    };
  });

  // Step 3: filter PO_Items where Part Details (Key) ∈ grnUUIDs; each matched row = one purchase entry
  const IC = _opColMap(_openPOItems || []);
  const rows = [];
  (_openPOItems || []).forEach(x => {
    const uuid = String(_opGet(x, IC, ['Part Details (Key)', 'Part Details', 'CheckSum', 'Check Sum']) || '').trim();
    if (!uuid || !grnUUIDs.has(uuid)) return;

    const part = String(_opGet(x, IC, ['Material Description', 'Material Desc', 'Material Name', 'Part Description', 'Part Name', 'Item Description', 'Item Name', 'Description', 'Particulars', 'Material']) || '').trim();
    if (!part) return;
    const uom  = String(_opGet(x, IC, ['UOM', 'Unit', 'Unit of Measure', 'Units']) || '').trim();
    const rate = _opNum(_opGet(x, IC, ['Rate', 'Unit Rate', 'Unit Price', 'Price', 'Basic Rate', 'Quoted Rate']));
    if (!rate) return;
    const qty  = _opNum(_opGet(x, IC, ['PO Qty', 'Qty', 'Quantity', 'Order Qty', 'Ordered Qty']));
    if (!qty) return;
    const poNo = String(_opGet(x, IC, ['PO No', 'Order No', 'PO No.']) || '').trim();

    // Site: PO_Items first, then PO header
    const itemSite = String(_opGet(x, IC, ['Site Name', 'Site', 'Project Site', 'Project', 'Location']) || '').trim();
    const hdr    = (poNo && poHdrMap[poNo]) || {};
    const site   = itemSite || hdr.site   || '';
    const vendor = hdr.vendor || '';
    const poDate = hdr.poDate  || '';

    rows.push({ uuid, part, uom, rate, qty, site, vendor, poNo, poDate, receivedOn: poDate, grnNo: '', invNo: '', amount: rate * qty });
  });
  try { console.log('[IRM] PO_Items rows after GRN filter:', rows.length); } catch (e) {}
  return rows;
}

function _irmFilteredRows() {
  if (!_irmFY) return _irmAllRows;
  return _irmAllRows.filter(r => _vplpFYof(r.poDate) === _irmFY);
}

function _irmGroupRows(rows, type) {
  const groups = {};
  rows.forEach(r => {
    // Group key: UUID + UOM + Site (T1) or UUID + UOM (T2) — all from PO_Items
    const key = r.uuid + '|' + _opNorm(r.uom) + (type === 1 ? '|' + _opNorm(r.site) : '');
    if (!groups[key]) groups[key] = { key, uuid: r.uuid, part: r.part, uom: r.uom, site: type === 1 ? r.site : '', items: [] };
    groups[key].items.push(r);
  });
  return Object.values(groups).map(g => {
    const rts  = g.items.map(r => r.rate).filter(v => v > 0).sort((a, b) => a - b);
    const min  = rts[0] || 0;
    const max  = rts[rts.length - 1] || 0;
    const avg  = rts.length ? rts.reduce((s, v) => s + v, 0) / rts.length : 0;
    const last = g.items.slice().sort((a, b) => (_mdpDateVal(b.poDate) || 0) - (_mdpDateVal(a.poDate) || 0))[0] || {};
    return { ...g, min, max, avg, count: g.items.length, lastRate: last.rate || 0, lastDate: last.poDate || '', lastVendor: last.vendor || '' };
  }).sort((a, b) => a.part.localeCompare(b.part));
}

function _irmRender() {
  const body = document.getElementById('irm-body'); if (!body) return;
  const esc = _mdpEsc;
  const rows   = _irmFilteredRows();
  const groups = _irmGroupRows(rows, _irmType);
  _irmGrouped  = groups;

  const allFYs = Array.from(new Set(_irmAllRows.map(r => _vplpFYof(r.poDate)).filter(Boolean))).sort().reverse();
  const fyOpts = `<option value="">All financial years</option>` +
    allFYs.map(fy => `<option value="${esc(fy)}"${fy === _irmFY ? ' selected' : ''}>${_vplpFYLabel(fy)}</option>`).join('');

  const totalParts   = groups.length;
  const totalPOs     = new Set(rows.map(r => r.poNo).filter(Boolean)).size;
  const totalVendors = new Set(rows.map(r => _opNorm(r.vendor)).filter(Boolean)).size;
  const canExport    = typeof userCan !== 'function' || userCan('item-rate-master', 'export');

  body.innerHTML = `
    <div class="evg-kpi-grid" style="margin-bottom:1rem">
      ${evgKpiCard({ icon:'&#127381;', value: totalParts.toLocaleString('en-IN'),  label: 'Parts Tracked' + (_irmFY ? ' · ' + _vplpFYLabel(_irmFY) : '') })}
      ${evgKpiCard({ icon:'&#128203;', value: totalPOs.toLocaleString('en-IN'),    label: 'POs Included' })}
      ${evgKpiCard({ icon:'&#127981;', value: totalVendors.toLocaleString('en-IN'),label: 'Vendors' })}
    </div>
    <div class="card card-pad" style="margin-bottom:1rem;display:flex;gap:.6rem;align-items:center;flex-wrap:wrap">
      <input id="irmSearch" type="text" value="${esc(_irmSearch)}" oninput="_irmSetSearch(this.value)" placeholder="Search part / vendor&hellip;"
        style="flex:1;min-width:200px;font-size:.84rem;border:1px solid var(--border);border-radius:6px;padding:6px 10px;background:var(--surface2)">
      <select onchange="_irmSetFY(this.value)" style="font-size:.82rem;border:1px solid var(--border);border-radius:6px;padding:6px 9px;background:var(--surface2)">${fyOpts}</select>
      <div style="display:flex;gap:.35rem">
        <button onclick="_irmSetType(1)" class="btn btn-sm ${_irmType===1?'btn-primary':'btn-secondary'}" title="Group by Item + UOM + Site">T1 &middot; Site</button>
        <button onclick="_irmSetType(2)" class="btn btn-sm ${_irmType===2?'btn-primary':'btn-secondary'}" title="Group by Item + UOM">T2 &middot; Overall</button>
      </div>
      <div style="display:flex;gap:.25rem">
        <button onclick="_irmExpandAll()" class="btn btn-sm btn-secondary" title="Expand all rows">&#9660; All</button>
        <button onclick="_irmCollapseAll()" class="btn btn-sm btn-secondary" title="Collapse all rows">&#9650; All</button>
      </div>
      ${canExport ? `<button onclick="_irmExport()" class="btn btn-sm btn-secondary" title="Download CSV">&#11015; CSV</button>` : ''}
      <span id="irmCount" style="font-size:.72rem;color:var(--txt3)"></span>
    </div>
    <div class="card"><table class="data-table" id="irmTable">
      <thead><tr>
        <th style="width:28px"></th>
        <th>Part Description</th>
        <th>UOM</th>
        ${_irmType === 1 ? '<th>Site</th>' : ''}
        <th style="text-align:right">Count</th>
        <th style="text-align:right">Min Rate</th>
        <th style="text-align:right">Avg Rate</th>
        <th style="text-align:right">Max Rate</th>
        <th style="text-align:right">Last Rate</th>
        <th>Latest PO</th>
        <th>Last Vendor</th>
      </tr></thead>
      <tbody id="irmTbody"></tbody>
    </table></div>`;

  _irmFill(groups);
  try { applyTableFeatures(); } catch (e) {}
}

function _irmFill(groups) {
  const tb = document.getElementById('irmTbody'); if (!tb) return;
  const esc = _mdpEsc, inr = _regINR;
  const q   = _irmSearch.trim().toLowerCase();
  const vis = q ? groups.filter(g => (g.part + ' ' + g.uom + ' ' + g.site + ' ' + g.lastVendor).toLowerCase().includes(q)) : groups;
  const cnt = document.getElementById('irmCount'); if (cnt) cnt.textContent = vis.length + ' item(s)';
  const cols = _irmType === 1 ? 11 : 10;
  if (!vis.length) {
    tb.innerHTML = `<tr><td colspan="${cols}" style="text-align:center;color:var(--txt3);padding:1.5rem">No items match.</td></tr>`;
    return;
  }
  tb.innerHTML = vis.map(g => {
    const spread     = g.max && g.min ? ((g.max - g.min) / g.min * 100).toFixed(1) : 0;
    const spreadClr  = +spread > 20 ? '#c62828' : +spread > 10 ? '#e65100' : 'var(--g9)';
    const rowBg      = +spread > 20 ? ';background:#fff8f0' : '';
    const keyAttr    = esc(g.key);
    const exp        = _irmExpanded.has(g.key);
    const hide       = exp ? '' : 'display:none;';

    // Pre-compute insights for child rows
    const cheapest = g.items.reduce((a, b) => (!a || b.rate < a.rate) ? b : a, null);
    const dearest  = g.items.reduce((a, b) => (!a || b.rate > a.rate) ? b : a, null);
    const vCnt = {};
    g.items.forEach(r => { const k = _opNorm(r.vendor); if (!k) return; if (!vCnt[k]) vCnt[k] = { name: r.vendor, n: 0 }; vCnt[k].n++; });
    const mostFreq  = Object.values(vCnt).sort((a, b) => b.n - a.n)[0];
    const totalQty  = g.items.reduce((s, r) => s + (r.qty  || 0), 0);
    const totalVal  = g.items.reduce((s, r) => s + (r.amount || 0), 0);
    const poLines   = g.items.slice().sort((a, b) => (_mdpDateVal(b.poDate) || 0) - (_mdpDateVal(a.poDate) || 0));
    const showSite  = _irmType === 2;

    const childStyle = `${hide}background:var(--surface2,#f9fafb);`;
    const hdrStyle   = `${hide}background:var(--surface3,#f0f0f0);`;

    const insightHdr = `<tr style="${hdrStyle}" data-irm-child="${keyAttr}">
      <td colspan="${cols}" style="padding:3px 0 2px 2.8rem;font-size:.6rem;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.07em;border-bottom:none">Rate Insights</td>
    </tr>`;

    const insightRow = `<tr style="${childStyle}" data-irm-child="${keyAttr}">
      <td colspan="${cols}" style="padding:.3rem .8rem .3rem 2.8rem">
        <div style="display:flex;gap:1.6rem;flex-wrap:wrap;font-size:.78rem;align-items:baseline">
          <span><b style="color:#16a34a">Min</b> ${inr(g.min)}${cheapest && cheapest.vendor ? ` <span style="color:var(--txt3);font-size:.72rem">· ${esc(cheapest.vendor)}</span>` : ''}</span>
          <span><b style="color:#1565c0">Avg</b> ${inr(Math.round(g.avg * 100) / 100)}</span>
          <span><b style="color:#c62828">Max</b> ${inr(g.max)}${dearest && dearest.vendor ? ` <span style="color:var(--txt3);font-size:.72rem">· ${esc(dearest.vendor)}</span>` : ''}</span>
          <span><b style="color:${spreadClr}">Spread</b> ${spread}%</span>
          <span><b>Total Qty</b> ${totalQty.toLocaleString('en-IN')} ${esc(g.uom||'')}</span>
          <span><b>Total Value</b> ${inr(Math.round(totalVal))}</span>
        </div>
        <div style="display:flex;gap:1.6rem;flex-wrap:wrap;font-size:.76rem;margin-top:.25rem;color:var(--txt2)">
          ${cheapest ? `<span>&#128994; Cheapest: <b>${esc(cheapest.vendor)||'—'}</b> ${inr(cheapest.rate)}${cheapest.poDate ? ' · ' + _mdpFmtDate(cheapest.poDate) : ''}</span>` : ''}
          ${dearest  ? `<span>&#128308; Dearest: <b>${esc(dearest.vendor)||'—'}</b> ${inr(dearest.rate)}${dearest.poDate ? ' · ' + _mdpFmtDate(dearest.poDate) : ''}</span>` : ''}
          ${mostFreq ? `<span>&#11088; Most Frequent: <b>${esc(mostFreq.name)}</b> (${mostFreq.n} PO${mostFreq.n>1?'s':''})</span>` : ''}
        </div>
      </td>
    </tr>`;

    const poHdr = `<tr style="${hdrStyle}" data-irm-child="${keyAttr}">
      <td colspan="${cols}" style="padding:3px 0 2px 2.8rem;font-size:.6rem;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.07em;border-bottom:none">Purchase Lines (${poLines.length})</td>
    </tr>`;

    const poRows = poLines.map(r => `<tr style="${childStyle}" data-irm-child="${keyAttr}">
      <td colspan="${cols}" style="padding:.25rem .8rem .25rem 2.8rem">
        <div style="display:flex;gap:1.4rem;font-size:.76rem;flex-wrap:wrap;align-items:center">
          <span style="color:var(--txt3);white-space:nowrap;min-width:75px">${_mdpFmtDate(r.poDate) || '—'}</span>
          <span style="font-family:monospace;font-size:.72rem;color:var(--txt2)">${esc(r.poNo) || '—'}</span>
          <span style="font-weight:500;min-width:120px">${esc(r.vendor) || '—'}</span>
          ${showSite ? `<span style="color:var(--txt3)">${esc(r.site) || '—'}</span>` : ''}
          <span style="color:var(--txt3)">${esc(r.uom) || ''}</span>
          <span style="font-weight:700">${inr(r.rate)}</span>
          <span style="color:var(--txt3)">Qty ${(r.qty||0).toLocaleString('en-IN')}</span>
          <span style="color:var(--txt2)">${inr(Math.round(r.amount||0))}</span>
        </div>
      </td>
    </tr>`).join('');

    return `<tr style="cursor:pointer${rowBg}" data-irm-key="${keyAttr}" onclick="_irmToggle(event,'${keyAttr}')">
      <td style="padding:0 4px;text-align:center"><span style="font-size:.65rem;color:var(--txt3)">${exp ? '▼' : '▶'}</span></td>
      <td style="font-weight:500">${esc(g.part)}</td>
      <td style="font-size:.78rem;color:var(--txt3)">${esc(g.uom) || '—'}</td>
      ${_irmType === 1 ? `<td style="font-size:.78rem">${esc(g.site) || '—'}</td>` : ''}
      <td style="text-align:right;font-size:.78rem">${g.count}</td>
      <td style="text-align:right;color:#16a34a;font-weight:600">${inr(g.min)}</td>
      <td style="text-align:right;font-weight:600">${inr(Math.round(g.avg * 100) / 100)}</td>
      <td style="text-align:right;color:#c62828;font-weight:600">${inr(g.max)}</td>
      <td style="text-align:right;color:var(--txt2)">${inr(g.lastRate)}</td>
      <td style="font-size:.78rem;white-space:nowrap">${_mdpFmtDate(g.lastDate) || '—'}</td>
      <td style="font-size:.78rem">${esc(g.lastVendor) || '—'}</td>
    </tr>${insightHdr}${insightRow}${poHdr}${poRows}`;
  }).join('');
  const tbl = tb.closest('table'); if (tbl) try { updateTableBadge(tbl); } catch (e) {}
}

window._irmReload    = function(btn) { if (btn) { btn.disabled = true; btn.textContent = '⏳'; } _irmEnsure(true).then(() => { _irmAllRows = _irmBuildRows(); _irmGrouped = null; _irmRender(); }).catch(() => { if (btn) { btn.disabled = false; btn.innerHTML = '&#8635; Refresh'; } }); };
window._irmSetFY     = function(v) { _irmFY = v; _irmGrouped = null; _irmRender(); };
window._irmSetType   = function(v) { _irmType = +v; _irmGrouped = null; _irmExpanded.clear(); _irmRender(); };
window._irmSetSearch = function(v) { _irmSearch = v; _irmFill(_irmGrouped || []); };

window._irmToggle = function(e, key) {
  if (e) e.stopPropagation();
  const tb = document.getElementById('irmTbody'); if (!tb) return;
  const exp = _irmExpanded.has(key);
  if (exp) _irmExpanded.delete(key); else _irmExpanded.add(key);
  tb.querySelectorAll(`[data-irm-child="${key}"]`).forEach(r => { r.style.display = exp ? 'none' : ''; });
  const pRow = tb.querySelector(`[data-irm-key="${key}"]`);
  if (pRow) { const icon = pRow.querySelector('span'); if (icon) icon.textContent = exp ? '▶' : '▼'; }
};

window._irmExpandAll = function() {
  const tb = document.getElementById('irmTbody'); if (!tb) return;
  tb.querySelectorAll('[data-irm-child]').forEach(r => { r.style.display = ''; });
  tb.querySelectorAll('[data-irm-key]').forEach(r => {
    const key = r.dataset.irmKey; if (key) _irmExpanded.add(key);
    const icon = r.querySelector('span'); if (icon) icon.textContent = '▼';
  });
};

window._irmCollapseAll = function() {
  const tb = document.getElementById('irmTbody'); if (!tb) return;
  tb.querySelectorAll('[data-irm-child]').forEach(r => { r.style.display = 'none'; });
  tb.querySelectorAll('[data-irm-key]').forEach(r => {
    const key = r.dataset.irmKey; if (key) _irmExpanded.delete(key);
    const icon = r.querySelector('span'); if (icon) icon.textContent = '▶';
  });
};


window._irmExport = function() {
  if (typeof userCan === 'function' && !userCan('item-rate-master', 'export')) {
    alert('You do not have permission to export.'); return;
  }
  const groups = _irmGrouped; if (!groups) return;
  const q   = _irmSearch.trim().toLowerCase();
  const vis = q ? groups.filter(g => (g.part + ' ' + g.uom + ' ' + g.site + ' ' + g.lastVendor).toLowerCase().includes(q)) : groups;
  const fy  = _irmFY ? _vplpFYLabel(_irmFY).replace(/\s/g, '_') : 'all';
  const csvRows = [];
  vis.forEach(g => {
    const base = { 'Part Description': g.part, 'UOM': g.uom };
    if (_irmType === 1) base['Site'] = g.site;
    // Summary row
    csvRows.push({ ...base, 'Row Type': 'Summary', 'PO Date': '', 'PO No': '', 'Vendor': g.lastVendor,
      'Count': g.count, 'Min Rate': g.min, 'Avg Rate': Math.round(g.avg * 100) / 100,
      'Max Rate': g.max, 'Last Rate': g.lastRate, 'Latest PO': g.lastDate, 'PO Qty': '', 'Value': '' });
    // One row per PO line with repeated Part details
    g.items.slice().sort((a, b) => (_mdpDateVal(b.poDate)||0) - (_mdpDateVal(a.poDate)||0)).forEach(r => {
      csvRows.push({ ...base, 'Row Type': 'PO Line', 'PO Date': r.poDate, 'PO No': r.poNo, 'Vendor': r.vendor,
        'Count': '', 'Min Rate': '', 'Avg Rate': '', 'Max Rate': '', 'Last Rate': r.rate, 'Latest PO': r.poDate,
        'PO Qty': r.qty, 'Value': Math.round(r.amount || 0) });
    });
  });
  downloadCSV(csvRows, `ItemRateMaster_T${_irmType}_${fy}_${new Date().toISOString().slice(0, 10)}.csv`);
};

// ════════════════════════════════════════════════════════════════
//  PENDING STOCK IN (Stock Transfer) — route 'pending-stockin'
//  Lists Stock Transfer items that have NOT yet been stocked-in.
//  Source tabs (all in STORES_SHEET_ID):
//    StockTransfer  — items dispatched on a DC (delivery challan)
//    ST_StockIN     — stock-in receipts against transfers
//    StockIN        — main goods-receipt register
//  A transfer is "stocked in" if its DC No appears in EITHER ST_StockIN or
//  StockIN. Matching is on a normalised DC No. Export gated by Access Settings.
// ════════════════════════════════════════════════════════════════
let _psiStatus  = 'pending';   // 'pending' | 'done' | 'all'
let _psiSearch  = '';
let _psiRows    = null;        // built rows
let _psiLoaded  = false;

async function _psiEnsure(force) {
  if (_psiLoaded && !force) return;
  const grab = async (tab, sid) => {
    try {
      let r = await fetchSheetSafe(tab, sid, { rawId: true });
      if (!r || !r.length) { await new Promise(z => setTimeout(z, 500)); r = await fetchSheetSafe(tab, sid, { rawId: true }); }
      return r || [];
    } catch (e) { return []; }
  };
  const [st, stSi, si, grn] = await Promise.all([
    grab('StockTransfer', STORES_SHEET_ID),
    grab('ST_StockIN',    STORES_SHEET_ID),
    grab('StockIN',       STORES_SHEET_ID),
    grab('4-GRNMaster_Actual', SHEET_ID),
  ]);
  _psiBuildPartMap(grn);
  _psiBuild(st, stSi, si);
  _psiLoaded = true;
}

// Resolve readable Part No / Part Description from the Master GRN tab
// (4-GRNMaster_Actual), keyed by UUID. A StockTransfer / receipt "Part Details"
// value IS that UUID, so we look it up to always show readable part details.
let _psiPartMap = {};
function _psiBuildPartMap(grnRows) {
  const map = {};
  const CM = _opColMap(grnRows || []);
  (grnRows || []).forEach(r => {
    const uuid = _psiKey(_opGet(r, CM, ['UUID', 'Row UUID', 'GRN UUID', 'Id', 'ID']));
    if (!uuid || map[uuid]) return;
    map[uuid] = {
      partNo:   String(_opGet(r, CM, ['GRN CODE', 'GRN Code', 'Part No', 'Part No.', 'Part Number', 'Part Code', 'Material Code', 'Item Code']) || '').trim(),
      partDesc: String(_opGet(r, CM, ['Description', 'Part Description', 'Material Description', 'Material Desc', 'Material Name', 'Part Name', 'Item Description', 'Item Name', 'Particulars']) || '').trim(),
    };
  });
  _psiPartMap = map;
}

// Normalise an identifier for matching (strip spaces / punctuation, lowercase).
const _psiKey = s => String(s == null ? '' : s).toLowerCase().replace(/[^a-z0-9]+/g, '').trim();

// Column-name candidates (flexible — live headers may vary).
const _PSI_DC_COLS   = ['DC No', 'DC No.', 'DC Number', 'DCNo', 'Delivery Challan No', 'Delivery Challan', 'Challan No', 'DC'];
const _PSI_PO_COLS   = ['PO No', 'PO No.', 'PO Number', 'Order No', 'Purchase Order No'];
const _PSI_INV_COLS  = ['Invoice No / ST No', 'Invoice No/ST No', 'Invoice No / ST', 'Invoice No', 'ST No', 'ST No.', 'Invoice Number', 'Invoice'];
const _PSI_PART_COLS = ['Part Details', 'Part Details (Key)', 'Material Description', 'Material Desc', 'Material Name', 'Part Description', 'Part Name', 'Item Name', 'Item Description', 'Description', 'Particulars', 'Material'];

function _psiBuild(stRows, stSiRows, siRows) {
  // A StockTransfer line is "stocked in" when, in ST_StockIN or StockIN, a row
  // exists where Part Details matches AND the transfer's DC No equals that row's
  // PO No OR Invoice No / ST No. We index the receipt tabs by composite keys
  // "part|id" (id = PO No or Invoice No / ST No). Both fields are required —
  // no fallback: a row with no Part Details or no DC No is treated as Pending.
  const stockedComposite = new Set();   // part|id
  [stSiRows, siRows].forEach(rows => {
    const CM = _opColMap(rows || []);
    (rows || []).forEach(r => {
      const part = _psiKey(_opGet(r, CM, _PSI_PART_COLS));
      if (!part) return;
      const po  = _psiKey(_opGet(r, CM, _PSI_PO_COLS));
      const inv = _psiKey(_opGet(r, CM, _PSI_INV_COLS));
      if (po)  stockedComposite.add(part + '|' + po);
      if (inv) stockedComposite.add(part + '|' + inv);
    });
  });

  const STC = _opColMap(stRows || []);
  const out = [];
  (stRows || []).forEach(r => {
    const dcRaw   = _opGet(r, STC, _PSI_DC_COLS);
    const partRaw = _opGet(r, STC, _PSI_PART_COLS);
    if (!dcRaw && !partRaw) return;   // skip blank rows
    const dc   = _psiKey(dcRaw);
    const part = _psiKey(partRaw);
    // Stocked in only when DC No + Part Details matches part|(PO No | Invoice/ST No).
    const stockedIn = (dc && part) ? stockedComposite.has(part + '|' + dc) : false;
    // Resolve readable Part No / Description from GRN master (Part Details = UUID).
    const pm = _psiPartMap[part] || {};
    out.push({
      dc: String(dcRaw || '').trim(),
      date:     _opGet(r, STC, ['DC Date', 'Transfer Date', 'Date', 'ST Date', 'Dispatch Date']),
      part:     String(partRaw || '').trim(),
      partNo:   pm.partNo   || '',
      partDesc: pm.partDesc || '',
      uom:      _opGet(r, STC, ['UOM', 'Unit', 'Unit of Measure', 'Units']),
      qty:      _opGet(r, STC, ['Transfer Qty', 'Qty', 'Quantity', 'ST Qty', 'Dispatch Qty', 'DC Qty']),
      fromSite: _opGet(r, STC, ['From Site', 'Source Site', 'Site From', 'From', 'Transfer From', 'From Location']),
      toSite:   _opGet(r, STC, ['To Site', 'Destination Site', 'Site To', 'To', 'Transfer To', 'To Location']),
      vehicle:  _opGet(r, STC, ['Vehicle No', 'Vehicle', 'Truck No', 'Lorry No']),
      stockedIn,
    });
  });
  // Pending first, then by date desc
  out.sort((a, b) => (a.stockedIn === b.stockedIn) ? ((_mdpDateVal(b.date) || 0) - (_mdpDateVal(a.date) || 0)) : (a.stockedIn ? 1 : -1));
  _psiRows = out;
}

function renderPendingStockIN() {
  const el = document.getElementById('mainContent'); if (!el) return;
  el.innerHTML = `<div class="page-header"><div class="page-header-row">
    <div><h1>&#128229; Open StockTransfer Report</h1><p>Stock Transfer items not yet stocked-in &middot; matched on PO No / Invoice No-ST No / Part Details across ST_StockIN &amp; StockIN</p></div>
    <button class="btn btn-secondary btn-sm" onclick="_psiReload(this)">&#8635; Refresh</button>
  </div></div>
  <div id="psi-body"><div class="card card-pad" style="text-align:center;color:var(--txt3);padding:2.5rem">&#9203; Loading stock transfer data&hellip;</div></div>`;
  _psiStatus = 'pending'; _psiSearch = '';
  _psiEnsure().then(() => _psiRender()).catch(() => {
    const b = document.getElementById('psi-body');
    if (b) b.innerHTML = '<div class="card card-pad" style="color:var(--danger);text-align:center;padding:2.5rem">&#9888; Could not load stock transfer data.</div>';
  });
}

function _psiRender() {
  const body = document.getElementById('psi-body'); if (!body) return;
  const esc = _mdpEsc;
  const rows = _psiRows || [];
  const total   = rows.length;
  const done    = rows.filter(r => r.stockedIn).length;
  const pending = total - done;
  const canExport = typeof userCan !== 'function' || userCan('pending-stockin', 'export');

  body.innerHTML = `
    <div class="evg-kpi-grid" style="margin-bottom:1rem">
      ${evgKpiCard({ icon:'&#128666;', value: total.toLocaleString('en-IN'),   label: 'Total Transfers' })}
      ${evgKpiCard({ icon:'&#9203;',   value: pending.toLocaleString('en-IN'), label: 'Pending Stock IN' })}
      ${evgKpiCard({ icon:'&#9989;',   value: done.toLocaleString('en-IN'),    label: 'Stocked IN' })}
    </div>
    <div class="card card-pad" style="margin-bottom:1rem;display:flex;gap:.6rem;align-items:center;flex-wrap:wrap">
      <input id="psiSearch" type="text" value="${esc(_psiSearch)}" oninput="_psiSetSearch(this.value)" placeholder="Search DC / part / site / vehicle&hellip;"
        style="flex:1;min-width:220px;font-size:.84rem;border:1px solid var(--border);border-radius:6px;padding:6px 10px;background:var(--surface2)">
      <div style="display:flex;gap:.35rem">
        <button onclick="_psiSetStatus('pending')" class="btn btn-sm ${_psiStatus==='pending'?'btn-primary':'btn-secondary'}">Pending (${pending})</button>
        <button onclick="_psiSetStatus('done')"    class="btn btn-sm ${_psiStatus==='done'?'btn-primary':'btn-secondary'}">Stocked IN (${done})</button>
        <button onclick="_psiSetStatus('all')"     class="btn btn-sm ${_psiStatus==='all'?'btn-primary':'btn-secondary'}">All (${total})</button>
      </div>
      ${canExport ? `<button onclick="_psiExport()" class="btn btn-sm btn-secondary" title="Download CSV">&#11015; CSV</button>` : ''}
      <span id="psiCount" style="font-size:.72rem;color:var(--txt3)"></span>
    </div>
    <div class="card"><table class="data-table" id="psiTable">
      <thead><tr>
        <th>Status</th>
        <th>DC No</th>
        <th>DC Date</th>
        <th>Part No</th>
        <th>Part Description</th>
        <th>UOM</th>
        <th style="text-align:right">Transfer Qty</th>
        <th>From Site</th>
        <th>To Site</th>
        <th>Vehicle</th>
      </tr></thead>
      <tbody id="psiTbody"></tbody>
    </table></div>`;

  _psiFill();
  try { applyTableFeatures(); } catch (e) {}
}

function _psiVisible() {
  let rows = _psiRows || [];
  if (_psiStatus === 'pending') rows = rows.filter(r => !r.stockedIn);
  else if (_psiStatus === 'done') rows = rows.filter(r => r.stockedIn);
  const q = _psiSearch.trim().toLowerCase();
  if (q) rows = rows.filter(r => (r.dc + ' ' + r.partNo + ' ' + r.partDesc + ' ' + r.part + ' ' + r.fromSite + ' ' + r.toSite + ' ' + r.vehicle).toLowerCase().includes(q));
  return rows;
}

function _psiFill() {
  const tb = document.getElementById('psiTbody'); if (!tb) return;
  const esc = _mdpEsc;
  const rows = _psiVisible();
  const cnt = document.getElementById('psiCount'); if (cnt) cnt.textContent = rows.length + ' item(s)';
  if (!rows.length) { tb.innerHTML = `<tr><td colspan="10" style="text-align:center;color:var(--txt3);padding:1.5rem">No items match.</td></tr>`; return; }
  tb.innerHTML = rows.map(r => {
    const badge = r.stockedIn
      ? `<span style="font-size:.68rem;font-weight:700;color:#16a34a;background:#e8f5e9;padding:2px 8px;border-radius:10px">Stocked IN</span>`
      : `<span style="font-size:.68rem;font-weight:700;color:#e65100;background:#fff3e0;padding:2px 8px;border-radius:10px">Pending</span>`;
    // Part No / Description resolved from GRN master; fall back to the raw key.
    const partDesc = r.partDesc || (r.partNo ? '' : r.part);
    return `<tr${r.stockedIn ? '' : ' style="background:#fffaf3"'}>
      <td>${badge}</td>
      <td style="font-family:monospace;font-size:.76rem;font-weight:600">${esc(r.dc) || '—'}</td>
      <td style="font-size:.78rem;white-space:nowrap">${_mdpFmtDate(r.date) || '—'}</td>
      <td style="font-size:.78rem;font-family:monospace">${esc(r.partNo) || '—'}</td>
      <td style="font-weight:500">${esc(partDesc) || '—'}</td>
      <td style="font-size:.78rem;color:var(--txt3)">${esc(r.uom) || '—'}</td>
      <td style="text-align:right;font-size:.78rem">${esc(r.qty) || '—'}</td>
      <td style="font-size:.78rem">${esc(r.fromSite) || '—'}</td>
      <td style="font-size:.78rem">${esc(r.toSite) || '—'}</td>
      <td style="font-size:.78rem">${esc(r.vehicle) || '—'}</td>
    </tr>`;
  }).join('');
  const tbl = tb.closest('table'); if (tbl) try { updateTableBadge(tbl); } catch (e) {}
}

window._psiReload    = function(btn) { if (btn) { btn.disabled = true; btn.textContent = '⏳'; } _psiEnsure(true).then(() => _psiRender()).catch(() => { if (btn) { btn.disabled = false; btn.innerHTML = '&#8635; Refresh'; } }); };
window._psiSetStatus = function(v) { _psiStatus = v; _psiRender(); };
window._psiSetSearch = function(v) { _psiSearch = v; _psiFill(); };
window._psiExport = function() {
  if (typeof userCan === 'function' && !userCan('pending-stockin', 'export')) { alert('You do not have permission to export.'); return; }
  const rows = _psiVisible();
  const csvRows = rows.map(r => ({
    'Status': r.stockedIn ? 'Stocked IN' : 'Pending',
    'DC No': r.dc, 'DC Date': r.date,
    'Part No': r.partNo, 'Part Description': r.partDesc || (r.partNo ? '' : r.part),
    'Part Key': r.part, 'UOM': r.uom,
    'Transfer Qty': r.qty, 'From Site': r.fromSite, 'To Site': r.toSite, 'Vehicle': r.vehicle,
  }));
  downloadCSV(csvRows, `PendingStockIN_${_psiStatus}_${new Date().toISOString().slice(0, 10)}.csv`);
};

// ════════════════════════════════════════════════════════════════
//  PROCUREMENT LIST PAGES — Material Request List, StockTransfer &
//  StockOut registers, and the Pending Pages landing. The registers are
//  generic searchable/exportable tables over their source tab; every
//  returned column renders and EVG table features add ⚙ Columns /
//  resize / CSV / sort / search.
// ════════════════════════════════════════════════════════════════
function _procRegRender(bodyId, rows, cols, emptyMsg) {
  const body = document.getElementById(bodyId); if (!body) return;
  const esc = _mdpEsc;
  rows = rows || [];
  cols = (cols && cols.length) ? cols : (rows[0] ? Object.keys(rows[0]).filter(c => c && String(c).trim()) : []);
  if (!rows.length || !cols.length) { body.innerHTML = `<div class="card card-pad" style="text-align:center;color:var(--txt3);padding:2.5rem">${emptyMsg || 'No records.'}</div>`; return; }
  const head = cols.map(c => `<th>${esc(c)}</th>`).join('');
  const trs = rows.map(r => `<tr>${cols.map(c => `<td style="font-size:.78rem">${esc(r[c] != null ? r[c] : '') || '—'}</td>`).join('')}</tr>`).join('');
  body.innerHTML = `<div class="card"><table class="data-table"><thead><tr>${head}</tr></thead><tbody>${trs}</tbody></table></div>`;
  try { applyTableFeatures(); } catch (e) {}
}

