function getPayStatus(raw) {
  const key = (raw || '').toLowerCase().trim().replace(/\s+/g,' ');
  if (!key) return { cat:'other', icon:'', label:'—', color:'#9ca3af', bg:'transparent' };
  return ACCOUNTS_STATUS[key] || { cat:'other', icon:'&#9711;', label: raw, color:'#6b7280', bg:'#f9fafb' };
}

// Strip an EGxxx| code prefix: "EG1415|RABIN RAJESH" → "RABIN RAJESH".
function _accStripCode(s) { return s ? String(s).replace(/^[A-Z]+\d+\|/i, '').trim() : ''; }
// Normalise a currency label: "Indian Rupee" → "INR"; keep short codes as-is.
function _accNormCurrency(s) {
  const m = { 'indian rupee':'INR','us dollar':'USD','usd':'USD','euro':'EUR','gbp':'GBP','aed':'AED','omr':'OMR','qar':'QAR' };
  return m[(s||'').toLowerCase().trim()] || (s||'INR').toUpperCase().trim().slice(0,5) || 'INR';
}
// Map one PaymentRequest row → the Accounts row shape. Read strictly by
// header name so it is resilient to column-order changes.
function _accMapRow(r) {
  const raw    = r['Status'] || '';
  const acStat = r['Accounts Status'] || '';
  const st     = getPayStatus(raw || acStat);
  const curr   = _accNormCurrency(r['Currency'] || '');
  const amt    = parseFloat(String(r['Amount'] || '0').replace(/[^0-9.]/g,'')) || 0;
  const initiator = _accStripCode(r['Name of the Intiator'] || '');
  const company   = r['Company'] || '';
  return {
    uuid:        r['UUID'] || '',
    link:        r['Link'] || '',
    manualAuto:  r['Manual / Auto'] || '',
    installment: r['Installment'] || '',
    requestId:   r['Request ID'] || '',
    date:        r['Date Of Request'] || '',
    initiator,
    nature:      r['NATURE OF EXPENSES'] || '',
    accCode:     r['ACCOUNT CODE DESCRIPTIONS'] || '',
    payTo:       r['Payment To'] || '',
    costCode:    r['CostCode'] || '',
    dept:        r['Department'] || '',
    process:     r['From Which Process'] || '',
    paidTo:      r['Paid To'] || '',
    site:        r['Site Name'] || '',
    company,
    entity:      company,
    orderNo:     r['Order No'] || '',
    billNo:      r['Bill No'] || '',
    poValue:     parseFloat(String(r['PO Value']      || '0').replace(/[^0-9.]/g,'')) || 0,
    invoiceVal:  parseFloat(String(r['Invoice Value'] || '0').replace(/[^0-9.]/g,'')) || 0,
    paidVal:     parseFloat(String(r['Paid Value']    || '0').replace(/[^0-9.]/g,'')) || 0,
    pendingVal:  parseFloat(String(r['Pending Value'] || '0').replace(/[^0-9.]/g,'')) || 0,
    currency:    curr,
    amount:      amt,
    narrative:   r['Narrative/Comments'] || '',
    acHolder:    r['A/C HOLDER NAME'] || '',
    acNumber:    r['A/C NUMBER'] || '',
    ifsc:        r['IFSC CODE'] || '',
    bank:        r['BANK NAME'] || '',
    accStatus:   acStat,
    accDate:     r['Accounts Date'] || '',
    utr:         r['UTR Details'] || '',
    remarks:     r['Remarks'] || '',
    monthYear:   r['Month-Year'] || '',
    rawStatus:   raw || acStat,
    status:      st,
    _s: [r['UUID'],r['Request ID'],r['Date Of Request'],initiator,r['Payment To'],
         r['NATURE OF EXPENSES'],r['Department'],r['From Which Process'],r['Site Name'],
         company,r['Order No'],r['Bill No'],curr,String(amt),r['Narrative/Comments'],
         r['Accounts Date'],r['UTR Details'],r['Remarks'],raw,acStat
        ].join('|').toLowerCase(),
  };
}
// Re-fetch the PaymentRequest tab and rebuild window._accAllRows.
async function _accReloadRows() {
  // Kick off the status-options preload early (cached), so the Update form never
  // has to fetch it on demand — avoids the "Loading status options…" stall when a
  // sync POST is in flight.
  try { _accLoadPaymentStatusMaster(); } catch (e) {}

  const lk = (typeof getLink === 'function') ? getLink('PAYMENT') : { id: PAYMENT_SHEET_ID, tab: 'PaymentRequest' };
  const payTab = lk.tab || 'PaymentRequest', paySid = lk.id || PAYMENT_SHEET_ID;
  const map = raw => (raw || []).filter(r => (r['Payment To'] || '').trim()).map(_accMapRow);
  let rows = map(await fetchSheet(payTab, null, paySid));
  // gviz JSONP resolves to [] on timeout/parse-error. The PaymentRequest sheet has
  // thousands of rows, so an empty result is virtually always a transient failure
  // (often while a sync POST is occupying the connection). Retry once…
  if (!rows.length) {
    await new Promise(r => setTimeout(r, 900));
    rows = map(await fetchSheet(payTab, null, paySid));
  }
  // …and if it is STILL empty, keep whatever good data we already had rather than
  // wiping the whole module to "0 records".
  if (!rows.length && Array.isArray(window._accAllRows) && window._accAllRows.length) {
    return window._accAllRows;
  }
  window._accAllRows = rows;
  return window._accAllRows;
}

// ══════════════════════════════════════════════════════════════
//  ACCOUNTS PIPELINE — the 8 stage Views
//  Every row sits in exactly one stage, derived from its status label.
//  `next` describes the one-click "Approve → Next Stage" advance:
//    status   = the status value to post (must exist in the status master)
//    to       = the human name of the stage it moves to
//    roles    = which roles may advance from this stage (role-aware action)
//    needsUtr = prompt for a bank UTR before completing
// ══════════════════════════════════════════════════════════════
const ACC_HOLD_LABELS = ['On Hold by MD','Payment On Hold by MD','Sent Back to Accounts','Sent Back to Dept (MD)','Pending Due to Queries'];
// Quick-Action advance matrix (who can advance each stage). Admin (MD role +
// admin email) can advance from ANY stage — see _accCanAdvance.
//   Verified, Move to MD Queue   → Process Payment, Move to Accounts  [Admin/MD]
//   Process Payment→ Accounts    → Payment Initiated                  [Admin/MD/Accounts]
//   Payment Initiated            → Paid (MD_ED)                       [Admin/MD]
//   Paid (MD_ED)                 → Payment Completed                  [Admin/MD/Accounts]
//   Payment Completed            → (terminal)
const ACC_VIEWS = [
  { id:'verify',   label:'To be Verified',      icon:'&#128269;', color:'#d97706',
    next:{ status:'Verified, Move to MD Queue',        to:'MD Queue',          actionLabel:'Verified, Move to MD Queue', roles:['accounts','dept_head'] } },
  { id:'mdqueue',  label:'MD Queue',            icon:'&#9878;',   color:'#6366f1',
    next:{ status:'Process Payment, Move to Accounts', to:'Initiate Payment',  actionLabel:'Process Payment', roles:['md'] } },
  { id:'initiate', label:'To Initiate Payment', icon:'&#128640;', color:'#2563eb',
    next:{ status:'Payment Initiated',                 to:'Paid?',             actionLabel:'Initiated Payment in Bank', roles:['md','accounts','dept_head'] } },
  { id:'paid',     label:'Paid?',               icon:'&#128181;', color:'#0891b2',
    next:{ status:'Paid (MD_ED)',                      to:'Update UTR',        actionLabel:'Bank Transaction Completed', roles:['md'] } },
  { id:'utr',      label:'To Update UTR',       icon:'&#128290;', color:'#7c3aed',
    next:{ status:'Payment Completed',                 to:'Done', needsUtr:true, actionLabel:'Update UTR', roles:['md','accounts','dept_head'] } },
  { id:'rejected', label:'Rejection Bin',       icon:'&#10060;',  color:'#dc2626', next:null },
  { id:'hold',     label:'Hold Bin',            icon:'&#9208;',   color:'#b45309', next:null },
  { id:'all',      label:'Accounts Database',   icon:'&#128194;', color:'#475569', next:null },
];
function _accViewById(id) { return ACC_VIEWS.find(v => v.id === id) || ACC_VIEWS[ACC_VIEWS.length - 1]; }
// Numeric value of a "PR-2753" request id, for largest-to-smallest sorting.
function _accPrNum(r) { const m = String((r && r.requestId) || '').match(/(\d+)/); return m ? parseInt(m[1], 10) : 0; }

// Which stage a row belongs to (first match wins).
function _accStageOf(r) {
  const lbl = (r.status && r.status.label) || '';
  const cat = (r.status && r.status.cat) || 'other';
  if (cat === 'rejected') return 'rejected';
  if (ACC_HOLD_LABELS.includes(lbl)) return 'hold';
  if (lbl === 'Verified, Move to MD Queue') return 'mdqueue';
  if (lbl === 'Payment Approved by MD') return 'initiate';
  if (lbl === 'Payment Initiated' || lbl === 'Payment Re-Initiated') return 'paid';
  if (lbl === 'Paid (Initiated in Bank)' || lbl === 'Paid') return 'utr';
  if (lbl === 'Pending With Accounts' || cat === 'other' || !lbl || lbl === '—') return 'verify';
  return 'done'; // Paid+UTR / Completed — surfaces only in Accounts Database
}
function _accRowsInView(rows, id) {
  if (id === 'all') return rows || [];
  return (rows || []).filter(r => _accStageOf(r) === id);
}
// Role-aware: can the current user advance a row from this stage?
// Admin (MD role + admin email) can advance from ANY stage that has a next —
// the Quick Action button is therefore visible to Admin in all views.
function _accCanAdvance(viewDef) {
  if (!viewDef || !viewDef.next) return false;
  // Per-status people/role restriction wins for everyone (except super-admins,
  // handled inside _accCanSetStatus) — so the Quick Action button hides for
  // anyone not on the allow-list, including MD/admin.
  if (typeof _accCanSetStatus === 'function' && !_accCanSetStatus(viewDef.next.status)) return false;
  if (typeof _accIsAdmin === 'function' && _accIsAdmin()) return true;
  return (viewDef.next.roles || []).includes((STATE.role || '').toLowerCase());
}
// One-click advance to the next positive stage (role-aware).
async function _accAdvance(uuid) {
  const r = (window._accAllRows || []).find(x => x.uuid === uuid);
  if (!r) return;
  if (typeof _accCan === 'function' && !_accCan('advance')) { alert('You do not have permission to advance payments.'); return; }
  const view = _accViewById(_accStageOf(r));
  if (!_accCanAdvance(view)) { alert('Your role cannot advance this stage.'); return; }
  const nx = view.next;
  let utr = '';
  if (nx.needsUtr) {
    utr = prompt('Enter the bank UTR / transaction reference to complete this payment:', '');
    if (utr === null) return;
    if (!utr.trim()) { alert('A UTR is required to complete the payment.'); return; }
  }
  if (!confirm(`Move "${r.requestId || uuid}" to "${nx.to}"?`)) return;
  // Optimistic: park + close + re-render now, then post in the background.
  _txnParkRow(r, nx.status, '→ ' + nx.to, 'acc');
  if (document.getElementById('accVoucherOverlay')) _accClosePRDetail();
  if (typeof accRender === 'function' && document.getElementById('accTbody')) accRender();
  if (document.getElementById('mdp-content') && typeof _mdpRender === 'function') _mdpRender();
  _accToast('Moving to ' + nx.to + '…');
  const ok = await _accQuickStatus(uuid, nx.status, '', utr.trim(), true, uuid + '|' + nx.status);
  if (ok) {
    _accToast('✅ Moved to ' + nx.to);
  } else {
    _txnDrop(uuid);
    if (typeof accRender === 'function' && document.getElementById('accTbody')) accRender();
    if (document.getElementById('mdp-content') && typeof _mdpRender === 'function') _mdpRender();
    alert('Could not move "' + (r.requestId || uuid) + '" — it has been returned to its queue.' + (window._accLastQuickErr ? '\n\nError: ' + window._accLastQuickErr : ''));
  }
}


// ══════════════════════════════════════════════════════════════════════════
//  ACCOUNTS WORKSPACE (v2) — standalone page (route: accounts-v2)
//  Two tabs: Dashboard (insights) + Worklist (grouped table · ageing · totals
//  · actions). Reuses _accAllRows, the stage model, and the voucher. The
//  classic Accounts page is untouched, so the two can run side by side.
// ══════════════════════════════════════════════════════════════════════════
const ACCW = { tab:'dashboard', stage:'all', groupBy:'stage', search:'', site:'', entity:'', process:'', age:'', _view:'', sel:new Set(), collapsed:new Set() };
const _accwOpenStages = ['verify','mdqueue','initiate','paid','utr'];
function _accwSetStage(id) { ACCW.stage = id; ACCW.sel.clear(); _accwRenderBody(); }
// ── Saved views (filter presets), per-browser ──────────────────────────────
const ACCW_VIEWS_LS = 'evgcpl.acc.savedViews';
function _accwGetViews() { try { return JSON.parse(localStorage.getItem(ACCW_VIEWS_LS) || '{}') || {}; } catch (e) { return {}; } }
function _accwSaveViews(o) { try { localStorage.setItem(ACCW_VIEWS_LS, JSON.stringify(o)); } catch (e) {} }
function _accwSaveCurrentView() {
  const name = (prompt('Save current filters as a view — name:', ACCW._view || '') || '').trim();
  if (!name) return;
  const o = _accwGetViews();
  o[name] = { stage:ACCW.stage, groupBy:ACCW.groupBy, search:ACCW.search, site:ACCW.site, entity:ACCW.entity, process:ACCW.process, age:ACCW.age };
  _accwSaveViews(o); ACCW._view = name; _accwRenderBody();
}
function _accwApplyView(name) {
  if (!name) { ACCW._view = ''; return; }
  const v = _accwGetViews()[name]; if (!v) return;
  Object.assign(ACCW, { stage:v.stage||'all', groupBy:v.groupBy||'stage', search:v.search||'', site:v.site||'', entity:v.entity||'', process:v.process||'', age:v.age||'' });
  ACCW._view = name; ACCW.sel.clear(); _accwRenderBody();
}
function _accwDeleteView() {
  const name = ACCW._view; if (!name) { alert('Pick a saved view first.'); return; }
  if (!confirm('Delete saved view "' + name + '"?')) return;
  const o = _accwGetViews(); delete o[name]; _accwSaveViews(o); ACCW._view = ''; _accwRenderBody();
}
// Group-View chips (the classic 8 stage views) — clickable, count per stage.
function _accwStageChipsHtml() {
  const rows = _accwRows();
  const chip = (id, label, icon, color, n) => {
    const on = ACCW.stage === id;
    return `<button onclick="_accwSetStage('${id}')" title="${label}"
      style="display:inline-flex;align-items:center;gap:.4rem;cursor:pointer;border:1px solid ${on?color:'var(--border)'};
        border-radius:8px;padding:.3rem .55rem;font-size:.75rem;font-weight:600;white-space:nowrap;
        background:${on?color+'14':'var(--surface2)'};color:var(--txt1);${on?'box-shadow:inset 0 0 0 1px '+color+';':''}">
      <span style="font-size:.9rem;line-height:1">${icon}</span><span>${label}</span>
      <span style="background:${color}22;color:${color};font-weight:800;border-radius:20px;padding:0 .4rem;font-size:.7rem;min-width:1.1rem;text-align:center">${n}</span>
    </button>`;
  };
  const chips = ACC_VIEWS.map(v => {
    const n = (v.id === 'all') ? rows.length : rows.filter(r => _accStageOf(r) === v.id).length;
    return chip(v.id, v.label, v.icon, v.color, n);
  }).join('');
  return `<div style="display:flex;flex-wrap:wrap;gap:.4rem;margin-bottom:.7rem">${chips}</div>`;
}
function _accwRows()        { return (window._accAllRows||[]).filter(r=>!_txnHas(r.uuid)); }
function _accwIsOpen(r)     { return _accwOpenStages.includes(_accStageOf(r)); }
function _accwFmt(v)        { return '₹' + Math.round(v||0).toLocaleString('en-IN'); }
function _accwSum(rows)     { return rows.reduce((s,r)=>s+(r.amount||0),0); }
function _accwAge(r) {
  const d = r && r.date; if (!d) return null;
  const p = String(d).trim().split(/[-\/]/); let t;
  if (p.length === 3) t = (p[0].length === 4) ? new Date(+p[0],+p[1]-1,+p[2]) : new Date(+p[2],+p[1]-1,+p[0]);
  else t = new Date(d);
  if (!t || isNaN(t.getTime())) return null;
  return Math.max(0, Math.floor((Date.now() - t.getTime()) / 86400000));
}
function _accwAgeChip(n) {
  if (n == null) return '<span style="color:var(--txt3)">—</span>';
  const c = n<=7 ? ['#16a34a','#dcfce7'] : n<=15 ? ['#b45309','#fef3c7'] : n<=30 ? ['#ea580c','#ffedd5'] : ['#dc2626','#fee2e2'];
  return `<span style="background:${c[1]};color:${c[0]};font-weight:700;font-size:.7rem;padding:1px 7px;border-radius:8px;white-space:nowrap">${n}d</span>`;
}

function renderAccountsWorkspace(initialTab) {
  if (initialTab) ACCW.tab = initialTab;
  ACCW.sel.clear();
  const el = document.getElementById('mainContent');
  el.innerHTML = `
    <div class="page-header">
      <div class="page-header-row">
        <div>
          <h1>&#128188; Accounts Workspace <span style="font-size:.58rem;font-weight:800;background:#fef3c7;color:#b45309;padding:2px 8px;border-radius:20px;vertical-align:middle;letter-spacing:.05em">NEW</span></h1>
          <p>Dashboard insights &middot; grouped worklist &middot; actions — all in one place</p>
        </div>
        <div style="display:flex;gap:.5rem;flex-wrap:wrap;align-items:center">
          <button class="btn btn-secondary btn-sm" onclick="renderAccountsWorkspace()">&#8635; Refresh</button>
          <button class="btn btn-primary btn-sm" onclick="_accOpenNewPR()">&#10133; New Request</button>
        </div>
      </div>
      <div style="display:flex;gap:.4rem;margin-top:.7rem">
        <button id="accwTab-dashboard" onclick="_accwSetTab('dashboard')" class="btn btn-sm">&#128202; Dashboard</button>
        <button id="accwTab-worklist"  onclick="_accwSetTab('worklist')"  class="btn btn-sm">&#128203; Worklist</button>
      </div>
    </div>
    <div id="accwBody"><div style="text-align:center;padding:3rem;color:var(--txt3)">&#8987; Loading payment requests…</div></div>`;
  // Load the PaymentRequest rows + the Vendor Ledger (PO) data in parallel so the
  // worklist's Vendor Status column can render synchronously on first paint. The
  // ledger load is best-effort — the column degrades to "—" if it fails.
  const _vplpReady = (typeof _vplpEnsure === 'function') ? _vplpEnsure().catch(() => {}) : Promise.resolve();
  Promise.all([_accReloadRows(), _vplpReady]).then(() => _accwRenderBody())
    .catch(() => { const b=document.getElementById('accwBody'); if (b) b.innerHTML='<div style="padding:2.5rem;text-align:center;color:var(--danger)">&#9888; Could not load the PaymentRequest sheet.</div>'; });
}
function _accwSetTab(t) { ACCW.tab = t; _accwRenderBody(); }
function _accwSyncTabs() {
  ['dashboard','worklist'].forEach(t => {
    const b = document.getElementById('accwTab-' + t); if (!b) return;
    const on = ACCW.tab === t;
    b.className = 'btn btn-sm' + (on ? '' : ' btn-secondary');
    b.style.cssText = on ? 'background:var(--g8);color:#fff;border-color:var(--g8)' : '';
  });
}
function _accwRenderBody() {
  const body = document.getElementById('accwBody'); if (!body) return;
  _accwSyncTabs();
  body.innerHTML = (ACCW.tab === 'dashboard') ? _accwDashboardHtml() : _accwWorklistHtml();
}
function _accwOpenStage(stage) { ACCW.tab='worklist'; ACCW.stage=stage; ACCW.age=''; ACCW.sel.clear(); _accwRenderBody(); }
function _accwOpenAge(age)    { ACCW.tab='worklist'; ACCW.stage='open'; ACCW.age=age; ACCW.sel.clear(); _accwRenderBody(); }

// ── Dashboard ─────────────────────────────────────────────────────────────
function _accwDashboardHtml() {
  const esc = (typeof escapeHtml_==='function') ? escapeHtml_ : (s=>String(s||''));
  const rows = _accwRows();
  const open = rows.filter(_accwIsOpen);
  const done = rows.filter(r => _accStageOf(r)==='done');
  const rej  = rows.filter(r => _accStageOf(r)==='rejected');
  const hold = rows.filter(r => _accStageOf(r)==='hold');
  const nonInr = rows.filter(r => r.currency && r.currency!=='INR').length;

  const kpi = (icon,color,val,label,sub,click) => `
    <div class="kpi-card" ${click?`onclick="${click}" style="cursor:pointer"`:''}>
      <div class="kpi-top"><div class="kpi-icon" style="background:${color}22;color:${color}">${icon}</div></div>
      <div class="kpi-value" style="font-size:1.5rem">${val}</div>
      <div class="kpi-label">${label}</div>
      <div class="kpi-sub">${sub||''}</div>
    </div>`;

  const kpis = `
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:.7rem;margin-bottom:1.2rem">
      ${kpi('&#128194;','#475569', rows.length, 'Total Requests', _accwFmt(_accwSum(rows))+(nonInr?` &middot; +${nonInr} non-INR`:''))}
      ${kpi('&#128260;','#d97706', open.length, 'Open / In-flight', _accwFmt(_accwSum(open)), `_accwOpenStage('open')`)}
      ${kpi('&#9208;','#b45309', hold.length, 'On Hold', _accwFmt(_accwSum(hold)), `_accwOpenStage('hold')`)}
      ${kpi('&#10003;','#16a34a', done.length, 'Completed', _accwFmt(_accwSum(done)), `_accwOpenStage('done')`)}
      ${kpi('&#10060;','#dc2626', rej.length, 'Rejected', '', `_accwOpenStage('rejected')`)}
    </div>`;

  // Pipeline stage tiles (open + bins), clickable into the worklist
  const stageTiles = ACC_VIEWS.filter(v=>v.id!=='all').map(v => {
    const inV = rows.filter(r => _accStageOf(r)===v.id);
    return `<div onclick="_accwOpenStage('${v.id}')" class="kpi-card" style="cursor:pointer;border-left:4px solid ${v.color}">
      <div class="kpi-top"><div class="kpi-icon" style="background:${v.color}22;color:${v.color}">${v.icon}</div>${v.next?`<div class="kpi-trend flat" style="font-size:.56rem">&rarr; ${v.next.to}</div>`:''}</div>
      <div class="kpi-value" style="font-size:1.3rem">${inV.length}</div>
      <div class="kpi-label">${v.label}</div>
      <div class="kpi-sub">${inV.length?_accwFmt(_accwSum(inV)):'—'}</div>
    </div>`;
  }).join('');

  // Ageing buckets (open rows only)
  const buckets = [['0-7','0–7 days','#16a34a'],['8-15','8–15 days','#b45309'],['16-30','16–30 days','#ea580c'],['30+','30+ days','#dc2626']];
  const inBucket = (r,b) => { const a=_accwAge(r); if (a==null) return false; return b==='0-7'?a<=7:b==='8-15'?(a>=8&&a<=15):b==='16-30'?(a>=16&&a<=30):a>30; };
  const ageTiles = buckets.map(([k,lbl,c]) => {
    const inB = open.filter(r => inBucket(r,k));
    return `<div onclick="_accwOpenAge('${k}')" style="cursor:pointer;flex:1 1 160px;border:1px solid var(--border);border-top:3px solid ${c};border-radius:10px;padding:.7rem .9rem;background:var(--surface1)">
      <div style="font-size:.68rem;font-weight:700;color:${c};text-transform:uppercase;letter-spacing:.04em">${lbl}</div>
      <div style="font-size:1.35rem;font-weight:800;color:var(--txt1);margin-top:2px">${inB.length}</div>
      <div style="font-size:.74rem;color:var(--txt2)">${inB.length?_accwFmt(_accwSum(inB)):'—'}</div>
    </div>`;
  }).join('');

  // Top vendors / sites by OPEN amount
  const topBy = (keyFn) => {
    const m = new Map();
    open.forEach(r => { const k=keyFn(r)||'—'; const e=m.get(k)||{n:0,amt:0}; e.n++; e.amt+=r.amount||0; m.set(k,e); });
    return [...m.entries()].sort((a,b)=>b[1].amt-a[1].amt).slice(0,6);
  };
  const listCard = (title, entries) => `
    <div style="flex:1 1 320px;border:1px solid var(--border);border-radius:10px;background:var(--surface1);overflow:hidden">
      <div style="background:var(--g9);color:#fff;padding:.45rem .9rem;font-size:.7rem;font-weight:700;text-transform:uppercase;letter-spacing:.05em">${title}</div>
      ${entries.length ? entries.map(([k,e]) => `
        <div style="display:flex;align-items:center;justify-content:space-between;gap:.6rem;padding:.45rem .9rem;border-bottom:1px solid var(--border)">
          <span style="font-size:.8rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(k)} <span style="color:var(--txt3);font-size:.7rem">&times;${e.n}</span></span>
          <span style="font-size:.8rem;font-weight:700;color:var(--g8);white-space:nowrap">${_accwFmt(e.amt)}</span>
        </div>`).join('') : '<div style="padding:.8rem .9rem;color:var(--txt3);font-size:.8rem">No open items</div>'}
    </div>`;

  return `
    ${kpis}
    <div style="font-weight:700;font-size:.74rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin:.2rem 0 .55rem">Pipeline</div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:.7rem;margin-bottom:1.3rem">${stageTiles}</div>
    <div style="font-weight:700;font-size:.74rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin:.2rem 0 .55rem">Ageing of open requests</div>
    <div style="display:flex;flex-wrap:wrap;gap:.7rem;margin-bottom:1.3rem">${ageTiles}</div>
    <div style="font-weight:700;font-size:.74rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin:.2rem 0 .55rem">Where the open money sits</div>
    <div style="display:flex;flex-wrap:wrap;gap:1rem">${listCard('Top Payees · open amount', topBy(r=>_accStripCode(r.paidTo)||r.payTo))}${listCard('Top Sites · open amount', topBy(r=>r.site))}</div>`;
}

// ── Worklist (grouped table + actions) ──────────────────────────────────────
function _accwFiltered() {
  let rows = _accwRows();
  if (ACCW.stage === 'open') rows = rows.filter(_accwIsOpen);
  else if (ACCW.stage !== 'all') rows = rows.filter(r => _accStageOf(r) === ACCW.stage);
  if (ACCW.site)    rows = rows.filter(r => r.site === ACCW.site);
  if (ACCW.entity)  rows = rows.filter(r => r.entity === ACCW.entity);
  if (ACCW.process) rows = rows.filter(r => r.process === ACCW.process);
  if (ACCW.search) { const q = ACCW.search.toLowerCase(); rows = rows.filter(r => r._s.includes(q)); }
  if (ACCW.age) {
    rows = rows.filter(r => { const a=_accwAge(r); if (a==null) return false;
      return ACCW.age==='0-7'?a<=7:ACCW.age==='8-15'?(a>=8&&a<=15):ACCW.age==='16-30'?(a>=16&&a<=30):a>30; });
  }
  return rows.sort((a,b) => _accPrNum(b) - _accPrNum(a));
}
function _accwGroupKey(r) {
  switch (ACCW.groupBy) {
    case 'stage':   return _accViewById(_accStageOf(r)).label;
    case 'site':    return r.site || '—';
    case 'entity':  return r.entity || '—';
    case 'process': return r.process || '—';
    case 'vendor':  return _accStripCode(r.paidTo) || r.payTo || '—';
    case 'month':   return r.monthYear || '—';
    default:        return '';
  }
}
function _accwWorklistHtml() {
  const esc = (typeof escapeHtml_==='function') ? escapeHtml_ : (s=>String(s||''));
  const rows = _accwFiltered();
  const sites    = [...new Set(_accwRows().map(r=>r.site).filter(Boolean))].sort();
  const entities = [...new Set(_accwRows().map(r=>r.entity).filter(Boolean))].sort();
  const procs    = [...new Set(_accwRows().map(r=>r.process).filter(Boolean))].sort();
  const stageOpts = [['all','All stages'],['open','Open / In-flight'],...ACC_VIEWS.filter(v=>v.id!=='all').map(v=>[v.id,v.label]),['done','Completed']];
  const groupOpts = [['stage','Stage'],['site','Site'],['vendor','Payee'],['process','Process'],['entity','For (Company)'],['month','Month'],['none','No grouping']];
  const ageOpts = [['','Any age'],['0-7','0–7 days'],['8-15','8–15 days'],['16-30','16–30 days'],['30+','30+ days']];
  const opt = (arr,cur) => arr.map(([v,l])=>`<option value="${v}" ${v===cur?'selected':''}>${l}</option>`).join('');
  const selStyle = 'font-size:.78rem;border:1px solid var(--border);border-radius:6px;padding:5px 8px;background:var(--surface2)';

  const toolbar = `
    <div class="card" style="margin-bottom:.8rem"><div class="card-body" style="padding:.7rem 1rem">
      <div style="display:flex;gap:.7rem;flex-wrap:wrap;align-items:flex-end">
        <div style="display:flex;flex-direction:column;gap:3px;flex:1;min-width:200px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">Search</label>
          <input id="accwSearch" value="${esc(ACCW.search)}" oninput="ACCW.search=this.value;_accwDebouncedList()" placeholder="Request ID, payee, Order No, Bill No, UTR…" style="${selStyle};width:100%;box-sizing:border-box">
        </div>
        <div style="display:flex;flex-direction:column;gap:3px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">Stage</label>
          <select onchange="_accwSetStage(this.value)" style="${selStyle}">${opt(stageOpts,ACCW.stage)}</select>
        </div>
        <div style="display:flex;flex-direction:column;gap:3px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">Site</label>
          <select onchange="ACCW.site=this.value;_accwRenderListOnly()" style="${selStyle}"><option value="">All Sites</option>${sites.map(s=>`<option ${s===ACCW.site?'selected':''}>${esc(s)}</option>`).join('')}</select>
        </div>
        <div style="display:flex;flex-direction:column;gap:3px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">For</label>
          <select onchange="ACCW.entity=this.value;_accwRenderListOnly()" style="${selStyle}"><option value="">All</option>${entities.map(s=>`<option ${s===ACCW.entity?'selected':''}>${esc(s)}</option>`).join('')}</select>
        </div>
        <div style="display:flex;flex-direction:column;gap:3px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">Process</label>
          <select onchange="ACCW.process=this.value;_accwRenderListOnly()" style="${selStyle}"><option value="">All Processes</option>${procs.map(s=>`<option ${s===ACCW.process?'selected':''}>${esc(s)}</option>`).join('')}</select>
        </div>
        <div style="display:flex;flex-direction:column;gap:3px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">Age</label>
          <select onchange="ACCW.age=this.value;_accwRenderListOnly()" style="${selStyle}">${opt(ageOpts,ACCW.age)}</select>
        </div>
        <div style="display:flex;flex-direction:column;gap:3px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">Group by</label>
          <select onchange="ACCW.groupBy=this.value;ACCW.collapsed.clear();_accwRenderListOnly()" style="${selStyle}">${opt(groupOpts,ACCW.groupBy)}</select>
        </div>
        <div style="display:flex;flex-direction:column;gap:3px">
          <label style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase">Saved view</label>
          <div style="display:flex;gap:4px">
            <select onchange="_accwApplyView(this.value)" style="${selStyle};min-width:120px"><option value="">— none —</option>${Object.keys(_accwGetViews()).map(n=>`<option ${n===ACCW._view?'selected':''}>${esc(n)}</option>`).join('')}</select>
            <button onclick="_accwSaveCurrentView()" class="btn btn-secondary btn-sm" title="Save current filters as a view">&#128190;</button>
            <button onclick="_accwDeleteView()" class="btn btn-secondary btn-sm" title="Delete the selected saved view">&#128465;</button>
          </div>
        </div>
        <button onclick="ACCW.search='';ACCW.site='';ACCW.entity='';ACCW.process='';ACCW.age='';ACCW.stage='all';ACCW._view='';_accwRenderBody()" class="btn btn-secondary btn-sm" style="align-self:flex-end">&#10006; Reset</button>
        <button onclick="_accwExportCsv()" class="btn btn-secondary btn-sm" style="align-self:flex-end;background:var(--g7);color:#fff;border-color:var(--g7)">&#11015; CSV</button>
      </div>
    </div></div>`;

  const shelf = (typeof _txnShelfHtml === 'function') ? `<div id="accwTxnShelf">${_txnShelfHtml('acc')}</div>` : '';
  return _accwStageChipsHtml() + shelf + toolbar + `<div id="accwList">${_accwTableHtml(rows)}</div>`;
}
function _accwRenderListOnly() {
  const el = document.getElementById('accwList'); if (!el) { _accwRenderBody(); return; }
  el.innerHTML = _accwTableHtml(_accwFiltered());
}
// Debounced re-render for the search box — typing fast over thousands of rows
// must not rebuild the whole table on every keystroke (that's the "stuck" lag).
let _accwListTimer = null;
function _accwDebouncedList() {
  clearTimeout(_accwListTimer);
  _accwListTimer = setTimeout(_accwRenderListOnly, 180);
}
function _accwTableHtml(rows) {
  const esc = (typeof escapeHtml_==='function') ? escapeHtml_ : (s=>String(s||''));
  const TH = 'padding:8px 9px;text-align:left;font-weight:600;white-space:nowrap;border-right:1px solid rgba(255,255,255,.15)';
  const TD = 'padding:6px 9px;border-bottom:1px solid var(--border)';
  // group
  const groups = new Map();
  if (ACCW.groupBy === 'none') groups.set('', rows);
  else rows.forEach(r => { const k=_accwGroupKey(r); if (!groups.has(k)) groups.set(k,[]); groups.get(k).push(r); });
  const gentries = [...groups.entries()].sort((a,b)=>_accwSum(b[1])-_accwSum(a[1]));
  const grand = _accwSum(rows);
  const ncol = 11;

  const tc = { 'vendor':['#dbeafe','#1d4ed8'], 'employee':['#dcfce7','#15803d'], 'sub contractor':['#fef3c7','#b45309'], 'others':['#f3e8ff','#7c3aed'] };
  const rowHtml = (r) => {
    const v = _accViewById(_accStageOf(r));
    const st = r.status || {};
    const canAdv = _accCanAdvance(v);
    const canUpd = (typeof _accCanUpdate === 'function') ? _accCanUpdate(r) : false;
    const advLabel = (v.next && (v.next.actionLabel || v.next.to)) || '';
    const payee = _accStripCode(r.paidTo) || r.payTo || '—';
    const uuid = (r.uuid || '').replace(/'/g, "\\'");
    const checked = ACCW.sel.has(r.uuid) ? 'checked' : '';
    const ma = (r.manualAuto || '').toLowerCase();
    const maBadge = r.manualAuto ? `<span style="font-size:.56rem;padding:1px 5px;border-radius:8px;background:${ma.includes('auto')?'#dbeafe':'#ede9fe'};color:${ma.includes('auto')?'#1d4ed8':'#6d28d9'};font-weight:700">${esc(r.manualAuto)}</span>` : '';
    const inst = (r.installment && +r.installment > 1) ? `<span title="Installment" style="font-size:.56rem;padding:1px 5px;border-radius:8px;background:#f1f5f9;color:var(--txt2);font-weight:700">#${esc(r.installment)}</span>` : '';
    const pc = tc[(r.payTo || '').toLowerCase()] || ['#e5e7eb', '#475569'];
    const typeBadge = r.payTo ? `<span style="font-size:.56rem;font-weight:700;padding:1px 6px;border-radius:8px;background:${pc[0]};color:${pc[1]};white-space:nowrap">${esc(r.payTo)}</span>` : '';
    return `<tr style="cursor:pointer" onclick="if(event.target.tagName!=='INPUT'&&event.target.tagName!=='BUTTON')_accOpenPRDetail('${uuid}')">
      <td style="${TD};text-align:center"><input type="checkbox" ${checked} onclick="event.stopPropagation();_accwToggleSel('${uuid}')" style="width:15px;height:15px;cursor:pointer"></td>
      <td style="${TD};white-space:nowrap">
        <div style="font-family:monospace;font-size:.74rem;color:var(--g8);font-weight:700">${esc(r.requestId)||'—'}</div>
        <div style="display:flex;gap:.25rem;margin-top:2px">${maBadge}${inst}</div>
      </td>
      <td style="${TD};max-width:260px">
        <div style="display:flex;align-items:center;gap:.35rem;min-width:0"><b style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(payee)}</b>${typeBadge}</div>
        ${r.nature?`<div style="font-size:.7rem;color:var(--txt2);overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${esc(r.nature)}">${esc(r.nature)}</div>`:''}
        ${r.narrative?`<div style="font-size:.66rem;color:var(--txt3);overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${esc(r.narrative)}">${esc(r.narrative)}</div>`:''}
      </td>
      <td style="${TD};max-width:130px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${esc(r.site)}">${esc(r.site)||'—'}</td>
      <td style="${TD};font-family:monospace;font-size:.72rem;color:var(--txt2);white-space:nowrap">${esc(r.orderNo)||'—'}</td>
      <td style="${TD};text-align:right;font-weight:700;color:${r.amount>0?'var(--g8)':'var(--txt3)'};white-space:nowrap">${_accwFmt(r.amount)}</td>
      <td style="${TD};white-space:nowrap">${st.label?`<span style="background:${st.bg};color:${st.color};padding:2px 8px;border-radius:9px;font-size:.66rem;font-weight:600;border:1px solid ${st.color}22">${esc(st.label)}</span>`:'—'}</td>
      <td style="${TD};white-space:nowrap">${(typeof _vplpStatusChipFor==='function')?_vplpStatusChipFor(r,{dash:'<span style=\"color:var(--txt3)\">—</span>'}):'—'}</td>
      <td style="${TD};text-align:center">${_accwAgeChip(_accwAge(r))}</td>
      <td style="${TD};white-space:nowrap;color:var(--txt2);font-size:.74rem">${esc(r.date)||'—'}</td>
      <td style="${TD};white-space:nowrap;text-align:center">
        <div style="display:flex;gap:4px;justify-content:center">
          ${canUpd?`<button onclick="event.stopPropagation();_accOpenPRDetail('${uuid}')" class="btn btn-secondary btn-sm" title="Update status" style="padding:2px 8px;font-size:.62rem">&#9998; Update</button>`:''}
          ${canAdv?`<button onclick="event.stopPropagation();_accAdvance('${uuid}')" class="btn btn-sm" title="${advLabel}" style="background:#16a34a;color:#fff;border:none;padding:2px 9px;font-size:.62rem;font-weight:700">&#10003; ${advLabel}</button>`:''}
          ${(!canUpd&&!canAdv)?'<span style="color:var(--txt3);font-size:.7rem">—</span>':''}
        </div>
      </td>
    </tr>`;
  };

  // Progressive rendering. Build the FULL ordered list of <tr> HTML (group
  // headers + rows, honoring collapse), but only paint a first window into the
  // DOM; the rest stream in as the user scrolls (_accwMaybeLoadMore). Painting
  // thousands of <tr> at once is what made the worklist feel stuck. Totals and
  // the footer still reflect every row.
  const items = [];
  gentries.forEach(([k, grp]) => {
    if (ACCW.groupBy !== 'none') {
      const sub = _accwSum(grp);
      const isCollapsed = ACCW.collapsed.has(k);
      items.push(`
        <tr style="background:var(--surface2);cursor:pointer" onclick="_accwToggleGroup('${String(k).replace(/'/g,"\\'")}')">
          <td colspan="${ncol}" style="padding:6px 9px;border-bottom:1px solid var(--border);font-weight:700;font-size:.78rem;color:var(--txt1)">
            <span style="display:inline-block;width:14px">${isCollapsed?'▸':'▾'}</span>
            ${esc(k)} <span style="color:var(--txt3);font-weight:500">&middot; ${grp.length}</span>
            <span style="float:right;color:var(--g8)">${_accwFmt(sub)}</span>
          </td>
        </tr>`);
      if (isCollapsed) return;
    }
    for (const r of grp) items.push(rowHtml(r));
  });
  ACCW._items = items;
  ACCW._n = Math.min(_ACCW_RENDER_INIT, items.length);
  const body = items.slice(0, ACCW._n).join('');

  return `
    <div class="card"><div id="accwScroller" onscroll="_accwMaybeLoadMore()" style="overflow:auto;max-height:66vh;border-radius:0 0 var(--rad) var(--rad)">
      <table class="data-table" data-evg-defaults="off" style="width:100%">
        <thead><tr style="background:var(--g9);color:#fff;position:sticky;top:0;z-index:2">
          <th style="${TH};text-align:center;width:34px"><input type="checkbox" onclick="_accwToggleAll(this.checked)" title="Select all shown" style="width:15px;height:15px;cursor:pointer"></th>
          <th style="${TH}">Request ID</th><th style="${TH}">Request Details</th><th style="${TH}">Site</th>
          <th style="${TH}">Order No</th><th style="${TH};text-align:right">Amount</th><th style="${TH}">Status</th>
          <th style="${TH}" title="Vendor bill status from the Vendor Ledger (PO)">Vendor Status</th>
          <th style="${TH};text-align:center">Age</th><th style="${TH}">Date</th><th style="${TH};text-align:center">Actions</th>
        </tr></thead>
        <tbody id="accwTbody">${body || `<tr><td colspan="${ncol}" style="text-align:center;padding:3rem;color:var(--txt3)">No matching requests.</td></tr>`}</tbody>
        <tfoot><tr style="background:var(--g9);color:#fff;position:sticky;bottom:0;font-weight:800">
          <td colspan="5" style="padding:8px 9px;text-align:right">${rows.length} request(s) &middot; Grand total</td>
          <td style="padding:8px 9px;text-align:right">${_accwFmt(grand)}</td>
          <td colspan="5"></td>
        </tr></tfoot>
      </table>
    </div></div>
    <div id="accwBulkBar">${_accwBulkBarHtml()}</div>`;
}
// Progressive worklist rendering: paint a window, stream the rest on scroll.
const _ACCW_RENDER_INIT = 200, _ACCW_RENDER_CHUNK = 200;
function _accwMaybeLoadMore() {
  const sc = document.getElementById('accwScroller');
  if (!sc || !ACCW._items || ACCW._n >= ACCW._items.length) return;
  if (sc.scrollTop + sc.clientHeight >= sc.scrollHeight - 600) _accwAppendRows();
}
function _accwAppendRows() {
  const tb = document.getElementById('accwTbody'), sc = document.getElementById('accwScroller');
  if (!tb || !sc || !ACCW._items || ACCW._n >= ACCW._items.length) return;
  const next = ACCW._items.slice(ACCW._n, ACCW._n + _ACCW_RENDER_CHUNK);
  tb.insertAdjacentHTML('beforeend', next.join(''));
  ACCW._n += next.length;
  // Keep filling if the user flung the scrollbar straight to the bottom.
  if (ACCW._n < ACCW._items.length && sc.scrollTop + sc.clientHeight >= sc.scrollHeight - 600) {
    requestAnimationFrame(_accwAppendRows);
  }
}
function _accwBulkBarHtml() {
  if (!ACCW.sel.size) return '';
  const rows = _accwRows().filter(r => ACCW.sel.has(r.uuid));
  const doable = rows.filter(r => { const v=_accViewById(_accStageOf(r)); return _accCanAdvance(v) && v.next && !v.next.needsUtr; });
  return `<div style="position:sticky;bottom:0;margin-top:.6rem;display:flex;align-items:center;gap:1rem;flex-wrap:wrap;background:var(--g9);color:#fff;padding:.6rem 1rem;border-radius:10px;box-shadow:0 6px 20px rgba(0,0,0,.2)">
    <span style="font-weight:700">${ACCW.sel.size} selected</span>
    <span style="opacity:.9">Total ${_accwFmt(_accwSum(rows))}</span>
    <span style="flex:1"></span>
    ${doable.length?`<button onclick="_accwBulkAdvance()" class="btn btn-sm" style="background:#16a34a;color:#fff;border:none;font-weight:700">&#10003; Advance ${doable.length} &rarr; next stage</button>`:''}
    <button onclick="ACCW.sel.clear();_accwRenderListOnly()" class="btn btn-secondary btn-sm">Clear</button>
  </div>`;
}
function _accwToggleSel(uuid) { if (ACCW.sel.has(uuid)) ACCW.sel.delete(uuid); else ACCW.sel.add(uuid); _accwSyncBulkBar(); }
function _accwToggleAll(on)   { ACCW.sel.clear(); if (on) _accwFiltered().forEach(r=>ACCW.sel.add(r.uuid)); _accwRenderListOnly(); }
function _accwToggleGroup(k)  { if (ACCW.collapsed.has(k)) ACCW.collapsed.delete(k); else ACCW.collapsed.add(k); _accwRenderListOnly(); }
function _accwSyncBulkBar() {
  const bar = document.getElementById('accwBulkBar'); if (bar) bar.innerHTML = _accwBulkBarHtml();
}
async function _accwBulkAdvance() {
  const rows = _accwRows().filter(r => ACCW.sel.has(r.uuid));
  const doable = rows.filter(r => { const v=_accViewById(_accStageOf(r)); return _accCanAdvance(v) && v.next && !v.next.needsUtr; });
  if (!doable.length) { alert('None of the selected rows can be advanced by you in one step.\n(UTR-completion rows must be done individually.)'); return; }
  if (!confirm(`Advance ${doable.length} request(s) to their next stage?`)) return;
  doable.forEach(r => { const v=_accViewById(_accStageOf(r)); _txnParkRow(r, v.next.status, '→ '+v.next.to, 'acc'); });
  ACCW.sel.clear(); _accwRenderListOnly();
  if (typeof _accToast==='function') _accToast('Advancing '+doable.length+' request(s)…');
  for (const r of doable) { const v=_accViewById(_accStageOf(r)); try { await _accQuickStatus(r.uuid, v.next.status, '', '', true, r.uuid + '|' + v.next.status); } catch(e){} }
  if (typeof _accToast==='function') _accToast('✅ Advanced '+doable.length+' request(s)');
  await _accReloadRows(); _accwRenderBody();
}
function _accwExportCsv() {
  if (typeof _accCan === 'function' && !_accCan('export')) { alert('You do not have permission to export.'); return; }
  const rows = _accwFiltered();
  const head = ['Request ID','Payee','Type','Site','For','Order No','Bill No','Amount','Currency','Stage','Status','Vendor Status','Age (days)','Date'];
  const esc = v => '"' + String(v==null?'':v).replace(/"/g,'""') + '"';
  const vStat = r => { const s = (typeof _vplpStatusForPR==='function') ? _vplpStatusForPR(r) : null; return s ? (s.status + ' (' + Math.round(Math.abs(s.bal)).toLocaleString('en-IN') + (s.bal>=0?' Cr':' Dr') + ')') : ''; };
  const lines = [head.map(esc).join(',')];
  rows.forEach(r => lines.push([r.requestId, _accStripCode(r.paidTo)||r.payTo, r.payTo, r.site, r.entity, r.orderNo, r.billNo,
    r.amount, r.currency, _accViewById(_accStageOf(r)).label, (r.status&&r.status.label)||'', vStat(r), _accwAge(r), r.date].map(esc).join(',')));
  const blob = new Blob([lines.join('\n')], { type:'text/csv' });
  const a = document.createElement('a'); a.href = URL.createObjectURL(blob);
  a.download = 'accounts-worklist-' + new Date().toISOString().slice(0,10) + '.csv';
  a.click(); URL.revokeObjectURL(a.href);
}



// ══════════════════════════════════════════════════════════════
//  ACCOUNTS — NEW PAYMENT REQUEST (portal-native, slide-in panel)
//  Reuses existing constants: PAYMENT_SHEET_ID, SHEET_ID (master), EMP_SHEET_ID
//  Writes are header-name driven (never by column letter) — the backend
//  saveNewPaymentRequest action matches each value to the live header row.
// ══════════════════════════════════════════════════════════════
let _accCostCenter      = null;   // [{ nature, accCodeDesc, accCode }]
let _accPayMaster       = null;   // [{ department, process, orderNo, billNo }]
let _accVendorMaster    = null;   // [{ name, acHolder, acNo, ifsc, bank }]
let _accSCMaster        = null;   // [{ name, acHolder, acNo, ifsc, bank }]

function _accBankRec(r, name) {
  return {
    name: name,
    acHolder: r['Vendor Acc Name'] || r['A/C HOLDER NAME'] || r['Account Holder Name'] || r['AC HOLDER NAME'] || name,
    acNo:     String(r['Acc No'] || r['A/C NUMBER'] || r['Account Number'] || r['AC NUMBER'] || r['A/C No'] || '').replace(/^ACNO:'?/i, ''),
    ifsc:     r['IFSC'] || r['IFSC CODE'] || r['Ifsc Code'] || '',
    bank:     r['Bank'] || r['BANK NAME'] || r['Bank Name'] || r['BANK'] || '',
  };
}

async function _accLoadCostCenter() {
  if (_accCostCenter !== null) return;
  try {
    const rows = await fetchSheet('M17_CostCenter', null, SHEET_ID);
    _accCostCenter = rows.map(r => ({
      nature:      r['NATURE OF EXPENSES'] || r['Nature Of Expenses'] || '',
      accCodeDesc: r['ACCOUNT CODE DESCRIPTIONS'] || r['Account Code Descriptions'] || '',
      accCode:     r['ACCOUNT CODES'] || r['Account Codes'] || r['CostCode'] || '',
    })).filter(r => r.nature || r.accCodeDesc);
  } catch (e) { _accCostCenter = []; }
}

async function _accLoadPaymentMaster() {
  if (_accPayMaster !== null) return;
  try {
    const rows = await fetchSheet('Payment_Mater', null, PAYMENT_SHEET_ID);
    _accPayMaster = rows.map(r => ({
      department: r['Department'] || '',
      process:    r['From Which Process'] || r['From which Process'] || '',
      orderNo:    r['Order No'] || '',
      billNo:     r['Bill No'] || '',
    })).filter(r => r.department || r.process);
  } catch (e) { _accPayMaster = []; }
}

async function _accLoadVendorMaster() {
  if (_accVendorMaster !== null) return;
  try {
    const rows = await fetchSheet(VENDOR_MASTER_TAB, null, VENDOR_MASTER_SHEET_ID);
    _accVendorMaster = rows
      .map(r => _accBankRec(r, r['Vendor Name'] || r['VENDOR NAME'] || r['Name'] || r['Vendor'] || ''))
      .filter(r => r.name);
  } catch (e) { _accVendorMaster = []; }
}

async function _accLoadSCMaster() {
  if (_accSCMaster !== null) return;
  try {
    const rows = await fetchSheet('10-SubContractorMaster', null, SHEET_ID);
    _accSCMaster = rows
      .map(r => _accBankRec(r, r['Sub Contractor Name'] || r['SubContractor Name'] || r['Name'] || r['Sub-Contractor'] || ''))
      .filter(r => r.name);
  } catch (e) { _accSCMaster = []; }
}

// Generic awaited POST to the main Apps Script — surfaces real errors, never swallows.
// Unlike _rcPostActionAwait this does NOT inject a recruitment sheetId.
async function _accPostAwait(payload) {
  let res;
  const endpoint = getExec('accounts');
  try {
    res = await fetch(endpoint, {
      method: 'POST', headers: { 'Content-Type': 'text/plain' },
      body: JSON.stringify(payload)
    });
  } catch (e) {
    return { success: false, message: 'Could not reach the backend: ' + e.message };
  }
  try { return await res.json(); }
  catch (e) { return { success: false, message: `Backend returned a non-JSON response (HTTP ${res.status}). Check the Apps Script deployment.` }; }
}

const _accToast = (m) => { try { _showRcToast(m); } catch (e) { /* toast optional */ } };
const _accV = (id) => { const e = document.getElementById(id); return e ? String(e.value || '').trim() : ''; };
const _accFlag = (v) => { const s = String(v || '').toLowerCase().trim(); return s === 'yes' || s === 'true' || s === 'y' || s === '1' || s === 'show'; };

// Date/time formatters for values written to the sheet.
const _ACC_MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
// Long date: "10Jun2026" — accepts a yyyy-mm-dd string or a Date.
// (_accFmtLongDate is defined once, later in this file — the canonical version.)
// Timestamp: "10/06/2026 13:47:38" — local time, DD/MM/YYYY HH:MM:SS.
function _accFmtDateTime(d) {
  const dt = d ? (d instanceof Date ? d : new Date(d)) : new Date();
  if (isNaN(dt)) return String(d || '');
  const p = n => String(n).padStart(2, '0');
  return `${p(dt.getDate())}/${p(dt.getMonth() + 1)}/${dt.getFullYear()} ${p(dt.getHours())}:${p(dt.getMinutes())}:${p(dt.getSeconds())}`;
}
// Numeric DD/MM/YYYY (no time). Use this when recording/displaying a plain date —
// unlike _accFmtLongDate, this accepts a Date object directly.
function _accFmtDate(d) {
  const dt = d ? (d instanceof Date ? d : new Date(d)) : new Date();
  if (isNaN(dt)) return String(d || '');
  const p = n => String(n).padStart(2, '0');
  return `${p(dt.getDate())}/${p(dt.getMonth() + 1)}/${dt.getFullYear()}`;
}

function _accOpenNewPR() {
  let dr = document.getElementById('accPRDrawer');
  if (!dr) {
    dr = document.createElement('div');
    dr.id = 'accPRDrawer';
    dr.style.cssText = 'position:fixed;top:var(--header-h);right:-660px;width:640px;max-width:96vw;height:calc(100vh - var(--header-h));background:#fff;border-left:1px solid var(--border);z-index:1100;transition:right .28s cubic-bezier(.4,0,.2,1);box-shadow:-4px 0 24px rgba(0,0,0,.1);display:flex;flex-direction:column';
    document.body.appendChild(dr);
  }
  dr.innerHTML = '<div style="padding:2.5rem;text-align:center;color:var(--txt3)">&#8987; Loading form&hellip;</div>';
  // slide in on next frame
  requestAnimationFrame(() => { dr.style.right = '0'; });
  Promise.all([
    _accLoadCostCenter(),
    _accLoadPaymentMaster(),
    _accLoadVendorMaster(),
    _accLoadSCMaster(),
  ]).then(() => _accDrawNewPRForm(dr));
}

function _accCloseNewPR() {
  const dr = document.getElementById('accPRDrawer');
  if (dr) dr.style.right = '-660px';
}

function _accDrawNewPRForm(dr) {
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const me  = (STATE.masters.users || []).find(u => (u.email || '').toLowerCase() === (STATE.user?.email || '').toLowerCase());
  const initiatorDefault = me ? (me.employeeRef || me.name) : (STATE.user?.name || '');
  const initiatorLocked  = STATE.role !== 'md';
  const today = new Date().toLocaleDateString('en-CA'); // yyyy-mm-dd for <input type=date>

  const opt = (arr, sel) => '<option value=""></option>' +
    [...new Set((arr || []).filter(Boolean))].sort()
      .map(v => `<option value="${esc(v)}"${v === sel ? ' selected' : ''}>${esc(v)}</option>`).join('');

  const depts      = [...new Set((_accPayMaster || []).map(p => p.department).filter(Boolean))];
  const procs      = [...new Set((_accPayMaster || []).map(p => p.process).filter(Boolean))];
  const natures    = [...new Set((_accCostCenter || []).map(c => c.nature).filter(Boolean))];
  const accDescs   = [...new Set((_accCostCenter || []).map(c => c.accCodeDesc).filter(Boolean))];
  const empNames   = (STATE.masters.users || []).filter(u => u.name && u.status === 'ACTIVE').map(u => u.employeeRef || u.name);
  const vendorNames= (_accVendorMaster || []).map(v => v.name);
  const scNames    = (_accSCMaster || []).map(v => v.name);
  const siteNames  = (STATE.masters.sites || []).map(s => s.name).filter(Boolean);
  const currencies = ['Indian Rupee', 'US Dollar', 'Euro', 'GBP', 'AED', 'OMR', 'QAR'];

  const sec = (title, inner) => `
    <div style="margin-bottom:1.1rem">
      <div style="font-weight:700;font-size:.74rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.6rem;border-bottom:1px solid var(--border);padding-bottom:.35rem">${title}</div>
      ${inner}
    </div>`;
  const fld = (label, ctrl, req, id) => `
    <div style="display:flex;flex-direction:column;gap:3px;margin-bottom:.55rem"${id ? ` id="${id}"` : ''}>
      <label style="font-size:.71rem;font-weight:600;color:var(--txt2)">${label}${req ? ' <span style="color:var(--danger)">*</span>' : ''}</label>
      ${ctrl}
    </div>`;
  const grid = (...items) => `<div style="display:grid;grid-template-columns:1fr 1fr;gap:0 1rem">${items.join('')}</div>`;
  const ro = 'background:var(--surface2);color:var(--txt2);cursor:not-allowed';

  dr.innerHTML = `
    <div style="padding:1rem 1.3rem;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;flex-shrink:0;background:linear-gradient(135deg,var(--g9),var(--g7));color:#fff">
      <div>
        <div style="font-size:.98rem;font-weight:700">&#10133; New Payment Request</div>
        <div style="font-size:.72rem;opacity:.8;margin-top:2px">Fields marked * are required</div>
      </div>
      <button onclick="_accCloseNewPR()" style="background:rgba(255,255,255,.18);border:none;color:#fff;width:30px;height:30px;border-radius:7px;cursor:pointer;font-size:1rem">&#10006;</button>
    </div>

    <div class="evg-form" style="flex:1;overflow-y:auto;padding:1.1rem 1.3rem">

      ${sec('1 &middot; Initiator', grid(
        fld('Date of Request', `<input id="acc-pr-dateOfRequest" type="date" value="${today}">`, true),
        fld('Payment Requested By', `<input id="acc-pr-initiator" value="${esc(initiatorDefault)}" ${initiatorLocked ? 'readonly title="Auto-filled from your profile"' : ''} style="${initiatorLocked ? ro : ''}">`, true),
        fld('Department', evgComboHtml({ id: 'acc-pr-department', items: depts.map(x => ({ v: x, label: x })), placeholder: 'Type a department…', onPick: '_accPROnDeptChange' })),
        fld('From Which Process', evgComboHtml({ id: 'acc-pr-fromWhichProcess', items: procs.map(x => ({ v: x, label: x })), placeholder: 'Type a process…', onPick: '_accPROnProcessChange' })),
        fld('Manual / Auto', `<select id="acc-pr-manualAuto"><option value="Manual" selected>Manual</option><option value="Auto">Auto</option></select>`)
      ))}

      ${sec('2 &middot; Payment To', `
        ${fld('Payment To', `<select id="acc-pr-paymentTo" onchange="_accPROnPaymentToChange()">${opt(['Employee', 'Vendor', 'Sub Contractor', 'Others'])}</select>`, true)}
        <div id="acc-pr-paidto-employee" style="display:none">${fld('Paid To (Employee)', evgComboHtml({ id: 'acc-pr-paidToEmployee', items: [...new Set((empNames || []).filter(Boolean))].sort().map(n => ({ v: n, label: n })), placeholder: 'Type an employee name…', onPick: '_accPRAutoFillBankDetails' }))}</div>
        <div id="acc-pr-paidto-vendor" style="display:none">${fld('Paid To (Vendor)', evgComboHtml({ id: 'acc-pr-paidToVendor', items: [...new Set((vendorNames || []).filter(Boolean))].sort().map(n => ({ v: n, label: n })), placeholder: 'Type a vendor name…', onPick: '_accPRAutoFillBankDetails' }))}</div>
        <div id="acc-pr-paidto-sc" style="display:none">${fld('Paid To (Sub Contractor)', evgComboHtml({ id: 'acc-pr-paidToSC', items: [...new Set((scNames || []).filter(Boolean))].sort().map(n => ({ v: n, label: n })), placeholder: 'Type a sub contractor name…', onPick: '_accPRAutoFillBankDetails' }))}</div>
        <div id="acc-pr-paidto-others" style="display:none">${fld('Paid To (Others)', `<input id="acc-pr-paidToOthers" placeholder="Name of payee">`)}</div>
      `)}

      ${sec('3 &middot; Site &amp; Company', grid(
        fld('Site Name', evgComboHtml({ id: 'acc-pr-siteName', items: [...new Set((siteNames || []).filter(Boolean))].sort().map(x => ({ v: x, label: x })), placeholder: 'Type a site name…', onPick: '_accPROnSiteChange' })),
        fld('Company', `<input id="acc-pr-company" placeholder="Auto-fills from site">`)
      ))}

      ${sec('4 &middot; Bill &amp; PO Reference', `
        ${grid(
          fld('Order No', `<input id="acc-pr-orderNo">`, false, 'acc-pr-orderNo-wrap'),
          fld('Bill No', `<input id="acc-pr-billNo">`, false, 'acc-pr-billNo-wrap')
        )}
        <div id="acc-pr-paymentTerms-wrap" style="display:none">${fld('Payment Terms', `<input id="acc-pr-paymentTerms" placeholder="e.g. Net 30">`)}</div>
        <div id="acc-pr-po-wrap" style="display:none">${grid(
          fld('PO Value', `<input id="acc-pr-poValue" type="number" step="0.01" oninput="_accPRRecalcPending()">`),
          fld('Invoice Value', `<input id="acc-pr-invoiceValue" type="number" step="0.01">`),
          fld('Paid Value', `<input id="acc-pr-paidValue" value="0" readonly style="${ro}">`),
          fld('Pending Value', `<input id="acc-pr-pendingValue" value="0" readonly style="${ro}">`)
        )}</div>
      `)}

      ${sec('5 &middot; Financial', grid(
        fld('Currency', `<select id="acc-pr-currency">${opt(currencies, 'Indian Rupee')}</select>`),
        fld('Amount', `<input id="acc-pr-amount" type="number" step="0.01">`, true),
        fld('Nature of Expenses', evgComboHtml({ id: 'acc-pr-natureOfExpenses', items: natures.map(x => ({ v: x, label: x })), placeholder: 'Type a nature of expense…', onPick: '_accPROnNatureChange' })),
        fld('Account Code Description', evgComboHtml({ id: 'acc-pr-accountCodeDesc', items: accDescs.map(x => ({ v: x, label: x })), placeholder: 'Type an account code…', onPick: '_accPROnAccCodeChange' })),
        fld('GST', `<input id="acc-pr-gst" type="number" step="0.01">`),
        fld('TDS', `<input id="acc-pr-tds" type="number" step="0.01">`)
      ) + `<input id="acc-pr-costCode" type="hidden">`)}

      ${sec('6 &middot; Bank Details', grid(
        fld('A/C Holder Name', `<input id="acc-pr-acHolderName">`),
        fld('A/C Number', `<input id="acc-pr-acNumber">`),
        fld('IFSC Code', `<input id="acc-pr-ifsc" placeholder="XXXX0XXXXXX">`),
        fld('Bank Name', `<input id="acc-pr-bankName">`)
      ))}

      ${sec('7 &middot; Narrative &amp; Attachments', `
        ${fld('Narrative / Comments', `<textarea id="acc-pr-narrative" rows="3" style="resize:vertical"></textarea>`, true)}
        ${fld('Account Type', `<input id="acc-pr-accountType">`)}
        ${fld('Attachments (invoice + supporting docs)', `<input id="acc-pr-files" type="file" multiple style="padding:6px">`)}
      `)}
    </div>

    <div style="padding:.9rem 1.3rem;border-top:1px solid var(--border);display:flex;gap:.7rem;justify-content:flex-end;flex-shrink:0;background:var(--surface2)">
      <button onclick="_accCloseNewPR()" class="btn btn-secondary btn-sm">Cancel</button>
      <button id="acc-pr-submit" onclick="_accPRSubmit()" class="btn btn-primary btn-sm">Submit Payment Request</button>
    </div>
  `;
}

function _accPROnDeptChange() {
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const dept = _accV('acc-pr-department');
  const procs = [...new Set((_accPayMaster || []).filter(p => !dept || p.department === dept).map(p => p.process).filter(Boolean))].sort();
  if (typeof evgComboSetItems === 'function') evgComboSetItems('acc-pr-fromWhichProcess', procs.map(p => ({ v: p, label: p })), true);
  const isPurchase = /purchase/i.test(dept);
  const pt = document.getElementById('acc-pr-paymentTerms-wrap'); if (pt) pt.style.display = isPurchase ? '' : 'none';
  const po = document.getElementById('acc-pr-po-wrap');           if (po) po.style.display = isPurchase ? '' : 'none';
  _accPROnProcessChange();
}

function _accPROnProcessChange() {
  const dept = _accV('acc-pr-department'), proc = _accV('acc-pr-fromWhichProcess');
  const rec = (_accPayMaster || []).find(p => p.process === proc && (!dept || p.department === dept))
           || (_accPayMaster || []).find(p => p.process === proc);
  const showOrder = rec ? _accFlag(rec.orderNo) : true;
  const showBill  = rec ? _accFlag(rec.billNo)  : true;
  const ow = document.getElementById('acc-pr-orderNo-wrap'); if (ow) ow.style.display = showOrder ? '' : 'none';
  const bw = document.getElementById('acc-pr-billNo-wrap');  if (bw) bw.style.display = showBill ? '' : 'none';
}

function _accPROnPaymentToChange() {
  const payTo = _accV('acc-pr-paymentTo');
  const map = { 'Employee': 'acc-pr-paidto-employee', 'Vendor': 'acc-pr-paidto-vendor', 'Sub Contractor': 'acc-pr-paidto-sc', 'Others': 'acc-pr-paidto-others' };
  Object.values(map).forEach(id => { const e = document.getElementById(id); if (e) e.style.display = 'none'; });
  const show = map[payTo]; if (show) { const e = document.getElementById(show); if (e) e.style.display = ''; }
  _accPRAutoFillBankDetails();
}

function _accPROnSiteChange() {
  const site = _accV('acc-pr-siteName');
  const rec = (STATE.masters.sites || []).find(s => s.name === site);
  const c = document.getElementById('acc-pr-company');
  if (rec && c) c.value = rec.company || '';
}

function _accPROnNatureChange() {
  const nature = _accV('acc-pr-natureOfExpenses');
  const descs = [...new Set((_accCostCenter || []).filter(c => !nature || c.nature === nature).map(c => c.accCodeDesc).filter(Boolean))].sort();
  if (typeof evgComboSetItems === 'function') evgComboSetItems('acc-pr-accountCodeDesc', descs.map(d => ({ v: d, label: d })), true);
  _accPROnAccCodeChange();
}

function _accPROnAccCodeChange() {
  const desc = _accV('acc-pr-accountCodeDesc');
  const rec = (_accCostCenter || []).find(c => c.accCodeDesc === desc);
  const cc = document.getElementById('acc-pr-costCode'); if (cc) cc.value = rec ? rec.accCode : '';
}

function _accPRAutoFillBankDetails() {
  const payTo = _accV('acc-pr-paymentTo');
  let rec = null;
  if (payTo === 'Vendor')              rec = (_accVendorMaster || []).find(v => v.name === _accV('acc-pr-paidToVendor'));
  else if (payTo === 'Sub Contractor') rec = (_accSCMaster || []).find(v => v.name === _accV('acc-pr-paidToSC'));
  if (!rec) return;
  const set = (id, val) => { const e = document.getElementById(id); if (e) e.value = val || ''; };
  set('acc-pr-acHolderName', rec.acHolder);
  set('acc-pr-acNumber',     rec.acNo);
  set('acc-pr-ifsc',         rec.ifsc);
  set('acc-pr-bankName',     rec.bank);
}

function _accPRRecalcPending() {
  const po   = parseFloat(_accV('acc-pr-poValue')) || 0;
  const paid = parseFloat(_accV('acc-pr-paidValue')) || 0;
  const pe = document.getElementById('acc-pr-pendingValue');
  if (pe) pe.value = (po - paid) > 0 ? (po - paid) : 0;
}

function _accPRBuildRow() {
  const rid = (crypto && crypto.randomUUID) ? crypto.randomUUID().slice(0, 8) : String(Date.now()).slice(-8);
  const uuid = 'ACC-' + rid;
  const email = STATE.user?.email || '';
  const payTo = _accV('acc-pr-paymentTo');
  const paidEmp = _accV('acc-pr-paidToEmployee'), paidVen = _accV('acc-pr-paidToVendor'),
        paidSC = _accV('acc-pr-paidToSC'),       paidOth = _accV('acc-pr-paidToOthers');
  const paidTo = payTo === 'Employee' ? paidEmp : payTo === 'Vendor' ? paidVen
               : payTo === 'Sub Contractor' ? paidSC : payTo === 'Others' ? paidOth : '';
  const num = id => { const n = parseFloat(_accV(id)); return isNaN(n) ? '' : n; };
  // Header-name keyed — backend places each into the matching live column.
  return {
    'UUID': uuid,
    'Link': uuid,
    'Manual / Auto': _accV('acc-pr-manualAuto') || 'Manual',
    'Installment': 1,
    'Date Of Request': _accFmtLongDate(_accV('acc-pr-dateOfRequest')),
    'Name of the Intiator': _accV('acc-pr-initiator'),
    'NATURE OF EXPENSES': _accV('acc-pr-natureOfExpenses'),
    'ACCOUNT CODE DESCRIPTIONS': _accV('acc-pr-accountCodeDesc'),
    'Payment To': payTo,
    'CostCode': _accV('acc-pr-costCode'),
    'Department': _accV('acc-pr-department'),
    'From Which Process': _accV('acc-pr-fromWhichProcess'),
    'Paid To': paidTo,
    'Paid To (Employee)': paidEmp,
    'Paid To (Vendor)': paidVen,
    'Paid To (SC)': paidSC,
    'Paid To (Others)': paidOth,
    'Site Name': _accV('acc-pr-siteName'),
    'Company': _accV('acc-pr-company'),
    'Order No': _accV('acc-pr-orderNo'),
    'Bill No': _accV('acc-pr-billNo'),
    'Payment Terms': _accV('acc-pr-paymentTerms'),
    'PO Value': num('acc-pr-poValue'),
    'Invoice Value': num('acc-pr-invoiceValue'),
    'GST': num('acc-pr-gst'),
    'TDS': num('acc-pr-tds'),
    'Currency': _accV('acc-pr-currency') || 'Indian Rupee',
    'Amount': num('acc-pr-amount'),
    'Narrative/Comments': _accV('acc-pr-narrative'),
    'Account Type': _accV('acc-pr-accountType'),
    'A/C HOLDER NAME': _accV('acc-pr-acHolderName'),
    'A/C NUMBER': _accV('acc-pr-acNumber'),
    'IFSC CODE': _accV('acc-pr-ifsc'),
    'BANK NAME': _accV('acc-pr-bankName'),
    'UserEmail': email,
    'SystemEmail': email,
    'Timestamp': _accFmtDateTime(new Date()),
  };
}

function _accFileToB64(file) {
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload  = () => resolve(String(r.result).split(',')[1] || '');
    r.onerror = reject;
    r.readAsDataURL(file);
  });
}

async function _accPRUploadAttachments(uuid, requestId) {
  const input = document.getElementById('acc-pr-files');
  if (!input || !input.files || !input.files.length) return;
  const folderResp = await _accPostAwait({ action: 'createPRFolder', requestId: requestId || uuid, uuid: uuid });
  if (!folderResp || folderResp.success === false || !folderResp.folderId) return;
  for (const f of input.files) {
    const base64 = await _accFileToB64(f);
    await _accPostAwait({ action: 'uploadPRAttachment', folderId: folderResp.folderId, filename: f.name, mimeType: f.type || 'application/octet-stream', base64: base64 });
  }
}

async function _accPRSubmit() {
  if (typeof _accCan === 'function' && !_accCan('create')) { alert('You do not have permission to create payment requests.'); return; }
  const errors = [];
  const amount  = parseFloat(_accV('acc-pr-amount')) || 0;
  const payTo   = _accV('acc-pr-paymentTo');
  const poValue = parseFloat(_accV('acc-pr-poValue')) || 0;
  const pending = parseFloat(_accV('acc-pr-pendingValue')) || 0;
  const paidMap = { 'Employee': 'acc-pr-paidToEmployee', 'Vendor': 'acc-pr-paidToVendor', 'Sub Contractor': 'acc-pr-paidToSC', 'Others': 'acc-pr-paidToOthers' };

  if (amount <= 0) errors.push('Amount must be greater than 0.');
  if (!_accV('acc-pr-narrative')) errors.push('Narrative / Comments is required.');
  if (payTo && paidMap[payTo] && !_accV(paidMap[payTo])) errors.push('Please specify who the payment is to.');
  if (poValue > 0 && pending > 0 && amount > pending) errors.push(`Amount (${amount}) exceeds the Pending Value (${pending}).`);
  if (errors.length) { alert('Please fix the following:\n\n• ' + errors.join('\n• ')); return; }

  // Duplicate-payment guard — warn if a non-rejected request already exists with the
  // same Order No (or same payee) AND the same amount. Cheap safety net vs double-paying.
  const _dupPayee = (payTo && paidMap[payTo]) ? _accStripCode(_accV(paidMap[payTo]) || '') : '';
  const _dupOrder = (_accV('acc-pr-orderNo') || '').trim().toLowerCase();
  const _dupes = (window._accAllRows || []).filter(r => {
    if (_accStageOf(r) === 'rejected') return false;
    if (Math.abs((r.amount || 0) - amount) >= 1) return false;
    const orderMatch = _dupOrder && String(r.orderNo || '').trim().toLowerCase() === _dupOrder;
    const payeeMatch = _dupPayee && (_accStripCode(r.paidTo || '') || '').toLowerCase() === _dupPayee.toLowerCase();
    return orderMatch || payeeMatch;
  });
  if (_dupes.length) {
    const fmt = n => '₹' + Math.round(n || 0).toLocaleString('en-IN');
    const list = _dupes.slice(0, 5).map(d => `• ${d.requestId || '?'} — ${fmt(d.amount)} — ${d.date || ''} — ${(d.status && d.status.label) || ''}`).join('\n');
    if (!confirm(`⚠ Possible duplicate payment\n\n${_dupes.length} existing request(s) match this amount and ${_dupOrder ? 'Order No' : 'payee'}:\n\n${list}\n\nCreate this request anyway?`)) {
      return;
    }
  }

  const btn = document.getElementById('acc-pr-submit');
  if (btn) { btn.disabled = true; btn.textContent = 'Saving…'; }

  const row  = _accPRBuildRow();
  const resp = await _accPostAwait({ action: 'saveNewPaymentRequest', sheetId: PAYMENT_SHEET_ID, tab: 'PaymentRequest', row: row });

  if (!resp || resp.success === false) {
    if (btn) { btn.disabled = false; btn.textContent = 'Submit Payment Request'; }
    const msg = (resp && resp.message) || 'unknown error';
    if (/unknown (post )?action/i.test(msg)) {
      alert('Apps Script redeploy required.\n\nThis build adds the "saveNewPaymentRequest" backend action (AccountsHandlers.gs + Router.gs), but the live Apps Script /exec has not been redeployed yet. Ask the admin to redeploy, then try again.');
    } else {
      alert('Could not save the payment request:\n\n' + msg);
    }
    return;
  }

  try { await _accPRUploadAttachments(row['UUID'], resp.requestId || ''); }
  catch (e) { console.warn('Accounts: attachment upload failed', e); }

  _accToast('✅ Payment request submitted' + (resp.requestId ? (' — ' + resp.requestId) : ''));
  _accCloseNewPR();
  // (classic list retired — re-render the Workspace below)
  renderAccountsWorkspace();
}

// ══════════════════════════════════════════════════════════════
//  ACCOUNTS — PAYMENT VOUCHER VIEW + STATUS UPDATES (Phase 2)
//  Centered modal styled as a printable payment voucher: payee, bank,
//  particulars, amount in figures + words, PO/bill reference, the
//  AccountsUpdate status history, and all role-gated action buttons.
// ══════════════════════════════════════════════════════════════

// Indian-system amount-in-words (crore/lakh/thousand) for the voucher.
function _accAmountWords(n) {
  n = Math.round(Math.abs(+n || 0));
  if (!n) return 'Zero';
  const ones = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten',
    'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen', 'Seventeen', 'Eighteen', 'Nineteen'];
  const tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
  const two = (x) => x < 20 ? ones[x] : (tens[Math.floor(x / 10)] + (x % 10 ? ' ' + ones[x % 10] : ''));
  const three = (x) => (x >= 100 ? ones[Math.floor(x / 100)] + ' Hundred' + (x % 100 ? ' ' + two(x % 100) : '') : two(x));
  let out = '';
  const crore = Math.floor(n / 10000000); n %= 10000000;
  const lakh  = Math.floor(n / 100000);   n %= 100000;
  const thou  = Math.floor(n / 1000);      n %= 1000;
  if (crore) out += three(crore) + ' Crore ';
  if (lakh)  out += three(lakh) + ' Lakh ';
  if (thou)  out += three(thou) + ' Thousand ';
  if (n)     out += three(n);
  return out.trim();
}

function _accClosePRDetail() {
  if (_accEscHandler) { document.removeEventListener('keydown', _accEscHandler); _accEscHandler = null; }
  const ov = document.getElementById('accVoucherOverlay');
  if (ov) { ov.style.opacity = '0'; setTimeout(() => { try { ov.remove(); } catch (e) {} }, 200); }
}

// Print / Save-as-PDF the open voucher as a proper document — branded logo header,
// the voucher body (minus the in-app dark header/buttons), and a signature footer.
function _accPrintVoucher() {
  const card = document.getElementById('accVoucherCard');
  if (!card) return;
  const logoEl = document.querySelector('.header-logo');
  const logo = logoEl ? logoEl.src : '';
  const row = (window._accAllRows || []).find(r => r.uuid === window._accDetailUuid) || {};
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const reqId = esc(row.requestId || '');
  const company = esc(row.company || 'Evergreen Enterprises');
  // Clone the body, drop the in-app dark header (first child), action bar and buttons.
  const clone = card.cloneNode(true);
  if (clone.firstElementChild) clone.firstElementChild.remove();
  clone.querySelectorAll('#acc-detail-actions, button').forEach(el => el.remove());
  const body = clone.innerHTML;
  const now = evgFmtDateTime(new Date());

  const w = window.open('', '_blank', 'width=900,height=1000');
  if (!w) { alert('Allow pop-ups for this site to print the voucher.'); return; }
  w.document.write(
    '<!doctype html><html><head><meta charset="utf-8"><title>Payment Voucher' + (reqId ? ' — ' + reqId : '') + '</title><style>'
    + '@page{margin:14mm}'
    + 'body{font-family:system-ui,-apple-system,Arial,sans-serif;margin:0;color:#1f2937;background:#fff;font-size:12px}'
    + 'button{display:none!important} *{box-shadow:none!important} table{border-collapse:collapse;width:100%}'
    + '.pv-head{display:flex;align-items:center;gap:14px;border-bottom:2px solid #1a6038;padding-bottom:10px;margin-bottom:14px}'
    + '.pv-head img{height:48px;width:auto;border-radius:6px}'
    + '.pv-head .t1{font-size:16px;font-weight:800;color:#1a6038;letter-spacing:.04em}'
    + '.pv-head .t2{font-size:12px;color:#6b7280;margin-top:1px}'
    + '.pv-head .r{margin-left:auto;text-align:right;font-size:11px;color:#374151}'
    + '.pv-foot{margin-top:24px;border-top:1px solid #d1d5db;padding-top:12px}'
    + '.pv-sign{display:flex;justify-content:space-between;gap:24px;margin-top:34px}'
    + '.pv-sign div{flex:1;text-align:center;border-top:1px solid #9ca3af;padding-top:5px;font-size:11px;color:#374151}'
    + '.pv-meta{font-size:10px;color:#9ca3af;text-align:center;margin-top:16px}'
    + '</style></head><body>'
    + '<div class="pv-head">'
    + (logo ? '<img src="' + logo + '" alt="logo">' : '')
    + '<div><div class="t1">' + company.toUpperCase() + '</div><div class="t2">Payment Voucher</div></div>'
    + '<div class="r">' + (reqId ? '<div><b>' + reqId + '</b></div>' : '') + '<div>Printed: ' + now + '</div></div>'
    + '</div>'
    + body
    + '<div class="pv-foot"><div class="pv-sign"><div>Prepared By</div><div>Verified By</div><div>Approved By</div></div>'
    + '<div class="pv-meta">System-generated payment voucher · EVGCPL Portal · ' + now + '</div></div>'
    + '</body><scr' + 'ipt>window.onload=function(){setTimeout(function(){window.print();},350);};</scr' + 'ipt></html>'
  );
  w.document.close();
}

// Format a date value as a long, human date — "28 May 2026".
// Handles GViz "Date(2026,4,28)" (month 0-based), ISO, and dd/mm/yyyy strings.
function _accFmtLongDate(v) {
  if (!v) return '';
  // Accept a Date object directly — stringifying it would otherwise fall through
  // every parser below and return the raw "Tue Jun 16 2026 … GMT+0530" toString.
  if (v instanceof Date) return isNaN(v.getTime()) ? '' : v.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });
  const s = String(v).trim();
  let d = null;
  if (/^Date\(\d+,\d+,\d+/.test(s)) {
    d = parseGvizDate(s);
  } else if (/^\d{4}-\d{2}-\d{2}/.test(s)) {
    d = new Date(s);
  } else {
    const m = s.match(/^(\d{1,2})[\/\-.](\d{1,2})[\/\-.](\d{2,4})$/);
    if (m) { let y = +m[3]; if (y < 100) y += 2000; d = new Date(y, +m[2] - 1, +m[1]); }
  }
  if (!d || isNaN(d.getTime()) || d.getFullYear() < 1971) return s;
  return d.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });
}
let _accEscHandler = null;

// ══════════════════════════════════════════════════════════════════════════
//  Accounts arrangements (table columns · voucher fields · voucher blocks)
//  Resolution priority:  personal localStorage  →  system default (PortalConfig
//  sheet)  →  compiled default.  Admins can push the current arrangement to the
//  PortalConfig sheet so it becomes the org-wide default for everyone.
// ══════════════════════════════════════════════════════════════════════════
function _accMergeCfg(saved, defs) {
  if (!Array.isArray(saved) || !saved.length) return defs.map(d => ({ key: d.key, enabled: d.on !== false }));
  const known = new Set(defs.map(d => d.key));
  const cfg = saved.filter(s => known.has(s.key)).map(s => ({ key: s.key, enabled: s.enabled !== false }));
  const seen = new Set(cfg.map(c => c.key));
  defs.forEach(d => { if (!seen.has(d.key)) cfg.push({ key: d.key, enabled: d.on !== false }); });
  return cfg;
}
function _accReadCfg(lsKey, sheetKey, defs) {
  let saved = null;
  try { saved = JSON.parse(localStorage.getItem(lsKey) || 'null'); } catch (e) {}
  if ((!Array.isArray(saved) || !saved.length) && sheetKey && window._SHEET_CONFIG && window._SHEET_CONFIG[sheetKey]) {
    try { saved = JSON.parse(window._SHEET_CONFIG[sheetKey]); } catch (e) {}
  }
  return _accMergeCfg(saved, defs);
}
function _accReadModalList(listId) {
  const list = document.getElementById(listId); if (!list) return [];
  return [...list.querySelectorAll('li')].map(li => ({
    key: li.dataset.key,
    enabled: !!(li.querySelector('input[type=checkbox]') || {}).checked,
  }));
}
// (_accIsAdmin is defined once, later in this file — the canonical version.)
// Footer button (admin only) that pushes the modal's current arrangement to the sheet.
function _accDefaultBtn(sheetKey, listId) {
  if (!_accIsAdmin()) return '';
  return `<button onclick="_accSetSystemDefault('${sheetKey}','${listId}',this)" class="btn btn-secondary btn-sm" title="Make this arrangement the org-wide default for everyone" style="font-size:.74rem">&#9733; Set as system default</button>`;
}
async function _accSetSystemDefault(sheetKey, listId, btn) {
  if (typeof _accCan === 'function' && !_accCan('setDefault')) { alert('You do not have permission to change the system default.'); return; }
  const value = _accReadModalList(listId);
  if (!value.length) return;
  let writeUrl = '';
  for (const k of ['portalConfig', 'pcc', 'main']) {
    const u = (typeof getExec === 'function') ? getExec(k) : '';
    if (u && /^https:\/\/script\.google\.com\/macros\//.test(u)) { writeUrl = u; break; }
  }
  if (!writeUrl) { alert('No PortalConfig backend URL is configured. Set it under Dev Mode → Portal Config Backend.'); return; }
  const prev = btn ? btn.innerHTML : '';
  if (btn) { btn.disabled = true; btn.textContent = 'Saving…'; }
  try {
    const email = (STATE && STATE.user && STATE.user.email) || 'unknown';
    const res = await fetch(writeUrl, {
      method: 'POST', headers: { 'Content-Type': 'text/plain' },
      body: JSON.stringify({ action: 'savePortalConfig', key: sheetKey, value: JSON.stringify(value), updatedBy: email }),
    });
    const data = await res.json();
    if (data && data.success) {
      window._SHEET_CONFIG = window._SHEET_CONFIG || {};
      window._SHEET_CONFIG[sheetKey] = JSON.stringify(value);
      if (btn) { btn.innerHTML = '&#10003; Saved as default'; btn.style.background = '#16a34a'; btn.style.color = '#fff'; btn.style.borderColor = '#16a34a'; }
    } else {
      if (btn) { btn.disabled = false; btn.innerHTML = prev; }
      alert('Could not save system default: ' + ((data && data.message) || 'unknown error'));
    }
  } catch (e) {
    if (btn) { btn.disabled = false; btn.innerHTML = prev; }
    alert('Error saving system default: ' + e.message);
  }
}

