// ── Global Accounts search — searches the whole DB (all stages) and opens the voucher ──
function _accGlobalSearch(q) {
  const box = document.getElementById('accGlobalSearchResults'); if (!box) return;
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const term = String(q || '').toLowerCase().trim();
  if (term.length < 2) { box.style.display = 'none'; box.innerHTML = ''; return; }
  const all = (window._accAllRows || []).filter(r => r._s && r._s.includes(term));
  if (!all.length) {
    box.innerHTML = '<div style="padding:.7rem .9rem;color:var(--txt3);font-size:.82rem">No matching payments</div>';
    box.style.display = 'block'; return;
  }
  const hits = all.slice(0, 15);
  const payee = (r) => (typeof _accStripCode === 'function' ? _accStripCode(r.paidTo) : r.paidTo) || r.payTo || '';
  box.innerHTML = hits.map(r => {
    const st = r.status || {};
    return `<div onmousedown="event.preventDefault();_accGlobalSearchOpen('${(r.uuid || '').replace(/'/g, "\\'")}')"
        style="padding:.5rem .9rem;border-bottom:1px solid var(--border);cursor:pointer;display:flex;align-items:center;gap:.6rem"
        onmouseover="this.style.background='var(--surface2)'" onmouseout="this.style.background=''">
        <span style="font-family:monospace;font-size:.74rem;color:var(--g8);font-weight:700;min-width:78px">${esc(r.requestId) || '—'}</span>
        <span style="flex:1;font-size:.8rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(payee(r)) || '—'}${r.site ? ` &middot; ${esc(r.site)}` : ''}</span>
        <span style="font-size:.76rem;font-weight:700;color:var(--g8);white-space:nowrap">${r.amount ? '&#8377;' + Math.round(r.amount).toLocaleString('en-IN') : ''}</span>
        ${st.label ? `<span style="font-size:.63rem;color:${st.color};white-space:nowrap;max-width:130px;overflow:hidden;text-overflow:ellipsis">${esc(st.label)}</span>` : ''}
      </div>`;
  }).join('') + (all.length > 15 ? `<div style="padding:.4rem .9rem;color:var(--txt3);font-size:.72rem">Showing first 15 of ${all.length}…</div>` : '');
  box.style.display = 'block';
}
function _accGlobalSearchOpen(uuid) {
  const box = document.getElementById('accGlobalSearchResults'); if (box) box.style.display = 'none';
  const inp = document.getElementById('accGlobalSearch'); if (inp) inp.blur();
  _accOpenPRDetail(uuid);
}

function _accOpenPRDetail(uuid) {
  if (!uuid) return;
  window._accDetailUuid = uuid;
  const row = (window._accAllRows || []).find(r => r.uuid === uuid)
           || ((typeof _mdpRows !== 'undefined' && _mdpRows) ? _mdpRows.find(r => r.uuid === uuid) : null);
  if (!row) return;
  let ov = document.getElementById('accVoucherOverlay');
  if (!ov) {
    ov = document.createElement('div');
    ov.id = 'accVoucherOverlay';
    ov.style.cssText = 'position:fixed;inset:0;z-index:1200;background:rgba(15,23,42,.55);display:flex;align-items:flex-start;justify-content:center;padding:3vh 2vw;overflow-y:auto;opacity:0;transition:opacity .2s ease';
    ov.onclick = (e) => { if (e.target === ov) _accClosePRDetail(); };
    document.body.appendChild(ov);
  }
  ov.innerHTML = `<div id="accVoucherCard" style="background:#fff;width:840px;max-width:100%;border-radius:14px;box-shadow:0 20px 60px rgba(0,0,0,.35);display:flex;flex-direction:column;overflow:hidden;margin:auto"></div>`;
  _accDrawPRDetail(document.getElementById('accVoucherCard'), row);
  requestAnimationFrame(() => { ov.style.opacity = '1'; });
  // Close on Esc (single global handler, cleaned up on close)
  if (_accEscHandler) document.removeEventListener('keydown', _accEscHandler);
  _accEscHandler = (e) => {
    if (e.key !== 'Escape') return;
    e.preventDefault();
    const fa = document.getElementById('accFieldArranger');
    if (fa) { fa.remove(); return; }   // close arranger first, keep voucher open
    _accClosePRDetail();
  };
  document.addEventListener('keydown', _accEscHandler);
  // Status Updates + documents + role-gated action bar load asynchronously
  _accDrawStatusUpdates(uuid);
  _accDrawPRAttachments(row);
  _accRenderDetailActions(row);
  _accDrawPOItems(row);
  _accDrawVendorStatus(row);
}

// Fill the voucher's vendor bill-status chip (Payable/Settled/Advance + net
// balance) from the Vendor Ledger (PO). Lazily loads ledger data if needed.
function _accDrawVendorStatus(r) {
  const slot = document.getElementById('acc-detail-vendorstatus');
  if (!slot || !r || r.payTo !== 'Vendor') return;
  const vid = (typeof _vplpResolveVid === 'function') ? _vplpResolveVid(r) : '';
  const link = `<a href="#" onclick="event.preventDefault();event.stopPropagation();_accOpenVendorLedger('${String(vid).replace(/'/g, "\\'")}')" title="Open this vendor's ledger (PO · Dr/Cr running balance)" style="margin-left:.55rem;font-size:.72rem;font-weight:700;color:var(--g7);white-space:nowrap;text-decoration:none">&#128210; View Ledger &rarr;</a>`;
  const paint = () => { try { const chip = (typeof _vplpStatusChipFor === 'function') ? _vplpStatusChipFor(r, { showBal: true }) : ''; slot.innerHTML = chip + link; } catch (e) { slot.innerHTML = link; } };
  if (typeof _vplpData !== 'undefined' && _vplpData) { paint(); return; }
  if (typeof _vplpEnsure === 'function') _vplpEnsure().then(paint).catch(() => { slot.innerHTML = link; });
  else slot.innerHTML = link;
}
// Jump from a vendor payment voucher straight to that vendor's PO ledger.
window._accOpenVendorLedger = function(vid) {
  if (typeof _accClosePRDetail === 'function') { try { _accClosePRDetail(); } catch (e) {} }
  if (typeof _vplpOpenVendor === 'function') _vplpOpenVendor(vid || '');
  else if (typeof navigate === 'function') navigate('vendor-ledger-po');
};

// Whole-tab cache for PO_Items_Actual (the items tab keys to a request via its
// CheckSum column). gviz WHERE only works on column letters, and CheckSum's
// letter isn't known here, so we fetch once and filter client-side by label.
let _poItemsCache = null;
let _poItemsCacheAt = 0;
async function _accLoadPOItems() {
  if (_poItemsCache && (Date.now() - _poItemsCacheAt) < 300000) return _poItemsCache;
  const lk = (typeof getLink === 'function') ? getLink('PO_ITEMS') : { id: PO_SHEET_ID, tab: 'PO_Items_Actual' };
  const tab = lk.tab || 'PO_Items_Actual', sid = lk.id || PO_SHEET_ID;
  let rows = await fetchSheet(tab, 'SELECT *', sid);
  if (!rows || !rows.length) {            // one retry — gviz can transiently time out
    await new Promise(r => setTimeout(r, 800));
    rows = await fetchSheet(tab, 'SELECT *', sid);
  }
  if (rows && rows.length) { _poItemsCache = rows; _poItemsCacheAt = Date.now(); }
  return _poItemsCache || [];
}

// Load PO line items (item / qty / rate / amount) for this request from the
// Purchase workbook (PO_Items_Actual tab), matched on the request's Link =
// the item row's CheckSum. Falls back to PO No / Order No if Link is empty.
// Column names are resolved defensively since the live tab schema isn't
// mirrored in code yet.
function _accDrawPOItems(r) {
  const el = document.getElementById('acc-detail-poitems');
  if (!el || !r) return;
  const linkKey  = String(r.link || '').trim().toLowerCase();
  const orderKey = String(r.orderNo || '').trim().toLowerCase();
  if (!linkKey && !orderKey) return;
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const onMatch = (x) => {
    const cs = (x['CheckSum'] || x['Checksum'] || x['CheckSum '] || '').toString().trim().toLowerCase();
    if (linkKey && cs && cs === linkKey) return true;
    if (!linkKey && orderKey) {
      const po = (x['PO No'] || x['Order No'] || x['E'] || '').toString().trim().toLowerCase();
      return po === orderKey;
    }
    return false;
  };
  el.innerHTML = '<div style="padding:.6rem;color:var(--txt3);font-size:.8rem">Loading PO items…</div>';
  _accLoadPOItems()
    .then(all => {
      const rows = (all || []).filter(onMatch);
      if (!rows.length) {
        const by = linkKey ? `Link ${esc(r.link)}` : `Order ${esc(r.orderNo)}`;
        el.innerHTML = `<div style="padding:.6rem;color:var(--txt3);font-size:.8rem">No PO line items found (matched on ${by}).</div>`;
        return;
      }
      const pick = (x, keys) => { for (const k of keys) { if (x[k] != null && String(x[k]).trim() !== '') return String(x[k]).trim(); } return ''; };
      const fmtN = v => { const n = parseFloat(String(v).replace(/[^0-9.\-]/g, '')); return isNaN(n) ? '' : n.toLocaleString('en-IN'); };
      // The readable item text lives in "Material Description" ("PartNo | Description");
      // the "Part Details" column is just a CheckSum key. Build the same CheckSum →
      // Material Description map Open PO uses so a raw key still resolves to text.
      const norm = (typeof _opNorm === 'function') ? _opNorm : (s => String(s == null ? '' : s).trim().toLowerCase());
      const matMap = {};
      rows.forEach(x => { const k = norm(pick(x, ['Part Details', 'Part Description'])); if (!k || matMap[k]) return; const md = pick(x, ['Material Description', 'Material Desc', 'Material Name', 'Material']); if (md) matMap[k] = md; });
      const readable = raw => (typeof _opPartReadable === 'function') ? _opPartReadable(raw, matMap).text : String(raw || '');
      let grand = 0;
      const body = rows.map((x, i) => {
        // Prefer the readable Material Description; only fall back to the Part Details
        // CheckSum, which readable()/matMap then resolve to text (never the bare key).
        const rawDesc = pick(x, ['Material Description', 'Material Desc', 'Item Name', 'Item Description', 'Material Name', 'Material', 'Description', 'Particulars', 'Item']) || pick(x, ['Part Details', 'Part Description']);
        const desc = readable(rawDesc);
        const unit = pick(x, ['Unit', 'UOM', 'Units']);
        const qty  = pick(x, ['Qty', 'Quantity', 'PO Qty', 'Order Qty', 'Quantity Ordered']);
        const rate = pick(x, ['Rate', 'Unit Rate', 'Unit Price', 'Price', 'Basic Rate']);
        const amt  = pick(x, ['Amount', 'Line Amount', 'Net Amount', 'Value', 'Total', 'Taxable Value']);
        if (!desc && !qty && !rate && !amt) return '';
        const an = parseFloat(String(amt).replace(/[^0-9.\-]/g, '')); if (!isNaN(an)) grand += an;
        const c = 'padding:6px 9px;border:1px solid var(--border)';
        return `<tr>
          <td style="${c};color:var(--txt3)">${i + 1}</td>
          <td style="${c}">${esc(desc) || '—'}</td>
          <td style="${c};text-align:right">${qty ? esc(fmtN(qty) + (unit ? ' ' + unit : '')) : '—'}</td>
          <td style="${c};text-align:right">${rate ? '&#8377;' + fmtN(rate) : '—'}</td>
          <td style="${c};text-align:right">${amt ? '&#8377;' + fmtN(amt) : '—'}</td>
        </tr>`;
      }).join('');
      if (!body) {
        el.innerHTML = `<div style="padding:.6rem;color:var(--txt3);font-size:.8rem">PO record found, but no recognizable item columns (item / qty / rate). Share the PO tab's header row and I'll map them precisely.</div>`;
        return;
      }
      const h = 'text-align:left;padding:6px 9px;border:1px solid var(--border);font-size:.7rem;color:var(--txt3)';
      el.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:.76rem">
        <thead><tr style="background:#f1f5f9">
          <th style="${h};width:34px">#</th><th style="${h}">Item / Description</th>
          <th style="${h};text-align:right">Qty</th><th style="${h};text-align:right">Rate</th>
          <th style="${h};text-align:right">Amount</th>
        </tr></thead><tbody>${body}</tbody>
        ${grand ? `<tfoot><tr style="font-weight:700;background:#f1f5f9">
          <td colspan="4" style="padding:6px 9px;border:1px solid var(--border);text-align:right">Total</td>
          <td style="padding:6px 9px;border:1px solid var(--border);text-align:right">&#8377;${grand.toLocaleString('en-IN')}</td>
        </tr></tfoot>` : ''}
      </table>`;
    })
    .catch(() => { el.innerHTML = `<div style="padding:.6rem;color:var(--txt3);font-size:.8rem">Could not load PO items.</div>`; });
}

function _accDrawPRDetail(dr, r) {
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const s = r.status || { label: '', icon: '', color: '#6b7280', bg: '#f9fafb' };
  const fmtAmt = (v, c) => { if (!v) return '—'; const n = Math.round(v).toLocaleString('en-IN'); return (c && c !== 'INR') ? (c + ' ' + n) : ('₹' + n); };

  const payee = (typeof _mdpStrip === 'function') ? (_mdpStrip(r.paidTo) || r.vendor || r.payTo) : (r.paidTo || r.payTo);

  const badge = s.label
    ? `<span style="display:inline-flex;align-items:center;gap:4px;background:${s.bg};color:${s.color};padding:4px 12px;border-radius:12px;font-size:.74rem;font-weight:600;border:1px solid ${s.color}22">${s.icon ? s.icon + '&thinsp;' : ''}${esc(s.label)}</span>`
    : '<span style="color:var(--txt3)">—</span>';

  const meta = (label, val) => `<div style="display:flex;gap:.4rem;font-size:.74rem"><span style="color:var(--txt3);min-width:96px">${label}</span><span style="font-weight:600;color:var(--txt1)">${esc(val) || '—'}</span></div>`;
  const partRow = (label, val) => val ? `<tr><td style="padding:6px 11px;border:1px solid var(--border);color:var(--txt3);font-size:.72rem;width:42%;vertical-align:top">${label}</td><td style="padding:6px 11px;border:1px solid var(--border);font-size:.8rem;color:var(--txt1)">${esc(val)}</td></tr>` : '';
  const words = r.amount ? `${(r.currency && r.currency !== 'INR') ? r.currency : 'Rupees'} ${_accAmountWords(r.amount)} Only` : '';

  const fieldsHtml = (pairs) => `
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:.55rem 1.4rem">
      ${pairs.filter(p => p).map(([label, val]) => `
        <div style="display:flex;flex-direction:column;gap:2px;min-width:0">
          <span style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.04em">${label}</span>
          <span style="font-size:.82rem;color:var(--txt1);word-break:break-word">${esc(val) || '—'}</span>
        </div>`).join('')}
    </div>`;
  const block = (title, inner) => `
    <div style="margin-bottom:1.1rem">
      <div style="font-weight:700;font-size:.74rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.55rem;border-bottom:1px solid var(--border);padding-bottom:.3rem">${title}</div>
      ${inner}
    </div>`;

  // ── Previous Payments — prior payment requests booked against this same Order No ──
  const _ppCellHead = 'text-align:left;padding:6px 9px;border:1px solid var(--border);font-size:.7rem;color:var(--txt3)';
  const _ppCell = 'padding:6px 9px;border:1px solid var(--border)';
  let prevPaysHtml = '';
  if (r.orderNo) {
    const key = String(r.orderNo).trim().toLowerCase();
    const prev = (window._accAllRows || [])
      .filter(p => p.orderNo && String(p.orderNo).trim().toLowerCase() === key)
      .sort((a, b) => String(a.date).localeCompare(String(b.date)));
    const total = prev.reduce((s, p) => s + (p.amount || 0), 0);
    prevPaysHtml = `
      <div style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin:1rem 0 .45rem;border-top:1px solid var(--border);padding-top:.8rem">Previous Payments &middot; Order ${esc(r.orderNo)}</div>
      ${prev.length ? `
      <table style="width:100%;border-collapse:collapse;margin-bottom:1rem;font-size:.76rem">
        <thead><tr style="background:#f1f5f9">
          <th style="${_ppCellHead}">Request ID</th><th style="${_ppCellHead}">Date</th>
          <th style="${_ppCellHead};text-align:right">Amount</th><th style="${_ppCellHead}">Status</th>
          <th style="${_ppCellHead}">Accounts Date</th>
        </tr></thead>
        <tbody>
          ${prev.map(p => {
            const cur = p.uuid === r.uuid;
            const st = p.status || {};
            return `<tr style="${cur ? 'background:#fffbeb;font-weight:700' : ''}">
              <td style="${_ppCell};font-family:monospace">${esc(p.requestId) || '—'}${cur ? ' &#9664;' : ''}</td>
              <td style="${_ppCell}">${esc(p.date) || '—'}</td>
              <td style="${_ppCell};text-align:right">${fmtAmt(p.amount, p.currency)}</td>
              <td style="${_ppCell}">${st.label ? `<span style="color:${st.color}">${esc(st.label)}</span>` : '—'}</td>
              <td style="${_ppCell}">${esc(_accFmtLongDate(p.accDate)) || '—'}</td>
            </tr>`;
          }).join('')}
        </tbody>
        <tfoot><tr style="font-weight:700;background:#f1f5f9">
          <td colspan="2" style="${_ppCell};text-align:right">Total against this Order</td>
          <td style="${_ppCell};text-align:right">${fmtAmt(total, r.currency)}</td>
          <td colspan="2" style="${_ppCell}"></td>
        </tr></tfoot>
      </table>` : `<div style="padding:.7rem;color:var(--txt3);font-size:.8rem;margin-bottom:1rem">No other payment requests found against this Order No.</div>`}`;
  }

  // Each voucher section is a self-contained block; order + visibility come from
  // the (drag-arrangeable) block config. Async blocks keep their container ids.
  const _vblocks = {
    requestDetails: `
      <div style="border:1px solid var(--border);border-radius:10px;background:var(--surface1);margin-bottom:1rem;overflow:hidden">
        <div style="background:var(--g9);color:#fff;padding:.4rem .9rem;font-size:.64rem;font-weight:700;text-transform:uppercase;letter-spacing:.06em">Request Details</div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:.5rem 1.6rem;padding:.85rem 1rem">
          <div style="min-width:0">
            <div style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.04em">Payee</div>
            <div style="display:flex;align-items:center;gap:.45rem;flex-wrap:wrap;margin-top:2px">
              <span style="font-size:1rem;font-weight:700;color:var(--g8)">${esc(payee) || '—'}</span>
              ${r.payTo ? `<span style="font-size:.6rem;font-weight:700;padding:1px 7px;border-radius:9px;background:#e0e7ff;color:#4338ca">${esc(r.payTo)}</span>` : ''}
              ${r.payTo === 'Vendor' ? '<span id="acc-detail-vendorstatus" title="Vendor bill status from the Vendor Ledger (PO)"></span>' : ''}
            </div>
            <div style="font-size:.73rem;color:var(--txt2);margin-top:2px">${esc(r.site)}${r.site && r.entity ? ' &middot; ' : ''}${esc(r.entity)}</div>
          </div>
          <div style="display:flex;flex-direction:column;gap:3px;justify-content:center">
            ${meta('Initiator', r.initiator)}
            ${meta('Department', r.dept)}
            ${meta('Manual / Auto', r.manualAuto)}
            ${r.installment > 1 ? meta('Installment', r.installment) : ''}
          </div>
          ${(r.nature || r.narrative) ? `<div style="grid-column:1/-1;border-top:1px solid var(--border);padding-top:.5rem;display:flex;flex-direction:column;gap:3px">
            ${r.nature ? `<div style="font-size:.78rem;color:var(--txt1)"><span style="color:var(--txt3);font-weight:600">Nature:&nbsp;</span>${esc(r.nature)}</div>` : ''}
            ${r.narrative ? `<div style="font-size:.78rem;color:var(--txt2)"><span style="color:var(--txt3);font-weight:600">Narrative:&nbsp;</span>${esc(r.narrative)}</div>` : ''}
          </div>` : ''}
        </div>
      </div>`,
    amount: `
      <div style="display:flex;align-items:center;justify-content:space-between;gap:1rem;flex-wrap:wrap;padding:.85rem 1.1rem;border:1px solid var(--g7);border-radius:10px;background:#f0fdf4;margin-bottom:1rem">
        <div style="min-width:0">
          <div style="font-size:.66rem;font-weight:700;color:var(--txt3);text-transform:uppercase;letter-spacing:.04em">Amount</div>
          ${words ? `<div style="font-size:.8rem;color:var(--txt2);margin-top:3px;font-style:italic">${esc(words)}</div>` : ''}
        </div>
        <div style="font-size:1.5rem;font-weight:800;color:var(--g8);white-space:nowrap">${fmtAmt(r.amount, r.currency)}</div>
      </div>`,
    particulars: `
      <div style="margin-bottom:1rem">
        <div style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.45rem">Particulars</div>
        <table style="width:100%;border-collapse:collapse">
          ${partRow('Nature of Expenses', r.nature)}
          ${partRow('Account Code Description', r.accCode)}
          ${partRow('Cost Code', r.costCode)}
          ${partRow('From Which Process', r.process)}
          ${partRow('Narrative / Comments', r.narrative)}
        </table>
      </div>`,
    billPo: `
      <div style="margin-bottom:1rem">
        <div style="display:flex;align-items:center;justify-content:space-between;gap:.5rem;margin-bottom:.45rem">
          <span style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em">Bill &amp; PO Reference</span>
          <button onclick="event.stopPropagation();_accArrangeOrderFields()" title="Drag &amp; drop to arrange these fields" style="background:none;border:1px solid var(--border);border-radius:6px;color:var(--txt2);cursor:pointer;font-size:.66rem;padding:2px 8px;white-space:nowrap">&#9881; Arrange</button>
        </div>
        <table style="width:100%;border-collapse:collapse">
          ${_accOrderFieldRows(r, partRow, fmtAmt)}
        </table>
      </div>`,
    bank: `
      <div style="margin-bottom:1rem">
        <div style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.45rem">Bank Details</div>
        <table style="width:100%;border-collapse:collapse">
          ${partRow('A/C Holder', r.acHolder)}
          ${partRow('A/C Number', r.acNumber)}
          ${partRow('IFSC Code', r.ifsc)}
          ${partRow('Bank Name', r.bank)}
        </table>
      </div>`,
    poItems: (r.link || r.orderNo) ? `
      <div style="margin-bottom:1rem">
        <div style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.45rem">PO Items${r.orderNo ? ' &middot; ' + esc(r.orderNo) : ''}</div>
        <div id="acc-detail-poitems"><div style="padding:.7rem;color:var(--txt3);font-size:.8rem">&#8987; Loading PO items&hellip;</div></div>
      </div>` : '',
    prevPayments: prevPaysHtml,
    accounts: (r.accStatus || r.utr || r.remarks) ? `
      <div style="margin-bottom:1rem">
        <div style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.45rem">Accounts Processing</div>
        <table style="width:100%;border-collapse:collapse">
          ${partRow('Accounts Status', r.accStatus)}
          ${partRow('Accounts Date', _accFmtLongDate(r.accDate))}
          ${partRow('UTR Details', r.utr)}
          ${partRow('Remarks', r.remarks)}
        </table>
      </div>` : '',
    documents: `
      <div style="margin-bottom:1rem">
        <div style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.45rem;border-top:1px solid var(--border);padding-top:.8rem">&#128206; Documents</div>
        <div id="acc-detail-docs"><div style="padding:.8rem;text-align:center;color:var(--txt3);font-size:.8rem">&#8987; Loading documents&hellip;</div></div>
      </div>`,
    statusUpdates: `
      <div>
        <div style="font-weight:700;font-size:.72rem;color:var(--g8);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.45rem;border-top:1px solid var(--border);padding-top:.8rem">Status Updates</div>
        <div id="acc-detail-timeline"><div style="padding:1rem;text-align:center;color:var(--txt3);font-size:.8rem">&#8987; Loading status history&hellip;</div></div>
      </div>`,
  };
  // Width hints: billPo + bank render half-width so they pair side-by-side when
  // adjacent (and grow to full width if alone). Everything else spans full width.
  // Order + visibility still come from the drag-arrangeable block config.
  const _vbHalf = { billPo: true, bank: true };
  const _vbodyHtml = _accGetVoucherBlockCfg().filter(c => c.enabled).map(c => {
    const html = _vblocks[c.key] || '';
    if (!html.trim()) return '';
    const basis = _vbHalf[c.key] ? 'flex:1 1 calc(50% - .5rem);min-width:260px' : 'flex:1 1 100%;min-width:0';
    return `<div style="${basis}">${html}</div>`;
  }).join('');

  dr.innerHTML = `
    <div style="padding:1rem 1.4rem;border-bottom:2px solid var(--g7);display:flex;align-items:flex-start;justify-content:space-between;gap:1rem;background:linear-gradient(135deg,var(--g9),var(--g7));color:#fff;flex-shrink:0">
      <div style="min-width:0">
        <div style="font-size:.7rem;letter-spacing:.14em;text-transform:uppercase;opacity:.8">${esc(r.company) || 'EVGCPL'}</div>
        <div style="font-size:1.1rem;font-weight:800;letter-spacing:.03em;margin-top:1px">PAYMENT VOUCHER</div>
        <div style="margin-top:.5rem">${badge}</div>
      </div>
      <div style="text-align:right;flex-shrink:0">
        <div style="font-family:monospace;font-size:1rem;font-weight:700">${esc(r.requestId) || esc(r.uuid)}</div>
        <div style="font-size:.74rem;opacity:.9;margin-top:2px">${esc(r.date) || '—'}</div>
        ${r.accDate ? `<div style="font-size:.72rem;opacity:.95;margin-top:3px;background:rgba(255,255,255,.18);padding:2px 9px;border-radius:8px;display:inline-block">Accounts Date&nbsp;&middot;&nbsp;<b>${esc(_accFmtLongDate(r.accDate))}</b></div>` : ''}
        <button onclick="event.stopPropagation();_accPrintVoucher()" title="Print / Save as PDF" style="margin-top:.5rem;margin-right:.4rem;background:rgba(255,255,255,.18);border:none;color:#fff;width:28px;height:28px;border-radius:7px;cursor:pointer;font-size:.9rem">&#128424;</button>
        <button onclick="_accClosePRDetail()" style="margin-top:.5rem;background:rgba(255,255,255,.18);border:none;color:#fff;width:28px;height:28px;border-radius:7px;cursor:pointer;font-size:.95rem">&#10006;</button>
      </div>
    </div>

    <div style="flex:1;overflow-y:auto;padding:1.1rem 1.4rem;max-height:74vh">
      <div id="acc-detail-actions"></div>
      <div style="display:flex;justify-content:flex-end;margin-bottom:.6rem">
        <button onclick="_accArrangeBlocks()" title="Drag &amp; drop to rearrange voucher sections" style="background:none;border:1px solid var(--border);border-radius:6px;color:var(--txt2);cursor:pointer;font-size:.68rem;padding:3px 10px;white-space:nowrap">&#9881; Layout</button>
      </div>
      <div style="display:flex;flex-wrap:wrap;align-items:flex-start;gap:0 1rem">${_vbodyHtml}</div>
    </div>
  `;
}

// Surface the PR's Drive documents as openable links. Attachments live in a
// Shared Drive named by the request's Link code (and sometimes Bill/Order No),
// so we search by those keys rather than a per-PR folder.
async function _accDrawPRAttachments(r) {
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const el = () => document.getElementById('acc-detail-docs');
  if (!el()) return;

  const keys = [r.link, r.orderNo].map(k => String(k || '').trim()).filter(k => k.length >= 4);
  if (!keys.length) {
    el().innerHTML = '<div style="padding:.7rem;color:var(--txt3);font-size:.78rem">No Link / Order No on this request to search documents by.</div>';
    return;
  }

  let resp;
  try {
    resp = await _accPostAwait({ action: 'listPRAttachments', link: r.link || '', orderNo: r.orderNo || '' });
  } catch (e) {
    resp = { success: false, message: e.message };
  }
  if (!el()) return; // user switched PRs while loading
  if (!resp || resp.success === false) {
    const msg = (resp && resp.message) || 'unknown error';
    if (/unknown (post )?action/i.test(msg)) {
      el().innerHTML = '<div style="padding:.7rem;color:var(--txt3);font-size:.76rem">Document search needs an Apps Script redeploy (adds the "listPRAttachments" action).</div>';
    } else if (/failed to fetch|could not reach/i.test(msg)) {
      el().innerHTML = '<div style="padding:.7rem;color:var(--danger);font-size:.76rem">&#9888; Backend unreachable. Check the Accounts Apps Script is deployed with access set to <b>Anyone</b>.</div>';
    } else {
      el().innerHTML = `<div style="padding:.7rem;color:var(--danger);font-size:.76rem">&#9888; Could not load documents: ${esc(msg)}</div>`;
    }
    return;
  }
  const files = resp.files || [];
  if (!files.length) {
    el().innerHTML = `<div style="padding:.7rem;color:var(--txt3);font-size:.78rem">No documents found for this request.<br><span style="font-size:.7rem">Searched by: ${keys.map(k => esc(k)).join(', ')}</span></div>`;
    return;
  }
  const iconFor = (mime, name) => {
    const n = (name || '').toLowerCase();
    if (/pdf/.test(mime) || n.endsWith('.pdf')) return '&#128196;';
    if (/image/.test(mime) || /\.(png|jpe?g|gif|webp|bmp)$/.test(n)) return '&#128247;';
    if (/sheet|excel|csv/.test(mime) || /\.(xlsx?|csv)$/.test(n)) return '&#128202;';
    if (/word|document/.test(mime) || /\.(docx?)$/.test(n)) return '&#128221;';
    return '&#128206;';
  };
  const fmtSize = (b) => {
    b = +b || 0;
    if (!b) return '';
    if (b < 1024) return b + ' B';
    if (b < 1048576) return (b / 1024).toFixed(0) + ' KB';
    return (b / 1048576).toFixed(1) + ' MB';
  };
  el().innerHTML = `<div style="display:flex;flex-direction:column;gap:.4rem">
    ${files.map(f => `
      <a href="${esc(f.url)}" target="_blank" rel="noopener"
         style="display:flex;align-items:center;gap:.6rem;padding:.5rem .7rem;border:1px solid var(--border);border-radius:9px;background:var(--surface1);text-decoration:none;color:var(--txt1)">
        <span style="font-size:1.1rem">${iconFor(f.mimeType, f.name)}</span>
        <span style="flex:1;min-width:0;font-size:.8rem;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(f.name)}</span>
        ${f.matchedOn ? `<span style="font-size:.62rem;color:var(--txt3);background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:1px 6px;white-space:nowrap" title="Matched on">${esc(f.matchedOn)}</span>` : ''}
        <span style="font-size:.68rem;color:var(--txt3);white-space:nowrap">${fmtSize(f.size)}</span>
        <span style="font-size:.72rem;color:var(--g7);font-weight:700;white-space:nowrap">Open &#8599;</span>
      </a>`).join('')}
  </div>`;
}

const _ACC_MON_ABBR = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
// Parse a stored timestamp (DD/MM/YYYY HH:MM:SS, ISO, or gviz Date(...)) → ms.
function _accTsVal(s) {
  if (!s) return 0;
  s = String(s).trim();
  let m = s.match(/Date\((\d+),(\d+),(\d+)(?:,(\d+),(\d+),(\d+))?\)/);
  if (m) return new Date(+m[1], +m[2], +m[3], +(m[4]||0), +(m[5]||0), +(m[6]||0)).getTime();
  m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(?:[ T](\d{1,2}):(\d{2})(?::(\d{2}))?)?/);
  if (m) return new Date(+m[3], +m[2]-1, +m[1], +(m[4]||0), +(m[5]||0), +(m[6]||0)).getTime();
  const t = Date.parse(s);
  return isNaN(t) ? 0 : t;
}
// Display a stored timestamp as "01Jan2026 13:47:38" (long date + time).
function _accFmtTs(s) {
  const v = _accTsVal(s);
  if (!v) return String(s || '—');
  const d = new Date(v), p = n => String(n).padStart(2, '0');
  return p(d.getDate()) + _ACC_MON_ABBR[d.getMonth()] + d.getFullYear() + ' ' + p(d.getHours()) + ':' + p(d.getMinutes()) + ':' + p(d.getSeconds());
}

async function _accDrawStatusUpdates(uuid) {
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const el = () => document.getElementById('acc-detail-timeline');
  let rows;
  try {
    rows = await fetchSheet('AccountsUpdate', null, PAYMENT_SHEET_ID);
  } catch (e) {
    if (el()) el().innerHTML = '<div style="padding:1rem;color:var(--danger);font-size:.8rem">&#9888; Could not load status history. Check the AccountsUpdate tab is shared as Anyone &rarr; Viewer.</div>';
    return;
  }
  // Guard against a stale timeline if the user opened another PR meanwhile
  if (!el()) return;

  const get = (r, keys) => { for (const k of keys) { if (r[k] != null && r[k] !== '') return r[k]; } return ''; };
  const updates = (rows || [])
    .filter(r => get(r, ['Request ID', 'RequestID', 'Request Id']) === uuid)
    .map(r => ({
      ts:       get(r, ['Timestamp', 'TimeStamp']),
      date:     get(r, ['Date']),
      by:       get(r, ['Updated By', 'UpdatedBy']),
      status:   get(r, ['Status', 'Accounts Status']),
      utr:      get(r, ['UTR Details', 'UTR']),
      comments: get(r, ['Comments (If Any)', 'Comments', 'Comments If Any']),
      reason:   get(r, ['Pending Reason', 'PendingReason']),
    }))
    .sort((a, b) => _accTsVal(b.ts || b.date) - _accTsVal(a.ts || a.date)); // newest first

  if (!updates.length) {
    el().innerHTML = '<div style="padding:1rem;text-align:center;color:var(--txt3);font-size:.8rem">No status updates recorded yet.</div>';
    return;
  }

  const th = (t, extra='') => `<th style="padding:7px 10px;font-size:.68rem;font-weight:700;text-align:left;white-space:nowrap;${extra}">${t}</th>`;
  const body = updates.map(u => {
    const st = (typeof getPayStatus === 'function') ? getPayStatus(u.status) : { label: u.status, icon: '', color: '#6b7280', bg: '#f9fafb' };
    const pill = st.label
      ? `<span style="display:inline-flex;align-items:center;gap:3px;background:${st.bg};color:${st.color};padding:2px 9px;border-radius:10px;font-size:.68rem;font-weight:600;border:1px solid ${st.color}22">${st.icon ? st.icon + '&thinsp;' : ''}${esc(st.label)}</span>`
      : `<span style="font-size:.72rem;color:var(--txt2)">${esc(u.status) || '—'}</span>`;
    const who = (typeof _accStripCode === 'function' ? _accStripCode(u.by) : u.by) || '—';
    const details = [
      u.utr ? 'UTR: ' + esc(u.utr) : '',
      u.reason ? 'Reason: ' + esc(u.reason) : '',
      u.comments ? esc(u.comments) : '',
    ].filter(Boolean).join(' · ') || '—';
    return `<tr style="border-bottom:1px solid var(--border)">
      <td style="padding:6px 10px;font-size:.72rem;white-space:nowrap;color:var(--txt2)">${esc(_accFmtTs(u.ts || u.date))}</td>
      <td style="padding:6px 10px;font-size:.74rem;font-weight:600">${esc(who)}</td>
      <td style="padding:6px 10px">${pill}</td>
      <td style="padding:6px 10px;font-size:.72rem;color:var(--txt2);white-space:pre-wrap">${details}</td>
    </tr>`;
  }).join('');
  el().innerHTML = `<div style="overflow-x:auto;border:1px solid var(--border);border-radius:8px">
    <table style="width:100%;border-collapse:collapse">
      <thead><tr style="background:var(--g9);color:#fff">${th('When')}${th('Who Did It')}${th('Status Passed Along')}${th('Details')}</tr></thead>
      <tbody>${body}</tbody>
    </table>
  </div>`;
}

// ══════════════════════════════════════════════════════════════
//  ACCOUNTS — ACCOUNTS UPDATE FORM (Phase 3)
//  Role-gated status changes. Every change is a NEW row in the
//  AccountsUpdate tab — existing rows are never modified.
// ══════════════════════════════════════════════════════════════
let _accPayStatusMaster = null;   // [{ status, viewFor, role }]

async function _accLoadPaymentStatusMaster() {
  if (_accPayStatusMaster !== null) return;
  // The status-options tab has been seen under a few names — try each.
  const tabs = ['Payment_Status', 'M21_Payment_Status', 'Payment Status', 'PaymentStatus', 'M21_Payment_status'];
  for (const tab of tabs) {
    try {
      const rows = await fetchSheet(tab, null, PAYMENT_SHEET_ID);
      const mapped = (rows || []).map(r => ({
        status:  r['Accounts Status'] || r['Status'] || '',
        viewFor: r['View for'] || r['View For'] || r['ViewFor'] || '',
        role:    r['Role'] || '',
      })).filter(r => r.status);
      if (mapped.length) { _accPayStatusMaster = mapped; return; }
    } catch (e) { /* try the next candidate */ }
  }
  _accPayStatusMaster = [];
}

// Is the current user allowed to post accounts updates?
// Admin = full override (MD role OR an admin/owner email): the Update Status
// quick action shows on EVERY request, at any stage.
function _accIsAdmin() {
  if ((STATE.role || '').toLowerCase() === 'md') return true;
  const e = (STATE.user?.email || '').toLowerCase();
  return e.includes('admin@evgcpl') || e.includes('neurolooom');
}
// Current statuses representing an MD/admin action — Accounts is LOCKED OUT of
// updating a request sitting at one of these (per the Accounts/Admin matrix).
// Anything NOT listed here is Accounts-updatable (Verified→MD, Payment
// Initiated / Re-Initiated, Payment Completed, Pending Due to Queries,
// Pending With Accounts, Reject Payment (Accounts), and new/blank rows).
const ACC_ADMIN_ONLY_STATUSES = new Set([
  'process payment, move to accounts',
  'reject payment (md)',
  'hold payment (md)',
  'on hold by md',
  'payment on hold by md',
  'paid (md_ed)',
  'send back to accounts (md)',
  'sent back to accounts',
  'send back to respective department (md)',
  'sent back to dept (md)',
]);
function _accCanUpdate(r) {
  if (_accIsAdmin()) return true;                       // admin/MD: every stage
  const role = (STATE.role || '').toLowerCase();
  const isAcc = role === 'accounts' ||
                (role === 'dept_head' && /finance|account/i.test(STATE.deptHeadDept || ''));
  if (!isAcc) return false;
  if (!r) return true;
  // Accounts: restricted — no Update button on MD/admin-action statuses.
  const lbl = (((r.status && r.status.label) || '')).toLowerCase().replace(/\s*,\s*/g, ', ').trim();
  return !ACC_ADMIN_ONLY_STATUSES.has(lbl);
}

// Status values this user may SET — from Payment_Status master, with a
// role-based fallback (handoff §5) if the master is empty or unmatched.
function _accAllowedStatuses() {
  const role = (STATE.role || '').toLowerCase();
  const dept = (STATE.deptHeadDept || '').toLowerCase().trim();
  const isFinance = role === 'accounts' || (role === 'dept_head' && /finance|account/.test(dept));

  const fromMaster = (_accPayStatusMaster || []).filter(r => {
    const vf = (r.viewFor || '').toLowerCase().trim();
    const rl = (r.role || '').toLowerCase().trim();
    if (rl && rl === role) return true;
    if (vf && dept && vf === dept) return true;
    if (vf && isFinance && /finance|account/.test(vf)) return true;
    if (rl && isFinance && /account/.test(rl)) return true;
    return false;
  }).map(r => r.status);

  const uniq = [...new Set(fromMaster.filter(Boolean))];
  if (uniq.length) return uniq;

  // Fallback — derived from the documented role matrix (strings the
  // portal's status map recognises, so they categorise/colour correctly).
  if (role === 'md') {
    return ['Process Payment, Move to Accounts', 'Hold Payment (MD)',
            'Send Back to Accounts (MD)', 'Send Back to Respective Department (MD)',
            'Reject Payment (MD)', 'Paid (MD_ED)'];
  }
  return ['Verified, Move to MD Queue', 'Pending Due to Queries', 'Payment Initiated',
          'Paid (Initiated in Bank)', 'Payment Completed', 'Reject Payment (Accounts)'];
}

function _accRenderDetailActions(r) {
  const host = document.getElementById('acc-detail-actions');
  if (!host) return;
  const stageDef = _accViewById(_accStageOf(r));
  const canUpd = _accCanUpdate(r);
  const canAdv = _accCanAdvance(stageDef);
  if (!canUpd && !canAdv) { host.innerHTML = ''; return; }
  const uuid = (r.uuid || '').replace(/'/g, "\\'");
  host.innerHTML = `
    <div style="display:flex;gap:.6rem;align-items:center;margin-bottom:1rem;flex-wrap:wrap">
      ${canAdv ? `<button onclick="_accAdvance('${uuid}')" class="btn btn-sm" style="background:#16a34a;color:#fff;border:none;font-weight:700">&#10003; ${stageDef.next.actionLabel||stageDef.next.to} &rarr;</button>` : ''}
      ${canUpd ? `<button onclick="_accToggleUpdateForm('${uuid}')" class="btn btn-primary btn-sm">&#9998; Update Status</button>` : ''}
      <span style="font-size:.72rem;color:var(--txt3)">${canAdv ? 'Quick action: ' + (stageDef.next.actionLabel||stageDef.next.to) + ', or post a custom update' : 'Post a verification, approval, payment or rejection update'}</span>
    </div>
    <div id="acc-detail-updateform"></div>`;
}

async function _accToggleUpdateForm(uuid) {
  const box = document.getElementById('acc-detail-updateform');
  if (!box) return;
  if (box.dataset.open === '1') { box.innerHTML = ''; box.dataset.open = '0'; return; }
  box.dataset.open = '1';
  // If the options are already cached, draw immediately — never block on a fetch
  // (which could be stuck behind an in-flight sync POST).
  if (_accPayStatusMaster !== null) { _accDrawUpdateForm(box, uuid); return; }
  box.innerHTML = '<div style="padding:.8rem;color:var(--txt3);font-size:.8rem">&#8987; Loading status options…</div>';
  await _accLoadPaymentStatusMaster();
  if (box.dataset.open === '1') _accDrawUpdateForm(box, uuid);
}

function _accDrawUpdateForm(box, uuid) {
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const today = new Date().toLocaleDateString('en-CA');
  const statuses = _accAllowedStatuses();
  const opts = '<option value=""></option>' + statuses.map(s => `<option value="${esc(s)}">${esc(s)}</option>`).join('');
  const reasons = ['Wrong A/C Number', 'Ledger Mismatch', 'Benificery Pending'];

  box.innerHTML = `
    <div class="evg-form" style="border:1px solid var(--border);border-radius:10px;padding:.9rem 1rem;margin-bottom:1rem;background:var(--surface1)">
      <div style="display:flex;flex-direction:column;gap:3px;margin-bottom:.6rem">
        <label style="font-size:.71rem;font-weight:600;color:var(--txt2)">New Status <span style="color:var(--danger)">*</span></label>
        <select id="acc-up-status" onchange="_accUpdateFormOnStatusChange()">${opts}</select>
      </div>
      <div id="acc-up-reason-wrap" style="display:none;flex-direction:column;gap:3px;margin-bottom:.6rem">
        <label style="font-size:.71rem;font-weight:600;color:var(--txt2)">Pending Reason <span style="color:var(--danger)">*</span></label>
        <select id="acc-up-reason"><option value=""></option>${reasons.map(r => `<option value="${esc(r)}">${esc(r)}</option>`).join('')}</select>
      </div>
      <div id="acc-up-utr-wrap" style="display:none;flex-direction:column;gap:3px;margin-bottom:.6rem">
        <label style="font-size:.71rem;font-weight:600;color:var(--txt2)">UTR Details <span style="color:var(--danger)">*</span></label>
        <input id="acc-up-utr" placeholder="Bank UTR / transaction reference">
      </div>
      <div id="acc-up-comments-wrap" style="display:flex;flex-direction:column;gap:3px;margin-bottom:.6rem">
        <label style="font-size:.71rem;font-weight:600;color:var(--txt2)">Comments <span id="acc-up-comments-req" style="color:var(--danger);display:none">*</span></label>
        <textarea id="acc-up-comments" rows="2" style="resize:vertical"></textarea>
      </div>
      <div style="display:flex;flex-direction:column;gap:3px;margin-bottom:.8rem">
        <label style="font-size:.71rem;font-weight:600;color:var(--txt2)">Date</label>
        <input id="acc-up-date" type="date" value="${today}">
      </div>
      <div style="display:flex;gap:.6rem;justify-content:flex-end">
        <button onclick="_accToggleUpdateForm('${(uuid || '').replace(/'/g, "\\'")}')" class="btn btn-secondary btn-sm">Cancel</button>
        <button id="acc-up-submit" onclick="_accUpdateFormSubmit('${(uuid || '').replace(/'/g, "\\'")}')" class="btn btn-primary btn-sm">Save Update</button>
      </div>
    </div>`;
}

function _accUpdateFormOnStatusChange() {
  const st = (document.getElementById('acc-up-status') || {}).value || '';
  const norm = st.toLowerCase().trim();
  const show = (id, on) => { const e = document.getElementById(id); if (e) e.style.display = on ? 'flex' : 'none'; };
  show('acc-up-reason-wrap', /pending due to queries/.test(norm));
  show('acc-up-utr-wrap', /payment completed/.test(norm));
  const reqComments = /reject/.test(norm);
  const rq = document.getElementById('acc-up-comments-req');
  if (rq) rq.style.display = reqComments ? '' : 'none';
}

// Single source of truth for the AccountsUpdate sheet row shape — used by both
// write paths (the Update form and the quick status/approve/reject actions) so
// they can never drift apart. `f` supplies the variable fields; the identity /
// timestamp / request-details columns are filled here.
function _accBuildUpdateRow(reqUuid, f) {
  const rid = (crypto && crypto.randomUUID) ? crypto.randomUUID().slice(0, 8) : String(Date.now()).slice(-8);
  const email = STATE.user?.email || '';
  const me = (STATE.masters.users || []).find(u => (u.email || '').toLowerCase() === email.toLowerCase());
  const updatedBy = me ? (me.employeeRef || me.name) : (STATE.user?.name || '');
  const pr = (window._accAllRows || []).find(r => r.uuid === reqUuid);
  const details = pr ? [pr.requestId, pr.payTo, pr.amount].filter(Boolean).join(' · ') : reqUuid;
  const uuid = 'ACC-AU-' + rid;
  return {
    'UUID': uuid,
    // Stable idempotency key for this write. Built once with the row, so the
    // v4.11.2 transient-retry re-posts the SAME key — the backend dedupes on it
    // (see docs/APPS_SCRIPT_accounts-write-fix.md), making retries / lost-ack
    // re-posts safe (no duplicate AccountsUpdate row). Defaults to the row UUID.
    'DedupeKey': f.dedupeKey || uuid,
    'UserEmail': email,
    'Updated By': updatedBy,
    'Request ID': reqUuid,
    'Details of Request': details,
    'Status': f.status,
    'Pending Reason': f.reason || '',
    'Date': f.date,
    'UTR Details': f.utr || '',
    'Comments (If Any)': f.comments || '',
    'Timestamp': _accFmtDateTime(new Date()),
  };
}
function _accUpdateBuildRow(prUuid) {
  return _accBuildUpdateRow(prUuid, {
    status: _accV('acc-up-status'),
    reason: _accV('acc-up-reason'),
    date: _accFmtDate(_accV('acc-up-date')),
    utr: _accV('acc-up-utr'),
    comments: _accV('acc-up-comments'),
  });
}

async function _accUpdateFormSubmit(prUuid) {
  const status = _accV('acc-up-status');
  const norm = status.toLowerCase().trim();
  const errors = [];
  if (!status) errors.push('Please choose a status.');
  if (/pending due to queries/.test(norm) && !_accV('acc-up-reason')) errors.push('Pending Reason is required.');
  if (/payment completed/.test(norm) && !_accV('acc-up-utr')) errors.push('UTR Details are required to complete a payment.');
  if (/reject/.test(norm) && !_accV('acc-up-comments')) errors.push('Comments are required when rejecting.');
  if (status && !_accCanSetStatus(status)) errors.push('You are not authorised to set the status “' + status + '”.');
  if (errors.length) { alert('Please fix the following:\n\n• ' + errors.join('\n• ')); return; }

  const btn = document.getElementById('acc-up-submit');
  if (btn) { btn.disabled = true; btn.textContent = 'Saving…'; }

  const row = _accUpdateBuildRow(prUuid);
  const resp = await _accPostAwait({ action: 'saveAccountsUpdate', sheetId: PAYMENT_SHEET_ID, tab: 'AccountsUpdate', row: row });

  if (!resp || resp.success === false) {
    if (btn) { btn.disabled = false; btn.textContent = 'Save Update'; }
    const msg = (resp && resp.message) || 'unknown error';
    if (/unknown (post )?action/i.test(msg)) {
      alert('Apps Script redeploy required.\n\nThe "saveAccountsUpdate" backend action is in this build but the live Apps Script /exec has not been redeployed yet. Ask the admin to redeploy, then try again.');
    } else {
      alert('Could not save the update:\n\n' + msg);
    }
    return;
  }

  _accToast('✅ Status update posted');
  // Park it in the In-Transaction shelf so it leaves the queue immediately;
  // the auto-poll clears it once the sheet's derived status catches up.
  _txnParkRow((window._accAllRows || []).find(r => r.uuid === prUuid), status, 'Updated', 'acc');
  if (typeof accRender === 'function' && document.getElementById('accTbody')) accRender();
  const box = document.getElementById('acc-detail-updateform');
  if (box) { box.innerHTML = ''; box.dataset.open = '0'; }
  // Refresh the timeline so the new entry shows immediately. The list's
  // derived status (col AL) is a sheet formula, so it reflects on the next
  // list refresh; the drawer stays open on the updated PR.
  _accDrawStatusUpdates(prUuid);
}

// ══════════════════════════════════════════════════════════════
//  ACCOUNTS — MD APPROVAL QUEUE (Phase 4)
//  "Pending My Approval" = PRs whose latest status is
//  "Verified, Move to MD Queue". MD can approve/reject inline.
// ══════════════════════════════════════════════════════════════
const ACC_MD_QUEUE_LABEL = 'Verified, Move to MD Queue';

function _accIsMDQueue(r) {
  const lbl = s => (typeof getPayStatus === 'function') ? getPayStatus(s).label : '';
  return lbl(r.rawStatus) === ACC_MD_QUEUE_LABEL || lbl(r.accStatus) === ACC_MD_QUEUE_LABEL;
}

// Navigate to the Accounts page with the MD-approval filter pre-selected.
function _accGotoMDQueue() {
  window._accPendingMDFilter = true;
  navigate('accounts');
}

// Group-access gate for Accounts write actions. True when the user holds the
// given action on ANY accounts surface (md/admin always true; when enforcement
// is off, userCan returns true → unchanged behaviour).
function _accCan(action) {
  if (typeof userCan !== 'function') return true;
  return ['accounts','accounts-v2','accounts-worklist','accounts-dashboard','md-payments'].some(rt => userCan(rt, action));
}

// ── Per-status update access (Accounts) ──────────────────────────────────
// Admins can restrict individual status transitions to specific PEOPLE (by
// email or name) and/or roles, via Configuration → Status Access. Stored in
// PortalConfig key 'acc_status_access' = { '<statusLabel>': {users:[],roles:[]} }.
// A status with no rule (or an empty rule) is unrestricted → normal role checks
// apply. Super-admins are never blocked (they configure the rules).
const ACC_STATUS_ACCESS = [
  { status: 'Verified, Move to MD Queue',        label: 'Move to MD Queue',               desc: 'Accounts verifies a request and moves it to the MD approval queue.' },
  { status: 'Process Payment, Move to Accounts', label: 'Approve — Proceed with Payment',  desc: 'MD approves a request; it moves to Accounts to process payment.' },
  { status: 'Payment Initiated',                 label: 'Initiate Payment (in bank)',      desc: 'Mark the payment as initiated in the bank.' },
  { status: 'Paid (MD_ED)',                      label: 'Bank Transaction Completed',      desc: 'Confirm the bank transaction is completed.' },
  { status: 'Payment Completed',                 label: 'Update UTR / Complete',           desc: 'Final completion of the payment (with UTR).' },
  { status: 'Reject Payment (MD)',               label: 'Reject Payment',                  desc: 'Reject a payment request.' },
  { status: 'GRN Approved',                      label: 'GRN Review — Approve / Edit',     desc: 'Accounts reviews a received GRN StockIN line (may edit rate + additional charges) and approves it into the ledger.' },
];
function _accStatusAccessCfg() { return (typeof pcReadJSON === 'function' ? (pcReadJSON('acc_status_access', {}) || {}) : {}); }
function _accStatusRule(status) {
  const r = _accStatusAccessCfg()[status];
  if (!r) return null;
  const users = (r.users || []).map(x => String(x || '').trim()).filter(Boolean);
  const roles = (r.roles || []).map(x => String(x || '').trim()).filter(Boolean);
  return (users.length || roles.length) ? { users, roles } : null;
}
// Can the current user set this status? true when unrestricted or allowed.
function _accCanSetStatus(status) {
  const rule = _accStatusRule(status);
  if (!rule) return true;                                   // no restriction on this status
  if (typeof _accessIsSuperAdmin === 'function' && _accessIsSuperAdmin()) return true;
  const me = (typeof STATE !== 'undefined' && STATE.user) || {};
  const norm = s => String(s == null ? '' : s).toLowerCase().trim();
  const mine = [norm(me.email), norm(me.name), norm(me.employeeRef), norm(me.empCode)].filter(Boolean);
  const userMatch = rule.users.some(u => mine.includes(norm(u)));
  const roleMatch = rule.roles.map(norm).includes(norm(typeof STATE !== 'undefined' && STATE.role));
  return userMatch || roleMatch;
}

async function _accQuickStatus(uuid, status, comments, utr, silent, dedupeKey) {
  // Central write-path gate: a user with no Accounts action permission cannot
  // post status/advance updates when group access is enforced.
  if (!_accCan('update') && !_accCan('advance') && !_accCan('verify') && !_accCan('approve')) {
    if (!silent) _accToast('🔒 You do not have permission to update payments.');
    return false;
  }
  // Per-status people/role restriction (Configuration → Status Access).
  if (!_accCanSetStatus(status)) {
    window._accLastQuickErr = 'Not authorised to set status: ' + status;
    if (!silent) _accToast('🔒 You are not authorised to set “' + status + '”.');
    return false;
  }
  // Build the row ONCE (stable UUID + DedupeKey) so the retry loop below re-posts
  // the identical idempotency key; the backend dedupes on it.
  const row = _accBuildUpdateRow(uuid, { status, date: _accFmtDate(new Date()), utr, comments, dedupeKey });
  // Google Apps Script intermittently returns "Service Spreadsheets timed out
  // while accessing document …" (and lock/quota/deadline blips) when the
  // PaymentRequest workbook is busy. These are transient: the same row (stable
  // UUID) can be safely re-posted — the worst case is a duplicate update row
  // with the identical status, so the request still ends up Approved/Rejected.
  // Retry a few times with backoff before giving up, so a single timeout no
  // longer bounces the approval back to the queue.
  const TRANSIENT = /tim(e|ed)\s*out|timeout|service spreadsheets|spreadsheet.*(busy|access)|try again|lock(ed)?|deadline|rate.?limit|too many|quota|exceeded|temporar|unavailable|503|429/i;
  const MAX = 4;
  let resp = null, msg = 'unknown error';
  for (let attempt = 1; attempt <= MAX; attempt++) {
    if (attempt > 1) await new Promise(r => setTimeout(r, 1200 * (attempt - 1) + Math.floor(Math.random() * 400)));
    try { resp = await _accPostAwait({ action: 'saveAccountsUpdate', sheetId: PAYMENT_SHEET_ID, tab: 'AccountsUpdate', row: row }); }
    catch (e) { resp = { success: false, message: String(e && e.message || e) }; }
    if (resp && resp.success !== false) return true;          // success
    msg = (resp && resp.message) || 'unknown error';
    if (!TRANSIENT.test(msg)) break;                          // permanent error → don't retry
    if (!silent && attempt < MAX) _accToast('Sheets busy — retrying (' + attempt + '/' + (MAX - 1) + ')…');
  }
  {
    if (silent) { window._accLastQuickErr = msg; return false; }
    if (/unknown (post )?action/i.test(msg)) {
      alert('Apps Script redeploy required.\n\nThe "saveAccountsUpdate" backend action is in the deployed build but the live Apps Script /exec has not been redeployed yet.');
    } else if (TRANSIENT.test(msg)) {
      alert('Google Sheets was busy and kept timing out after several retries.\n\nThe request is back in your queue — please try again in a minute.\n\nDetails: ' + msg);
    } else {
      alert('Could not post the update:\n\n' + msg);
    }
    return false;
  }
}

async function _accQuickApprove(uuid) {
  if (!confirm('Approve this payment request and move it to Accounts for processing?')) return;
  const status = 'Process Payment, Move to Accounts';
  if (await _accQuickStatus(uuid, status, '', '', false, uuid + '|' + status)) {
    _txnParkRow((window._accAllRows || []).find(r => r.uuid === uuid), status, 'Approved', 'acc');
    _accToast('Approval submitted — confirming on Sheets…');
    if (typeof accRender === 'function') accRender();
  }
}

async function _accQuickReject(uuid) {
  const reason = prompt('Reason for rejection (required):', '');
  if (reason === null) return;
  if (!reason.trim()) { alert('A reason is required to reject.'); return; }
  const status = 'Reject Payment (MD)';
  if (await _accQuickStatus(uuid, status, reason.trim(), '', false, uuid + '|' + status)) {
    _txnParkRow((window._accAllRows || []).find(r => r.uuid === uuid), status, 'Rejected', 'acc');
    _accToast('Rejection submitted — confirming on Sheets…');
    if (typeof accRender === 'function') accRender();
  }
}

// ══════════════════════════════════════════════════
//  DEV MODE PAGE
// ══════════════════════════════════════════════════
// ══════════════════════════════════════════════════════════════
//  PORTAL CONFIGURATION — replaces Dev Mode page
//  All settings stored in localStorage → survive refresh
//  ROLE_ROUTES are rebuilt from config on every load
// ══════════════════════════════════════════════════════════════

// v2 → bumped May 2026 when Planning section restructured to Budgeting + Execution.
// Old config keys with 'planning' / 'project-setup' / 'md-command' entries are obsolete.
const CONFIG_KEY = 'evgcpl_portal_config_v2';
const LEGACY_CONFIG_KEYS = ['evgcpl_portal_config']; // cleared on first load

// ════════════════════════════════════════════════════════════════
//  EXPENSE LEDGER (route 'expense-ledger') — site cash-expense ledger from the
//  Expenses spreadsheet (EXPENSE_SHEET_ID). The `Cash For` column splits it
//  into two views: "Other Expenses" and "Site Mess Expenses". Source tabs:
//   • CashExpenseMonth — monthly per-site ledger (Opening/Initiated/Paid/Closing,
//     Ledger Status Open|Closed).
//   • Ledger — the line-item bills (Expense Head / Sub-Head / Amount / Status).
//  Pending = a month whose Ledger Status is not "Closed".
// ════════════════════════════════════════════════════════════════
// Tree model: payment request (Cash Expenses, "Cash-N") → its bills (Ledger rows
// with the same Request ID) → the approval trail (Cash Expenses - Approval).
// Tree model: a monthly per-site ledger entry (CashExpenseMonth) is the top
// node; its UUID (the "MCE-site|Cash For|period" composite) is what the bills
// (Ledger) and the cash requests (Cash Expenses) carry as their CheckSum. So
// each month node links to: its payment requests + its bills, by CheckSum=UUID.
let _expLedData = null;
let _expLedView = 'Other Expenses';     // 'Other Expenses' | 'Mess Expenses'
let _expLedSite = '';
let _expLedOpen = new Set();            // expanded month UUIDs
function _expNum(v) { const n = parseFloat(String(v == null ? '' : v).replace(/[^0-9.\-]/g, '')); return isNaN(n) ? 0 : n; }
function _expFmt(n) { return '₹' + Math.round(n || 0).toLocaleString('en-IN'); }
function _expName(v) { v = String(v || ''); return v.includes('|') ? v.split('|').pop().trim() : v; } // "EG123|NAME" → NAME
function _expGroup(arr, key) { const m = new Map(); (arr || []).forEach(x => { const k = x[key]; if (!k) return; if (!m.has(k)) m.set(k, []); m.get(k).push(x); }); return m; }
function _expLedEnsure() {
  if (_expLedData) return Promise.resolve(_expLedData);
  return Promise.all([
    fetchSheet('CashExpenseMonth',         null, EXPENSE_SHEET_ID, { rawId: true, headers: 1 }),
    fetchSheet('Cash Expenses',            null, EXPENSE_SHEET_ID, { rawId: true, headers: 1 }),
    fetchSheet('Ledger',                   null, EXPENSE_SHEET_ID, { rawId: true, headers: 1 }),
  ]).then(([months, reqs, bills]) => {
    const M = (months || []).filter(r => r['UUID']).map(r => ({
      uuid: r['UUID'] || '', requestId: r['Request ID'] || '', site: r['Site Name'] || '', cashFor: r['Cash For'] || '',
      from: r['For the Period (From)'] || '', to: r['For the Period (To)'] || '',
      opening: _expNum(r['Opening Balance']), initiated: _expNum(r['Initiated']), paid: _expNum(r['Paid']),
      closing: _expNum(r['Closing Balance']), status: r['Ledger Status'] || '', monthYear: r['Month-Year'] || '', fy: r['Financial Year'] || '',
    }));
    const Q = (reqs || []).filter(r => r['CheckSum']).map(r => ({
      key: r['CheckSum'] || '', requestId: r['Request ID'] || '', cashFor: r['Cash For'] || '',
      headCount: r['Total Head count of Mess eligible members'] || '', fixedRate: r['Fixed rate/day for the site'] || '',
      eligible: _expNum(r['Eligible amount']), initiated: _expNum(r['Amount Initiated by HR']),
      from: r['For the Period (From)'] || '', to: r['For the Period (To)'] || '',
      payTo: _expName(r['Process Paymnet To'] || r['Process Payment To']), status: r['Status'] || '', stage: r['Stage'] || '',
      comments: r['Comments (If Any)'] || '',
    }));
    const B = (bills || []).filter(r => r['CheckSum']).map(r => ({
      key: r['CheckSum'] || '', requestId: r['Request ID'] || '', madeBy: _expName(r['Expense Made by']),
      spentUnder: r['Spent Under'] || '', date: r['Date of Expense'] || '', head: r['Expense Head'] || '',
      subHead: r['Expense Sub-Head'] || '', details: r['Details'] || '', amount: _expNum(r['Amount']), status: r['Status'] || '',
      bills: Array.from({ length: 10 }, (_, i) => r['Bill' + (i + 1)]).filter(u => u && /^https?:/i.test(u)),
    }));
    const billsByKey = _expGroup(B, 'key');
    _expLedData = {
      months: M, reqsByKey: _expGroup(Q, 'key'), billsByKey,
      meta: { monthRows: (months || []).length, reqRows: (reqs || []).length, billRows: (bills || []).length,
        other: M.filter(r => /other/i.test(r.cashFor)).length, mess: M.filter(r => /mess/i.test(r.cashFor)).length,
        linked: M.filter(r => (billsByKey.get(r.uuid) || []).length).length },
    };
    return _expLedData;
  });
}
function _expMonthPending(m) { return !/closed/i.test(m.status); }
function _expLedToggle(id) { id = String(id); if (_expLedOpen.has(id)) _expLedOpen.delete(id); else _expLedOpen.add(id); _expLedRenderBody(); }
function renderExpenseLedger() {
  const el = document.getElementById('mainContent');
  el.innerHTML = `
    <div class="page-header"><div class="page-header-row">
      <div><h1>&#129534; Expense Ledger</h1><p>Payment requests &rarr; bills &middot; Other Expenses &amp; Site Mess Expenses &middot; click a request to drill into its bills &amp; approvals</p></div>
      <button class="btn btn-secondary btn-sm" onclick="_expLedReload(this)">&#8635; Refresh</button>
    </div></div>
    <div id="expled-body"><div class="card card-pad" style="text-align:center;color:var(--txt3);padding:2.5rem">&#9203; Loading expense ledger&hellip;</div></div>`;
  _expLedEnsure().then(() => _expLedRenderBody()).catch(() => {
    const b = document.getElementById('expled-body');
    if (b) b.innerHTML = '<div class="card card-pad" style="color:var(--danger);padding:1.5rem">Could not load the expense ledger. Try Refresh.</div>';
  });
}
function _expLedReload(btn) { _expLedData = null; if (btn) btn.disabled = true; renderExpenseLedger(); }
function _expLedSetView(v) { _expLedView = v; _expLedRenderBody(); }
function _expLedSetSite(s) { _expLedSite = s; _expLedRenderBody(); }
function _expLedRenderBody() {
  const b = document.getElementById('expled-body'); if (!b || !_expLedData) return;
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const wantMess = /mess/i.test(_expLedView);
  const inView = _expLedData.months.filter(r => wantMess ? /mess/i.test(r.cashFor) : /other/i.test(r.cashFor));
  const sites = [...new Set(inView.map(r => r.site).filter(Boolean))].sort();
  const months = inView.filter(r => !_expLedSite || r.site === _expLedSite)
    .sort((a, b) => (b.monthYear || '').localeCompare(a.monthYear || '') || String(a.site).localeCompare(String(b.site)));
  const billsOf = mo => _expLedData.billsByKey.get(mo.uuid) || [];
  const reqsOf = mo => _expLedData.reqsByKey.get(mo.uuid) || [];
  const pend = months.filter(_expMonthPending);
  const totInit = months.reduce((s, r) => s + r.initiated, 0);
  const totBilled = months.reduce((s, r) => s + billsOf(r).reduce((t, x) => t + x.amount, 0), 0);
  const tab = (v, label) => `<button onclick="_expLedSetView('${v}')" class="btn btn-sm" style="${_expLedView === v ? 'background:var(--g7);color:#fff;border-color:var(--g7)' : ''}">${label}</button>`;
  const kpis = `<div class="evg-kpi-grid" style="margin-bottom:1rem">
    ${evgKpiCard({ icon: '🗓️', value: months.length.toLocaleString('en-IN'), label: _expLedView + ' — months' })}
    ${evgKpiCard({ icon: '⏳', value: pend.length.toLocaleString('en-IN'), label: 'Open', accent: pend.length ? '#c2410c' : undefined })}
    ${evgKpiCard({ icon: '💸', value: _expFmt(totInit), label: 'Initiated' })}
    ${evgKpiCard({ icon: '📑', value: _expFmt(totBilled), label: 'Billed' })}
  </div>`;
  const m = _expLedData.meta || {};
  const controls = `<div class="card" style="margin-bottom:.8rem"><div class="card-body" style="padding:.7rem 1rem;display:flex;gap:.7rem;flex-wrap:wrap;align-items:center">
    <div style="display:flex;gap:.4rem">${tab('Other Expenses', '🧾 Other Expenses')}${tab('Mess Expenses', '🍲 Site Mess Expenses')}</div>
    <span style="font-size:.68rem;color:var(--txt3)" title="Rows loaded from the Expenses sheet">${m.monthRows || 0} months (${m.other || 0} other / ${m.mess || 0} mess) · ${m.reqRows || 0} requests · ${m.billRows || 0} bills · ${m.linked || 0} linked</span>
    <span style="flex:1"></span>
    <label style="font-size:.72rem;color:var(--txt3);font-weight:700">SITE</label>
    <select onchange="_expLedSetSite(this.value)" style="font-size:.8rem;border:1px solid var(--border);border-radius:6px;padding:5px 8px;background:var(--surface2)"><option value="">All Sites</option>${sites.map(s => `<option ${s === _expLedSite ? 'selected' : ''}>${esc(s)}</option>`).join('')}</select>
  </div></div>`;
  const kv = (label, val) => (val || val === 0) ? `<div style="display:flex;flex-direction:column;gap:1px"><span style="font-size:.62rem;text-transform:uppercase;letter-spacing:.04em;color:var(--txt3);font-weight:700">${label}</span><span style="font-size:.82rem;color:var(--txt1)">${esc(val)}</span></div>` : '';
  const statusBadge = (txt, pending) => `<span style="background:${pending ? '#ffedd5' : '#dcfce7'};color:${pending ? '#c2410c' : '#15803d'};padding:2px 9px;border-radius:9px;font-size:.66rem;font-weight:700;border:1px solid ${pending ? '#fdba74' : 'transparent'};white-space:nowrap">${pending ? '● ' : ''}${esc(txt || (pending ? 'Open' : 'Closed'))}</span>`;
  const TH = 'padding:6px 8px;text-align:left;font-weight:600;font-size:.7rem;color:var(--txt2);border-bottom:1px solid var(--border);white-space:nowrap';
  const TD = 'padding:5px 8px;border-bottom:1px solid var(--border);font-size:.78rem;vertical-align:top';
  const nodes = months.map(mo => {
    const open = _expLedOpen.has(String(mo.uuid));
    const bills = billsOf(mo); const reqs = reqsOf(mo);
    const billed = bills.reduce((t, x) => t + x.amount, 0);
    const pending = _expMonthPending(mo);
    const head = `<div onclick="_expLedToggle('${String(mo.uuid).replace(/'/g, "\\'").replace(/"/g, '&quot;')}')" style="cursor:pointer;display:flex;align-items:center;gap:.7rem;padding:.65rem .9rem;${pending ? 'background:#fff7ed;' : ''}">
      <span style="color:var(--txt3);width:14px;flex-shrink:0">${open ? '▾' : '▸'}</span>
      <div style="min-width:0;flex:1;display:flex;align-items:center;gap:.6rem;flex-wrap:wrap">
        <b style="font-weight:700">${esc(mo.site) || '—'}</b>
        <span style="font-size:.74rem;color:var(--txt2)">${esc(mo.monthYear)}</span>
        <span style="font-size:.72rem;color:var(--txt3)">${esc(mo.from)}${mo.to ? ' – ' + esc(mo.to) : ''}</span>
      </div>
      <span style="font-size:.72rem;color:var(--txt3);white-space:nowrap">${reqs.length} req · ${bills.length} bill${bills.length === 1 ? '' : 's'}</span>
      <span style="font-weight:700;color:var(--g8);white-space:nowrap" title="Initiated">${_expFmt(mo.initiated)}</span>
      <span style="font-weight:700;white-space:nowrap;color:${mo.closing < 0 ? 'var(--danger)' : 'var(--txt2)'}" title="Closing balance">${_expFmt(mo.closing)}</span>
      ${statusBadge(mo.status, pending)}
    </div>`;
    if (!open) return `<div style="border-bottom:1px solid var(--border)">${head}</div>`;
    const details = `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(130px,1fr));gap:.7rem;padding:.8rem .9rem;background:var(--surface2);border-top:1px dashed var(--border)">
      ${kv('Cash For', mo.cashFor)}${kv('Opening', _expFmt(mo.opening))}${kv('Initiated', _expFmt(mo.initiated))}${kv('Paid', _expFmt(mo.paid))}
      ${kv('Billed', _expFmt(billed))}${kv('Closing', _expFmt(mo.closing))}${kv('Ledger Status', mo.status)}${kv('Period', (mo.from || '') + (mo.to ? ' – ' + mo.to : ''))}
    </div>`;
    const reqRows = reqs.map(q => `<tr>
      <td style="${TD};white-space:nowrap;font-family:monospace;color:var(--g8)">${esc(q.requestId)}</td>
      <td style="${TD};white-space:nowrap">${esc(q.payTo) || '—'}</td>
      <td style="${TD};white-space:nowrap;color:var(--txt2)">${esc(q.from)}${q.to ? ' – ' + esc(q.to) : ''}</td>
      <td style="${TD};text-align:center">${esc(q.headCount)}</td>
      <td style="${TD};text-align:right;white-space:nowrap;font-weight:600">${_expFmt(q.initiated)}</td>
      <td style="${TD}">${esc(q.status || q.stage)}</td>
    </tr>`).join('');
    const reqTbl = reqs.length ? `<div style="padding:.2rem .9rem .2rem">
      <div style="font-size:.7rem;font-weight:700;text-transform:uppercase;letter-spacing:.04em;color:var(--g8);margin:.5rem 0 .4rem">Payment requests (${reqs.length})</div>
      <table data-evg-defaults="off" style="width:100%;border-collapse:collapse;background:var(--surface1);border:1px solid var(--border);border-radius:8px;overflow:hidden">
        <thead><tr><th style="${TH}">Request</th><th style="${TH}">Pay To</th><th style="${TH}">Period</th><th style="${TH};text-align:center">Heads</th><th style="${TH};text-align:right">Initiated</th><th style="${TH}">Status</th></tr></thead>
        <tbody>${reqRows}</tbody>
      </table></div>` : '';
    const billRows = bills.map(x => `<tr>
      <td style="${TD};white-space:nowrap;color:var(--txt2)">${esc(x.date)}</td>
      <td style="${TD}">${esc(x.head) || '—'}${x.subHead ? `<div style="font-size:.68rem;color:var(--txt3)">${esc(x.subHead)}</div>` : ''}</td>
      <td style="${TD}">${esc(x.details) || '—'}</td>
      <td style="${TD};white-space:nowrap;color:var(--txt2)">${esc(x.madeBy)}</td>
      <td style="${TD};text-align:right;white-space:nowrap;font-weight:600">${_expFmt(x.amount)}</td>
      <td style="${TD}">${esc(x.status)}</td>
      <td style="${TD};white-space:nowrap">${x.bills.length ? x.bills.map((u, i) => `<a href="${esc(u)}" target="_blank" rel="noopener" style="color:var(--g7);font-size:.72rem;margin-right:.4rem">📎${i + 1}</a>`).join('') : '<span style="color:var(--txt3)">—</span>'}</td>
    </tr>`).join('');
    const billsTbl = `<div style="padding:.2rem .9rem .9rem">
      <div style="font-size:.7rem;font-weight:700;text-transform:uppercase;letter-spacing:.04em;color:var(--g8);margin:.6rem 0 .4rem">Bills (${bills.length}) &middot; total ${_expFmt(billed)}</div>
      <table data-evg-defaults="off" style="width:100%;border-collapse:collapse;background:var(--surface1);border:1px solid var(--border);border-radius:8px;overflow:hidden">
        <thead><tr><th style="${TH}">Date</th><th style="${TH}">Expense Head</th><th style="${TH}">Details</th><th style="${TH}">Made By</th><th style="${TH};text-align:right">Amount</th><th style="${TH}">Status</th><th style="${TH}">Bills</th></tr></thead>
        <tbody>${billRows || `<tr><td colspan="7" style="${TD};text-align:center;color:var(--txt3);padding:1rem">No bills recorded for this month yet.</td></tr>`}</tbody>
      </table></div>`;
    return `<div style="border-bottom:1px solid var(--border)">${head}${details}${reqTbl}${billsTbl}</div>`;
  }).join('');
  const empty = m.monthRows
    ? `<div style="text-align:center;padding:3rem;color:var(--txt3)">No ${esc(_expLedView)}${_expLedSite ? ' for ' + esc(_expLedSite) : ''}.<div style="font-size:.74rem;margin-top:.5rem">Loaded ${m.monthRows} months — ${m.other} Other, ${m.mess} Mess. Try the other tab${_expLedSite ? ' or clear the site filter' : ''}.</div></div>`
    : `<div style="text-align:center;padding:3rem;color:var(--txt3)">No ledger months loaded from the <b>CashExpenseMonth</b> tab.<div style="font-size:.74rem;margin-top:.5rem">Bills loaded: ${m.billRows || 0}.</div></div>`;
  b.innerHTML = controls + kpis + `<div class="card" style="padding:0">${nodes || empty}</div>`;
}

// ════════════════════════════════════════════════════════════════
//  INDIVIDUAL MESS EXPENSES (route 'mess-individual') — per-employee monthly
//  mess allowance from the Expenses sheet (Individual Food Expenses + its
//  Approval tab). Pending = a record not yet Approved/Paid.
// ════════════════════════════════════════════════════════════════
let _imData = null, _imSite = '', _imMonth = '', _imStatus = '';
function _imEnsure() {
  if (_imData) return Promise.resolve(_imData);
  return Promise.all([
    fetchSheet('Individual Food Expenses',          null, EXPENSE_SHEET_ID, { rawId: true, headers: 1 }),
    fetchSheet('Individual Food Expenses Approval', null, EXPENSE_SHEET_ID, { rawId: true, headers: 1 }),
  ]).then(([recs, appr]) => {
    const R = (recs || []).filter(r => r['Request ID']).map(r => ({
      requestId: r['Request ID'] || '', name: r['Employee Name'] || '', empId: r['Employee ID'] || '',
      desig: r['Designation'] || '', payroll: r['Payroll'] || '', grade: r['Grade'] || '', site: r['Site Name'] || '',
      perDay: _expNum(r['Per Day Mess Allowance']), punches: r['No.of Punch Previous Month'] || '',
      eligible: _expNum(r['Elgible Amount of current month']), payable: _expNum(r['Final Payable amount']),
      status: r['Status'] || '', monthSel: r['Month Selection'] || r['Month-Year'] || '', monthYear: r['Month-Year'] || '', fy: r['Financial Year'] || '',
    }));
    _imData = { recs: R, apprByReq: _expGroup((appr || []).filter(a => a['Request ID']).map(a => ({
      requestId: a['Request ID'] || '', level: a['Approval Level'] || '', status: a['Approval Status'] || '',
      approved: _expNum(a['Approved Amount']), by: _expName(a['Approved By']), on: a['Approved On'] || '', comments: a['Comments / Remarks'] || '',
    })), 'requestId'), meta: { recRows: (recs || []).length, apprRows: (appr || []).length } };
    return _imData;
  });
}
function _imPending(r) { return !/approved|paid|completed|closed/i.test(r.status); }
function renderIndividualMess() {
  const el = document.getElementById('mainContent');
  el.innerHTML = `
    <div class="page-header"><div class="page-header-row">
      <div><h1>&#127869;&#65039; Individual Mess Expenses</h1><p>Per-employee monthly mess allowance &middot; eligibility, punches &amp; final payable &middot; pending highlighted</p></div>
      <button class="btn btn-secondary btn-sm" onclick="_imReload(this)">&#8635; Refresh</button>
    </div></div>
    <div id="im-body"><div class="card card-pad" style="text-align:center;color:var(--txt3);padding:2.5rem">&#9203; Loading individual mess data&hellip;</div></div>`;
  _imEnsure().then(() => _imRenderBody()).catch(() => {
    const b = document.getElementById('im-body');
    if (b) b.innerHTML = '<div class="card card-pad" style="color:var(--danger);padding:1.5rem">Could not load individual mess data. Try Refresh.</div>';
  });
}
function _imReload(btn) { _imData = null; if (btn) btn.disabled = true; renderIndividualMess(); }
function _imSet(k, v) { if (k === 'site') _imSite = v; else if (k === 'month') _imMonth = v; else if (k === 'status') _imStatus = v; _imRenderBody(); }
function _imRenderBody() {
  const b = document.getElementById('im-body'); if (!b || !_imData) return;
  const esc = (typeof escapeHtml_ === 'function') ? escapeHtml_ : (s => String(s || ''));
  const all = _imData.recs;
  const sites = [...new Set(all.map(r => r.site).filter(Boolean))].sort();
  const monthsList = [...new Set(all.map(r => r.monthYear || r.monthSel).filter(Boolean))].sort().reverse();
  const rows = all.filter(r => (!_imSite || r.site === _imSite) && (!_imMonth || (r.monthYear || r.monthSel) === _imMonth) && (!_imStatus || (_imStatus === 'pending' ? _imPending(r) : !_imPending(r))));
  const pend = rows.filter(_imPending);
  const totPay = rows.reduce((s, r) => s + r.payable, 0);
  const sel = 'font-size:.8rem;border:1px solid var(--border);border-radius:6px;padding:5px 8px;background:var(--surface2)';
  const kpis = `<div class="evg-kpi-grid" style="margin-bottom:1rem">
    ${evgKpiCard({ icon: '👥', value: rows.length.toLocaleString('en-IN'), label: 'Records' })}
    ${evgKpiCard({ icon: '⏳', value: pend.length.toLocaleString('en-IN'), label: 'Pending', accent: pend.length ? '#c2410c' : undefined })}
    ${evgKpiCard({ icon: '💸', value: _expFmt(totPay), label: 'Final payable' })}
  </div>`;
  const controls = `<div class="card" style="margin-bottom:.8rem"><div class="card-body" style="padding:.7rem 1rem;display:flex;gap:.6rem;flex-wrap:wrap;align-items:center">
    <span style="font-size:.68rem;color:var(--txt3)">${_imData.meta.recRows} records loaded</span><span style="flex:1"></span>
    <select onchange="_imSet('site',this.value)" style="${sel}"><option value="">All Sites</option>${sites.map(s => `<option ${s === _imSite ? 'selected' : ''}>${esc(s)}</option>`).join('')}</select>
    <select onchange="_imSet('month',this.value)" style="${sel}"><option value="">All Months</option>${monthsList.map(s => `<option ${s === _imMonth ? 'selected' : ''}>${esc(s)}</option>`).join('')}</select>
    <select onchange="_imSet('status',this.value)" style="${sel}"><option value="">Any status</option><option value="pending" ${_imStatus === 'pending' ? 'selected' : ''}>Pending</option><option value="done" ${_imStatus === 'done' ? 'selected' : ''}>Approved/Paid</option></select>
  </div></div>`;
  const TH = 'padding:8px 9px;text-align:left;font-weight:600;white-space:nowrap;border-right:1px solid rgba(255,255,255,.15)';
  const TD = 'padding:6px 9px;border-bottom:1px solid var(--border)';
  const trs = rows.sort((a, b) => (b.monthYear || '').localeCompare(a.monthYear || '') || a.name.localeCompare(b.name)).map(r => {
    const p = _imPending(r);
    return `<tr style="${p ? 'background:#fff7ed' : ''}">
      <td style="${TD};white-space:nowrap"><div style="font-weight:600">${esc(r.name) || '—'}</div><div style="font-size:.68rem;color:var(--txt3)">${esc(r.empId)}${r.desig ? ' · ' + esc(r.desig) : ''}</div></td>
      <td style="${TD};white-space:nowrap;max-width:160px;overflow:hidden;text-overflow:ellipsis" title="${esc(r.site)}">${esc(r.site) || '—'}</td>
      <td style="${TD};white-space:nowrap;color:var(--txt2);font-size:.74rem">${esc(r.monthYear || r.monthSel)}</td>
      <td style="${TD};text-align:right;white-space:nowrap">${r.perDay ? _expFmt(r.perDay) : '—'}</td>
      <td style="${TD};text-align:center">${esc(r.punches) || '—'}</td>
      <td style="${TD};text-align:right;white-space:nowrap">${r.eligible ? _expFmt(r.eligible) : '—'}</td>
      <td style="${TD};text-align:right;white-space:nowrap;font-weight:700;color:var(--g8)">${_expFmt(r.payable)}</td>
      <td style="${TD};white-space:nowrap">${p ? `<span style="background:#ffedd5;color:#c2410c;padding:2px 8px;border-radius:9px;font-size:.66rem;font-weight:700;border:1px solid #fdba74">● ${esc(r.status) || 'Pending'}</span>` : `<span style="background:#dcfce7;color:#15803d;padding:2px 8px;border-radius:9px;font-size:.66rem;font-weight:600">${esc(r.status) || 'Done'}</span>`}</td>
    </tr>`;
  }).join('');
  b.innerHTML = controls + kpis + `<div class="card"><table class="data-table" style="width:100%">
    <thead><tr style="background:var(--g9);color:#fff">
      <th style="${TH}">Employee</th><th style="${TH}">Site</th><th style="${TH}">Month</th>
      <th style="${TH};text-align:right">Per Day</th><th style="${TH};text-align:center">Punches</th>
      <th style="${TH};text-align:right">Eligible</th><th style="${TH};text-align:right">Final Payable</th><th style="${TH}">Status</th>
    </tr></thead>
    <tbody>${trs || `<tr><td colspan="8" style="text-align:center;padding:3rem;color:var(--txt3)">No records${_imData.meta.recRows ? ' for this filter' : ' loaded from Individual Food Expenses'}.</td></tr>`}</tbody>
  </table></div>`;
}

